CREATE FUNCTION app.current_company_id() RETURNS uuid
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE v TEXT;
BEGIN
    v := current_setting('app.company_id', true);
    RETURN CASE WHEN v IS NULL OR v = '' THEN NULL ELSE v::UUID END;
END;
$$;


