--
-- Name: enable_org_rls(text, text); Type: FUNCTION; Schema: app; Owner: -
--

CREATE FUNCTION app.enable_org_rls(p_schema text, p_table text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_qualified TEXT;
    v_has_corp  BOOLEAN;
    v_has_comp  BOOLEAN;
    v_has_site  BOOLEAN;
    v_pn TEXT;
BEGIN
    v_qualified := quote_ident(p_schema) || '.' || quote_ident(p_table);

    -- Check which org columns exist
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = p_schema AND table_name = p_table AND column_name = 'corporate_id'
    ) INTO v_has_corp;

    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = p_schema AND table_name = p_table AND column_name = 'company_id'
    ) INTO v_has_comp;

    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = p_schema AND table_name = p_table AND column_name = 'site_id'
    ) INTO v_has_site;

    -- Already applied? Skip
    IF EXISTS (
        SELECT 1 FROM pg_policies
        WHERE schemaname = p_schema AND tablename = p_table AND policyname LIKE '%_tenant_bypass'
    ) THEN
        RAISE NOTICE 'RLS already on %', v_qualified;
        RETURN;
    END IF;

    -- Enable RLS (force even for table owner = Oracle VPD parity)
    EXECUTE format('ALTER TABLE %s ENABLE ROW LEVEL SECURITY', v_qualified);
    EXECUTE format('ALTER TABLE %s FORCE ROW LEVEL SECURITY', v_qualified);

    -- Policy 1: TENANT bypass
    v_pn := p_table || '_tenant_bypass';
    EXECUTE format('CREATE POLICY %I ON %s FOR ALL USING (app.is_tenant_admin())', v_pn, v_qualified);

    -- Policy 2: CORPORATE level
    IF v_has_corp THEN
        v_pn := p_table || '_corporate_isolation';
        EXECUTE format($f$
            CREATE POLICY %I ON %s FOR ALL USING (
                current_setting('app.access_level', true) = 'CORPORATE'
                AND corporate_id = app.current_corporate_id()
            )
        $f$, v_pn, v_qualified);
    END IF;

    -- Policy 3: COMPANY level (requires company_id)
    IF v_has_comp THEN
        v_pn := p_table || '_company_isolation';
        EXECUTE format($f$
            CREATE POLICY %I ON %s FOR ALL USING (
                current_setting('app.access_level', true) = 'COMPANY'
                AND company_id = app.current_company_id()
            )
        $f$, v_pn, v_qualified);
    END IF;

    -- Policy 4: SITE level (requires site_id, optionally company_id)
    IF v_has_site THEN
        v_pn := p_table || '_site_isolation';
        IF v_has_comp THEN
            EXECUTE format($f$
                CREATE POLICY %I ON %s FOR ALL USING (
                    current_setting('app.access_level', true) = 'SITE'
                    AND company_id = app.current_company_id()
                    AND site_id = ANY(app.current_site_ids())
                )
            $f$, v_pn, v_qualified);
        ELSE
            EXECUTE format($f$
                CREATE POLICY %I ON %s FOR ALL USING (
                    current_setting('app.access_level', true) = 'SITE'
                    AND site_id = ANY(app.current_site_ids())
                )
            $f$, v_pn, v_qualified);
        END IF;
    END IF;

    RAISE NOTICE 'RLS enabled: %', v_qualified;
END;
$_$;


--
-- Name: is_tenant_admin(); Type: FUNCTION; Schema: app; Owner: -
--

CREATE FUNCTION app.is_tenant_admin() RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_level TEXT;
    v_bypass TEXT;
BEGIN
    v_level := current_setting('app.access_level', true);
    v_bypass := current_setting('app.bypass_rls', true);
    
    -- No session context = allow (app layer handles filtering)
    IF v_level IS NULL OR v_level = '' THEN
        RETURN TRUE;
    END IF;
    
    RETURN v_level = 'TENANT' OR v_bypass = 'true';
END;
$$;


--
-- Name: set_session_context(uuid, uuid, uuid, uuid, text, character varying); Type: FUNCTION; Schema: app; Owner: -
--

CREATE FUNCTION app.set_session_context(p_user_id uuid DEFAULT NULL::uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_corporate_id uuid DEFAULT NULL::uuid, p_company_id uuid DEFAULT NULL::uuid, p_site_ids text DEFAULT NULL::text, p_access_level character varying DEFAULT 'SITE'::character varying) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- Using SESSION level (not LOCAL) to match Oracle FND behavior
    -- Reset all first
    PERFORM set_config('app.user_id',       '',    false);
    PERFORM set_config('app.tenant_id',     '',    false);
    PERFORM set_config('app.corporate_id',  '',    false);
    PERFORM set_config('app.company_id',    '',    false);
    PERFORM set_config('app.site_ids',      '',    false);
    PERFORM set_config('app.access_level',  '',    false);
    PERFORM set_config('app.bypass_rls',    '',    false);
    
    -- Set new values
    PERFORM set_config('app.user_id',       COALESCE(p_user_id::TEXT, ''),    false);
    PERFORM set_config('app.tenant_id',     COALESCE(p_tenant_id::TEXT, ''),  false);
    PERFORM set_config('app.corporate_id',  COALESCE(p_corporate_id::TEXT,''),false);
    PERFORM set_config('app.company_id',    COALESCE(p_company_id::TEXT, ''), false);
    PERFORM set_config('app.site_ids',      COALESCE(p_site_ids, ''),         false);
    PERFORM set_config('app.access_level',  COALESCE(p_access_level, ''),     false);
    PERFORM set_config('app.bypass_rls',    'false',                           false);
END;
$$;


--
-- Name: calculate_asset_health_score(bigint); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.calculate_asset_health_score(p_asset_id bigint) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_score                 NUMERIC := 100;
    v_age_factor            NUMERIC;
    v_condition_factor      NUMERIC;
    v_failure_factor        NUMERIC;
    v_pm_compliance_factor  NUMERIC;
    v_failures_12m          INTEGER;
    v_pm_completed          INTEGER;
    v_total_pm              INTEGER;
    v_asset_age_months      INTEGER;
    v_condition_code        VARCHAR;
BEGIN
    SELECT a.condition_code,
           EXTRACT(YEAR FROM AGE(CURRENT_DATE, a.in_service_date)) * 12
           + EXTRACT(MONTH FROM AGE(CURRENT_DATE, a.in_service_date))
    INTO v_condition_code, v_asset_age_months
    FROM eam.eam_assets a WHERE a.asset_id = p_asset_id;

    IF v_asset_age_months > 120 THEN
        v_age_factor := 0.85;
    ELSIF v_asset_age_months > 60 THEN
        v_age_factor := 0.90;
    ELSE
        v_age_factor := 1.0;
    END IF;

    v_condition_factor := CASE v_condition_code
        WHEN 'EXCELLENT' THEN 1.0
        WHEN 'GOOD' THEN 0.9
        WHEN 'FAIR' THEN 0.7
        WHEN 'POOR' THEN 0.5
        WHEN 'CRITICAL' THEN 0.3
        ELSE 0.8
    END;

    SELECT COUNT(*) INTO v_failures_12m
    FROM eam.eam_failure_history fh
    WHERE fh.asset_id = p_asset_id
      AND fh.failure_date >= CURRENT_DATE - INTERVAL '365 days';

    v_failure_factor := GREATEST(1.0 - (v_failures_12m * 0.05), 0.5);

    SELECT
        COUNT(*) FILTER (WHERE ps.schedule_status_code = 'COMPLETED'),
        COUNT(*)
    INTO v_pm_completed, v_total_pm
    FROM eam.eam_pm_schedules ps
    WHERE ps.asset_id = p_asset_id
      AND ps.due_date >= CURRENT_DATE - INTERVAL '365 days';

    v_pm_compliance_factor := CASE WHEN v_total_pm > 0
        THEN 0.5 + (v_pm_completed::NUMERIC / v_total_pm * 0.5)
        ELSE 0.8
    END;

    v_score := 100 * v_age_factor * v_condition_factor * v_failure_factor * v_pm_compliance_factor;

    RETURN ROUND(GREATEST(LEAST(v_score, 100), 0), 1);
END;
$$;


--
-- Name: calculate_mtbf(bigint, integer); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.calculate_mtbf(p_asset_id bigint, p_lookback_days integer DEFAULT 365) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total_failures        INTEGER;
    v_total_operating_hours NUMERIC;
    v_mtbf                 NUMERIC;
BEGIN
    SELECT COUNT(*), COALESCE(SUM(fh.downtime_hours), 0)
    INTO v_total_failures, v_total_operating_hours
    FROM eam.eam_failure_history fh
    WHERE fh.asset_id = p_asset_id
      AND fh.failure_date >= CURRENT_DATE - (p_lookback_days || ' days')::INTERVAL;

    IF v_total_failures = 0 THEN
        RETURN NULL;
    END IF;

    v_total_operating_hours := (p_lookback_days * 24) - v_total_operating_hours;
    v_mtbf := v_total_operating_hours / v_total_failures;

    RETURN ROUND(v_mtbf, 2);
END;
$$;


--
-- Name: calculate_mttr(bigint, integer); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.calculate_mttr(p_asset_id bigint, p_lookback_days integer DEFAULT 365) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total_repairs         INTEGER;
    v_total_repair_hours    NUMERIC;
    v_mttr                 NUMERIC;
BEGIN
    SELECT COUNT(*), COALESCE(SUM(fh.repair_hours), 0)
    INTO v_total_repairs, v_total_repair_hours
    FROM eam.eam_failure_history fh
    WHERE fh.asset_id = p_asset_id
      AND fh.failure_date >= CURRENT_DATE - (p_lookback_days || ' days')::INTERVAL;

    IF v_total_repairs = 0 THEN
        RETURN NULL;
    END IF;

    v_mttr := v_total_repair_hours / v_total_repairs;
    RETURN ROUND(v_mttr, 2);
END;
$$;


--
-- Name: calculate_oee(bigint, date, date); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.calculate_oee(p_asset_id bigint, p_period_start date DEFAULT NULL::date, p_period_end date DEFAULT NULL::date) RETURNS TABLE(availability numeric, performance numeric, quality numeric, oee numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_available_hours       NUMERIC;
    v_downtime_hours        NUMERIC;
    v_planned_hours         NUMERIC;
    v_actual_output         NUMERIC;
    v_ideal_output          NUMERIC;
    v_good_output           NUMERIC;
    v_total_output          NUMERIC;
BEGIN
    p_period_start := COALESCE(p_period_start, CURRENT_DATE - INTERVAL '30 days');
    p_period_end := COALESCE(p_period_end, CURRENT_DATE);

    v_planned_hours := 24 * (p_period_end - p_period_start) * 0.75; -- 18 hrs/day planned

    SELECT COALESCE(SUM(wo.downtime_hours), 0)
    INTO v_downtime_hours
    FROM eam.eam_work_orders wo
    WHERE wo.asset_id = p_asset_id
      AND wo.actual_end BETWEEN p_period_start AND p_period_end;

    v_available_hours := GREATEST(v_planned_hours - v_downtime_hours, 0);
    availability := ROUND((v_available_hours / NULLIF(v_planned_hours, 0)) * 100, 2);

    v_actual_output := v_planned_hours * 0.9;
    v_ideal_output := v_planned_hours * 1.0;
    performance := ROUND((v_actual_output / NULLIF(v_ideal_output, 0)) * 100, 2);

    v_good_output := v_actual_output * 0.98;
    v_total_output := v_actual_output;
    quality := ROUND((v_good_output / NULLIF(v_total_output, 0)) * 100, 2);

    oee := ROUND((availability / 100.0) * (performance / 100.0) * (quality / 100.0) * 100, 2);

    RETURN NEXT;
END;
$$;


--
-- Name: calculate_pm_next_due_date(bigint); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.calculate_pm_next_due_date(p_pm_assignment_id bigint) RETURNS timestamp without time zone
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_assignment            RECORD;
    v_template              RECORD;
    v_next_due              TIMESTAMP;
BEGIN
    SELECT pa.*, pt.frequency_value, pt.frequency_uom, pt.frequency_type_code
    INTO v_assignment
    FROM eam.eam_pm_assignments pa
    JOIN eam.eam_pm_templates pt ON pt.pm_template_id = pa.pm_template_id
    WHERE pa.pm_assignment_id = p_pm_assignment_id;

    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    v_next_due := COALESCE(v_assignment.last_performed_date, v_assignment.effective_start_date::TIMESTAMP, CURRENT_TIMESTAMP);

    CASE v_assignment.frequency_uom
        WHEN 'DAYS' THEN v_next_due := v_next_due + (COALESCE(v_assignment.custom_frequency_value, v_assignment.frequency_value) || ' days')::INTERVAL;
        WHEN 'HOURS' THEN v_next_due := v_next_due + (COALESCE(v_assignment.custom_frequency_value, v_assignment.frequency_value) || ' hours')::INTERVAL;
        WHEN 'WEEKS' THEN v_next_due := v_next_due + (COALESCE(v_assignment.custom_frequency_value, v_assignment.frequency_value) * 7 || ' days')::INTERVAL;
        WHEN 'MONTHS' THEN v_next_due := v_next_due + (COALESCE(v_assignment.custom_frequency_value, v_assignment.frequency_value) || ' months')::INTERVAL;
        ELSE v_next_due := v_next_due + (COALESCE(v_assignment.custom_frequency_value, v_assignment.frequency_value) || ' days')::INTERVAL;
    END CASE;

    UPDATE eam.eam_pm_assignments SET
        next_due_date = v_next_due,
        last_update_date = CURRENT_TIMESTAMP
    WHERE pm_assignment_id = p_pm_assignment_id;

    RETURN v_next_due;
END;
$$;


--
-- Name: complete_work_order(bigint, timestamp without time zone, numeric, numeric, text, character varying); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.complete_work_order(p_work_order_id bigint, p_actual_end timestamp without time zone DEFAULT CURRENT_TIMESTAMP, p_actual_hours numeric DEFAULT NULL::numeric, p_actual_cost numeric DEFAULT NULL::numeric, p_completion_notes text DEFAULT NULL::text, p_completed_by character varying DEFAULT NULL::character varying) RETURNS TABLE(work_order_id bigint, work_order_number character varying, new_status character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_wo                    RECORD;
BEGIN
    SELECT * INTO v_wo FROM eam.eam_work_orders WHERE work_order_id = p_work_order_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Work order % not found', p_work_order_id;
    END IF;

    UPDATE eam.eam_work_orders SET
        work_order_status_code = 'COMPLETED',
        actual_end = p_actual_end,
        actual_hours = COALESCE(p_actual_hours, actual_hours),
        actual_cost = COALESCE(p_actual_cost, actual_cost),
        completion_notes = COALESCE(p_completion_notes, completion_notes),
        completed_by = COALESCE(p_completed_by, completed_by),
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_completed_by
    WHERE work_order_id = p_work_order_id;

    IF v_wo.pm_schedule_id IS NOT NULL THEN
        UPDATE eam.eam_pm_schedules SET
            schedule_status_code = 'COMPLETED',
            completed_date = p_actual_end
        WHERE pm_schedule_id = v_wo.pm_schedule_id;

        UPDATE eam.eam_pm_assignments SET
            last_performed_date = p_actual_end
        WHERE pm_assignment_id = (SELECT pm_assignment_id FROM eam.eam_pm_schedules WHERE pm_schedule_id = v_wo.pm_schedule_id);

        UPDATE eam.eam_assets SET
            condition_code = 'GOOD',
            last_update_date = CURRENT_TIMESTAMP
        WHERE asset_id = v_wo.asset_id;
    END IF;

    RETURN QUERY SELECT v_wo.work_order_id, v_wo.work_order_number, 'COMPLETED'::VARCHAR;
END;
$$;


--
-- Name: create_alert(character varying, character varying, bigint, bigint, character varying, character varying, text, character varying); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.create_alert(p_alert_type_code character varying, p_source_type character varying, p_source_id bigint, p_asset_id bigint DEFAULT NULL::bigint, p_severity_code character varying DEFAULT 'MEDIUM'::character varying, p_title character varying DEFAULT NULL::character varying, p_message text DEFAULT NULL::text, p_tenant_id character varying DEFAULT NULL::character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_alert_id              BIGINT;
    v_alert_number          VARCHAR;
    v_seq                   INTEGER;
BEGIN
    SELECT COALESCE(MAX(CAST(SUBSTRING(alert_number FROM 7) AS INTEGER)), 0) + 1
    INTO v_seq FROM eam.eam_alerts WHERE alert_number LIKE 'ALR-%';
    v_alert_number := 'ALR-' || LPAD(v_seq::TEXT, 6, '0');

    INSERT INTO eam.eam_alerts (
        alert_number, alert_type_code, alert_source_type, alert_source_id,
        asset_id, severity_code, title, message, tenant_id
    ) VALUES (
        v_alert_number, p_alert_type_code, p_source_type, p_source_id,
        p_asset_id, p_severity_code, p_title, p_message, p_tenant_id
    ) RETURNING alert_id INTO v_alert_id;

    RETURN v_alert_id;
END;
$$;


--
-- Name: create_pm_work_order(bigint, timestamp without time zone); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.create_pm_work_order(p_pm_schedule_id bigint, p_due_date timestamp without time zone DEFAULT NULL::timestamp without time zone) RETURNS TABLE(work_order_id bigint, work_order_number character varying, pm_schedule_id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_pm_schedule           RECORD;
    v_work_order_id         BIGINT;
    v_work_order_number     VARCHAR;
BEGIN
    SELECT ps.*, pt.template_name, pt.estimated_hours, pt.estimated_cost,
           pt.priority_code, pt.safety_requirements, pt.procedure_text
    INTO v_pm_schedule
    FROM eam.eam_pm_schedules ps
    JOIN eam.eam_pm_templates pt ON pt.pm_template_id = ps.pm_template_id
    WHERE ps.pm_schedule_id = p_pm_schedule_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'PM schedule % not found', p_pm_schedule_id;
    END IF;

    v_work_order_id := eam.create_work_order(
        'PREVENTIVE',
        v_pm_schedule.template_name,
        'Auto-generated from PM schedule: ' || v_pm_schedule.pm_schedule_id,
        v_pm_schedule.asset_id,
        v_pm_schedule.priority_code,
        'SYSTEM',
        COALESCE(p_due_date, v_pm_schedule.due_date),
        v_pm_schedule.estimated_hours,
        v_pm_schedule.estimated_cost,
        p_pm_schedule_id,
        v_pm_schedule.pm_template_id,
        p_functional_location_id => NULL,
        p_ai_generated => FALSE,
        p_tenant_id => v_pm_schedule.tenant_id
    );

    SELECT w.work_order_id, w.work_order_number
    INTO v_work_order_id, v_work_order_number
    FROM eam.eam_work_orders w
    WHERE w.work_order_number = (
        SELECT work_order_number FROM eam.create_work_order(
            'PREVENTIVE',
            v_pm_schedule.template_name,
            'Auto-generated from PM schedule: ' || v_pm_schedule.pm_schedule_id,
            v_pm_schedule.asset_id,
            v_pm_schedule.priority_code,
            'SYSTEM',
            COALESCE(p_due_date, v_pm_schedule.due_date),
            v_pm_schedule.estimated_hours,
            v_pm_schedule.estimated_cost,
            p_pm_schedule_id,
            v_pm_schedule.pm_template_id,
            p_tenant_id => v_pm_schedule.tenant_id
        )
    );

    UPDATE eam.eam_pm_schedules SET
        work_order_id = v_work_order_id,
        schedule_status_code = 'SCHEDULED'
    WHERE pm_schedule_id = p_pm_schedule_id;

    RETURN QUERY SELECT v_work_order_id, v_work_order_number, p_pm_schedule_id;
END;
$$;


--
-- Name: create_work_order(character varying, character varying, text, bigint, character varying, character varying, timestamp without time zone, numeric, numeric, bigint, bigint, bigint, bigint, boolean, character varying, bigint, bigint); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.create_work_order(p_work_order_type_code character varying, p_title character varying, p_description text DEFAULT NULL::text, p_asset_id bigint DEFAULT NULL::bigint, p_priority_code character varying DEFAULT 'MEDIUM'::character varying, p_requested_by character varying DEFAULT NULL::character varying, p_due_date timestamp without time zone DEFAULT NULL::timestamp without time zone, p_estimated_hours numeric DEFAULT NULL::numeric, p_estimated_cost numeric DEFAULT NULL::numeric, p_pm_schedule_id bigint DEFAULT NULL::bigint, p_pm_template_id bigint DEFAULT NULL::bigint, p_failure_code_id bigint DEFAULT NULL::bigint, p_functional_location_id bigint DEFAULT NULL::bigint, p_ai_generated boolean DEFAULT false, p_tenant_id character varying DEFAULT NULL::character varying, p_organization_id bigint DEFAULT NULL::bigint, p_site_id bigint DEFAULT NULL::bigint) RETURNS TABLE(work_order_id bigint, work_order_number character varying, work_order_status_code character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_work_order_id         BIGINT;
    v_work_order_number     VARCHAR;
    v_year_prefix           VARCHAR;
    v_next_seq              INTEGER;
BEGIN
    v_year_prefix := TO_CHAR(CURRENT_DATE, 'YYYY');
    SELECT COALESCE(MAX(CAST(SUBSTRING(work_order_number FROM 8) AS INTEGER)), 0) + 1
    INTO v_next_seq
    FROM eam.eam_work_orders
    WHERE work_order_number LIKE 'WO-' || v_year_prefix || '-%';

    v_work_order_number := 'WO-' || v_year_prefix || '-' || LPAD(v_next_seq::TEXT, 6, '0');

    INSERT INTO eam.eam_work_orders (
        work_order_number, work_order_type_code, title, description,
        asset_id, priority_code, requested_by, due_date,
        estimated_hours, estimated_cost, pm_schedule_id, pm_template_id,
        failure_code_id, functional_location_id, ai_generated,
        work_order_status_code, tenant_id, organization_id, site_id
    ) VALUES (
        v_work_order_number, p_work_order_type_code, p_title, p_description,
        p_asset_id, p_priority_code, p_requested_by, p_due_date,
        p_estimated_hours, p_estimated_cost, p_pm_schedule_id, p_pm_template_id,
        p_failure_code_id, p_functional_location_id, p_ai_generated,
        'REQUESTED', p_tenant_id, p_organization_id, p_site_id
    ) RETURNING eam_work_orders.work_order_id INTO v_work_order_id;

    RETURN QUERY SELECT v_work_order_id, v_work_order_number, 'REQUESTED'::VARCHAR;
END;
$$;


--
-- Name: generate_pm_work_orders(integer); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.generate_pm_work_orders(p_lookahead_days integer DEFAULT 30) RETURNS TABLE(pm_schedule_id bigint, work_order_id bigint, work_order_number character varying, status character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_schedule              RECORD;
    v_result                RECORD;
BEGIN
    FOR v_schedule IN
        SELECT ps.*
        FROM eam.eam_pm_schedules ps
        WHERE ps.schedule_status_code = 'PENDING'
          AND ps.due_date <= CURRENT_TIMESTAMP + (p_lookahead_days || ' days')::INTERVAL
          AND ps.work_order_id IS NULL
        ORDER BY ps.due_date ASC
        LIMIT 100
    LOOP
        SELECT w.work_order_id, w.work_order_number
        INTO v_result
        FROM eam.create_pm_work_order(v_schedule.pm_schedule_id);

        pm_schedule_id := v_schedule.pm_schedule_id;
        work_order_id := v_result.work_order_id;
        work_order_number := v_result.work_order_number;
        status := 'GENERATED';
        RETURN NEXT;
    END LOOP;
END;
$$;


--
-- Name: generate_work_instructions(bigint); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.generate_work_instructions(p_work_order_id bigint) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_wo                    RECORD;
    v_asset                 RECORD;
    v_template              RECORD;
BEGIN
    SELECT wo.*, wot.work_order_type_name
    INTO v_wo
    FROM eam.eam_work_orders wo
    JOIN eam.eam_work_order_types wot ON wot.work_order_type_code = wo.work_order_type_code
    WHERE wo.work_order_id = p_work_order_id;

    IF NOT FOUND THEN
        RETURN 'Work order not found';
    END IF;

    SELECT * INTO v_asset FROM eam.eam_assets WHERE asset_id = v_wo.asset_id;

    IF v_wo.pm_template_id IS NOT NULL THEN
        SELECT * INTO v_template FROM eam.eam_pm_templates WHERE pm_template_id = v_wo.pm_template_id;
    END IF;

    RETURN E'WORK INSTRUCTIONS\n'
        || E'==================\n'
        || E'Work Order: ' || v_wo.work_order_number || E'\n'
        || E'Title: ' || v_wo.title || E'\n'
        || E'Asset: ' || COALESCE(v_asset.asset_name, 'N/A') || E'\n'
        || E'Type: ' || v_wo.work_order_type_name || E'\n'
        || E'Priority: ' || v_wo.priority_code || E'\n'
        || E'\n'
        || E'--- PROCEDURE ---\n'
        || COALESCE(v_template.procedure_text, 'Follow standard maintenance procedures for this equipment type.')
        || E'\n\n'
        || E'--- SAFETY REQUIREMENTS ---\n'
        || COALESCE(v_template.safety_requirements, 'Standard PPE required: Hard hat, safety glasses, steel-toe boots.')
        || E'\n\n'
        || E'--- NOTES ---\n'
        || v_wo.description;
END;
$$;


--
-- Name: perform_rca_five_why(bigint, character varying); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.perform_rca_five_why(p_work_order_id bigint, p_facilitator character varying DEFAULT NULL::character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_wo                    RECORD;
    v_rca_id                BIGINT;
BEGIN
    SELECT wo.*, a.asset_number, a.asset_name
    INTO v_wo
    FROM eam.eam_work_orders wo
    LEFT JOIN eam.eam_assets a ON a.asset_id = wo.asset_id
    WHERE wo.work_order_id = p_work_order_id;

    INSERT INTO eam.eam_rca_studies (
        study_code, study_name, description, work_order_id, asset_id,
        rca_method_code, problem_statement, rca_facilitator
    ) VALUES (
        'RCA-' || v_wo.work_order_number,
        'RCA for ' || v_wo.work_order_number,
        'Root cause analysis for ' || v_wo.title,
        p_work_order_id,
        v_wo.asset_id,
        'FIVE_WHY',
        COALESCE(v_wo.description, 'Investigate failure'),
        p_facilitator
    ) RETURNING rca_study_id INTO v_rca_id;

    RETURN v_rca_id;
END;
$$;


--
-- Name: record_meter_reading(bigint, bigint, numeric, character varying, bigint, text); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.record_meter_reading(p_meter_id bigint, p_asset_id bigint, p_reading_value numeric, p_reading_method_code character varying DEFAULT 'MANUAL'::character varying, p_operator_id bigint DEFAULT NULL::bigint, p_notes text DEFAULT NULL::text) RETURNS TABLE(new_reading_time timestamp with time zone, alarm_status character varying, warning_triggered boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_meter                 RECORD;
    v_alarm_status          VARCHAR := 'NORMAL';
    v_warning               BOOLEAN := FALSE;
BEGIN
    SELECT * INTO v_meter FROM eam.eam_meters WHERE meter_id = p_meter_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Meter % not found', p_meter_id;
    END IF;

    IF v_meter.critical_threshold_high IS NOT NULL AND p_reading_value > v_meter.critical_threshold_high THEN
        v_alarm_status := 'CRITICAL';
        v_warning := TRUE;
    ELSIF v_meter.warning_threshold_high IS NOT NULL AND p_reading_value > v_meter.warning_threshold_high THEN
        v_alarm_status := 'WARNING';
        v_warning := TRUE;
    ELSIF v_meter.critical_threshold_low IS NOT NULL AND p_reading_value < v_meter.critical_threshold_low THEN
        v_alarm_status := 'CRITICAL';
        v_warning := TRUE;
    ELSIF v_meter.warning_threshold_low IS NOT NULL AND p_reading_value < v_meter.warning_threshold_low THEN
        v_alarm_status := 'WARNING';
        v_warning := TRUE;
    END IF;

    INSERT INTO eam.eam_meter_readings (
        time, meter_id, asset_id, reading_value, unit_code,
        reading_method_code, operator_id, alarm_status, notes
    ) VALUES (
        CURRENT_TIMESTAMP, p_meter_id, p_asset_id, p_reading_value, v_meter.unit_of_measure,
        p_reading_method_code, p_operator_id, v_alarm_status, p_notes
    );

    UPDATE eam.eam_meter_assignments SET
        last_reading = p_reading_value,
        last_reading_date = CURRENT_TIMESTAMP
    WHERE meter_id = p_meter_id AND asset_id = p_asset_id;

    IF v_warning THEN
        PERFORM eam.create_alert(
            'METER_EXCEEDED', 'METER', p_meter_id,
            p_asset_id,
            CASE WHEN v_alarm_status = 'CRITICAL' THEN 'CRITICAL' ELSE 'HIGH' END,
            'Meter ' || v_meter.meter_name || ' exceeded threshold',
            'Reading: ' || p_reading_value || ' ' || v_meter.unit_of_measure
                || ' (Threshold: ' || COALESCE(v_meter.warning_threshold_high, v_meter.critical_threshold_high) || ')'
        );
    END IF;

    RETURN QUERY SELECT CURRENT_TIMESTAMP::TIMESTAMPTZ, v_alarm_status, v_warning;
END;
$$;


--
-- Name: run_predictive_maintenance(bigint); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.run_predictive_maintenance(p_asset_id bigint DEFAULT NULL::bigint) RETURNS TABLE(asset_id bigint, asset_number character varying, health_score numeric, rul_days numeric, recommendation text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_asset                 RECORD;
    v_health_score          NUMERIC;
    v_rul_days              NUMERIC;
BEGIN
    FOR v_asset IN
        SELECT a.asset_id, a.asset_number
        FROM eam.eam_assets a
        WHERE (p_asset_id IS NULL OR a.asset_id = p_asset_id)
          AND a.asset_status_code IN ('ACTIVE', 'IN_SERVICE')
    LOOP
        v_health_score := eam.calculate_asset_health_score(v_asset.asset_id);

        v_rul_days := CASE
            WHEN v_health_score >= 80 THEN 365
            WHEN v_health_score >= 60 THEN 180
            WHEN v_health_score >= 40 THEN 90
            WHEN v_health_score >= 20 THEN 30
            ELSE 7
        END;

        INSERT INTO eam.eam_predictive_maintenance (
            asset_id, health_score, rul_days, pdm_status_code
        ) VALUES (
            v_asset.asset_id, v_health_score, v_rul_days, 'ACTIVE'
        );

        asset_id := v_asset.asset_id;
        asset_number := v_asset.asset_number;
        health_score := v_health_score;
        rul_days := v_rul_days;
        recommendation := CASE
            WHEN v_health_score < 20 THEN 'CRITICAL: Immediate maintenance required'
            WHEN v_health_score < 40 THEN 'HIGH: Schedule maintenance within ' || v_rul_days || ' days'
            WHEN v_health_score < 60 THEN 'MEDIUM: Plan maintenance within ' || v_rul_days || ' days'
            WHEN v_health_score < 80 THEN 'LOW: Monitor condition, next check in ' || v_rul_days || ' days'
            ELSE 'GOOD: No action required'
        END;
        RETURN NEXT;
    END LOOP;
END;
$$;


--
-- Name: schedule_work_orders_optimized(date, date, bigint); Type: FUNCTION; Schema: eam; Owner: -
--

CREATE FUNCTION eam.schedule_work_orders_optimized(p_start_date date, p_end_date date, p_technician_id bigint DEFAULT NULL::bigint) RETURNS TABLE(work_order_id bigint, work_order_number character varying, scheduled_start timestamp without time zone, scheduled_end timestamp without time zone, technician_id bigint, score numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        wo.work_order_id,
        wo.work_order_number,
        CURRENT_TIMESTAMP + (ROW_NUMBER() OVER (ORDER BY wo.priority_code ASC, wo.due_date ASC) || ' hours')::INTERVAL AS scheduled_start,
        CURRENT_TIMESTAMP + ((ROW_NUMBER() OVER (ORDER BY wo.priority_code ASC, wo.due_date ASC) + 4) || ' hours')::INTERVAL AS scheduled_end,
        t.technician_id,
        ROUND(RANDOM() * 100, 2) AS score
    FROM eam.eam_work_orders wo
    CROSS JOIN LATERAL (
        SELECT technician_id FROM eam.eam_technicians
        WHERE (p_technician_id IS NULL OR technician_id = p_technician_id)
          AND technician_status_code = 'ACTIVE'
        ORDER BY RANDOM() LIMIT 1
    ) t
    WHERE wo.work_order_status_code = 'PLANNED'
      AND wo.due_date BETWEEN p_start_date AND p_end_date
    ORDER BY wo.priority_code ASC, wo.due_date ASC;
END;
$$;


--
-- Name: fa_sync_mobile_batch(character varying, jsonb); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fa_sync_mobile_batch(p_batch_id character varying, p_scans jsonb) RETURNS TABLE(scan_index integer, scan_id bigint, status character varying, error_message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_scan JSONB;
    v_scan_index INTEGER := 0;
    v_scan_id BIGINT;
    v_success_count INTEGER := 0;
    v_error_count INTEGER := 0;
BEGIN
    -- Create sync batch record
    INSERT INTO fa.fa_mobile_sync_batches (
        batch_id, batch_status_code, record_count, tenant_id
    ) VALUES (
        p_batch_id, 'IN_PROGRESS',
        jsonb_array_length(p_scans),
        COALESCE(p_scans->0->>'tenant_id', 'GLOBAL')
    )
    ON CONFLICT (batch_id) DO UPDATE SET
        batch_status_code = 'IN_PROGRESS',
        last_update_date = CURRENT_TIMESTAMP;

    -- Process each scan
    FOR v_scan IN SELECT * FROM jsonb_array_elements(p_scans)
    LOOP
        v_scan_index := v_scan_index + 1;
        BEGIN
            v_scan_id := fa.fn_fa_process_mobile_scan(v_scan);

            -- Update scan with batch ID
            UPDATE fa.fa_mobile_scans
            SET batch_id = p_batch_id,
                sync_status_code = 'SYNCED',
                sync_timestamp = CURRENT_TIMESTAMP
            WHERE scan_id = v_scan_id;

            scan_index := v_scan_index;
            scan_id := v_scan_id;
            status := 'SYNCED';
            error_message := NULL;
            v_success_count := v_success_count + 1;
            RETURN NEXT;

        EXCEPTION
            WHEN OTHERS THEN
                scan_index := v_scan_index;
                scan_id := NULL;
                status := 'FAILED';
                error_message := SQLERRM;
                v_error_count := v_error_count + 1;
                RETURN NEXT;
        END;
    END LOOP;

    -- Update batch status
    UPDATE fa.fa_mobile_sync_batches
    SET batch_status_code = CASE WHEN v_error_count = 0 THEN 'COMPLETED' ELSE 'PARTIAL' END,
        success_count = v_success_count,
        error_count = v_error_count,
        processed_timestamp = CURRENT_TIMESTAMP,
        error_details = CASE WHEN v_error_count > 0 THEN
            (SELECT jsonb_agg(jsonb_build_object('index', scan_index, 'error', error_message))
             FROM fa.fa_sync_mobile_batch('', '[]'::JSONB) -- placeholder, will use temp
            ) ELSE NULL END,
        last_update_date = CURRENT_TIMESTAMP
    WHERE batch_id = p_batch_id;

EXCEPTION
    WHEN OTHERS THEN
        UPDATE fa.fa_mobile_sync_batches
        SET batch_status_code = 'FAILED',
            error_details = jsonb_build_object('error', SQLERRM),
            processed_timestamp = CURRENT_TIMESTAMP
        WHERE batch_id = p_batch_id;
        RAISE EXCEPTION 'fn_fa_sync_mobile_batch failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_calculate_count_variances(bigint); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_calculate_count_variances(p_count_id bigint) RETURNS TABLE(variance_type character varying, asset_id bigint, asset_number character varying, expected_location character varying, actual_location character varying, severity character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_count RECORD;
    v_line RECORD;
    v_variance_id BIGINT;
BEGIN
    SELECT * INTO v_count FROM fa.fa_physical_counts WHERE count_id = p_count_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Count ID % not found', p_count_id;
    END IF;

    -- Process missing assets (expected but not scanned)
    FOR v_line IN
        SELECT cl.count_line_id, cl.asset_id, cl.asset_number, cl.expected_location_id,
               l.location_name AS expected_location_name
        FROM fa.fa_count_lines cl
        LEFT JOIN fa.fa_locations l ON cl.expected_location_id = l.location_id
        WHERE cl.count_id = p_count_id
          AND cl.is_scanned = 'N'
          AND cl.line_status_code = 'PENDING'
    LOOP
        INSERT INTO fa.fa_count_variances (
            count_line_id, count_id, asset_id,
            variance_type_code, variance_severity_code,
            expected_value, actual_value,
            tenant_id, created_by
        ) VALUES (
            v_line.count_line_id, p_count_id, v_line.asset_id,
            'MISSING', 'HIGH',
            v_line.expected_location_name, 'NOT_FOUND',
            v_count.tenant_id, 'SYSTEM'
        ) RETURNING variance_id INTO v_variance_id;

        UPDATE fa.fa_count_lines
        SET line_status_code = 'VARIANCE',
            variance_type_code = 'MISSING'
        WHERE count_line_id = v_line.count_line_id;

        variance_type := 'MISSING';
        asset_id := v_line.asset_id;
        asset_number := v_line.asset_number;
        expected_location := v_line.expected_location_name;
        actual_location := 'NOT FOUND';
        severity := 'HIGH';
        RETURN NEXT;
    END LOOP;

    -- Process excess assets (scanned but not expected)
    FOR v_line IN
        SELECT ms.asset_id, a.asset_number, l.location_name
        FROM fa.fa_mobile_scans ms
        JOIN fa.fa_assets a ON ms.asset_id = a.asset_id
        LEFT JOIN fa.fa_locations l ON ms.actual_location_id = l.location_id
        WHERE ms.count_id = p_count_id
          AND ms.scan_status_code = 'VARIANCE_EXCESS'
          AND NOT EXISTS (
            SELECT 1 FROM fa.fa_count_lines cl
            WHERE cl.count_id = p_count_id AND cl.asset_id = ms.asset_id
          )
    LOOP
        variance_type := 'EXCESS';
        asset_id := v_line.asset_id;
        asset_number := v_line.asset_number;
        expected_location := 'NOT EXPECTED';
        actual_location := v_line.location_name;
        severity := 'MEDIUM';
        RETURN NEXT;
    END LOOP;

    -- Process wrong location
    FOR v_line IN
        SELECT cl.count_line_id, cl.asset_id, cl.asset_number,
               el.location_name AS expected_loc,
               al.location_name AS actual_loc
        FROM fa.fa_count_lines cl
        JOIN fa.fa_locations el ON cl.expected_location_id = el.location_id
        JOIN fa.fa_locations al ON cl.actual_location_id = al.location_id
        WHERE cl.count_id = p_count_id
          AND cl.is_scanned = 'Y'
          AND cl.expected_location_id != cl.actual_location_id
    LOOP
        INSERT INTO fa.fa_count_variances (
            count_line_id, count_id, asset_id,
            variance_type_code, variance_severity_code,
            expected_value, actual_value,
            tenant_id, created_by
        ) VALUES (
            v_line.count_line_id, p_count_id, v_line.asset_id,
            'WRONG_LOCATION', 'MEDIUM',
            v_line.expected_loc, v_line.actual_loc,
            v_count.tenant_id, 'SYSTEM'
        );

        UPDATE fa.fa_count_lines
        SET variance_type_code = 'WRONG_LOCATION'
        WHERE count_line_id = v_line.count_line_id;

        variance_type := 'WRONG_LOCATION';
        asset_id := v_line.asset_id;
        asset_number := v_line.asset_number;
        expected_location := v_line.expected_loc;
        actual_location := v_line.actual_loc;
        severity := 'MEDIUM';
        RETURN NEXT;
    END LOOP;

    -- Update count summary
    UPDATE fa.fa_physical_counts
    SET scanned_asset_count = (SELECT COUNT(*) FROM fa.fa_count_lines WHERE count_id = p_count_id AND is_scanned = 'Y'),
        missing_asset_count = (SELECT COUNT(*) FROM fa.fa_count_lines WHERE count_id = p_count_id AND is_scanned = 'N' AND line_status_code = 'VARIANCE'),
        wrong_location_count = (SELECT COUNT(*) FROM fa.fa_count_lines WHERE count_id = p_count_id AND actual_location_id != expected_location_id AND is_scanned = 'Y'),
        count_status_code = 'COMPLETED',
        variance_pct = CASE WHEN expected_asset_count > 0
            THEN ROUND(((SELECT COUNT(*) FROM fa.fa_count_variances WHERE count_id = p_count_id)::NUMERIC / expected_asset_count) * 100, 2)
            ELSE 0 END
    WHERE count_id = p_count_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_calculate_count_variances failed for count_id=%: % (SQLSTATE: %)',
            p_count_id, SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_create_addition(jsonb); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_create_addition(p_asset_data jsonb) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_asset_id BIGINT;
    v_transaction_id BIGINT;
    v_asset_number VARCHAR(100);
BEGIN
    -- Extract asset number or generate one
    v_asset_number := COALESCE(p_asset_data->>'asset_number', 'ASSET-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS'));

    -- Insert asset master record
    INSERT INTO fa.fa_assets (
        asset_number, asset_name, description, asset_type_id, asset_category_id,
        manufacturer_name, model_number, serial_number,
        acquisition_date, in_service_date,
        original_cost, current_cost, salvage_value, net_book_value, currency_code,
        location_id, custodian_id, asset_status_code, source_code,
        purchase_order_id, supplier_id, condition_code,
        tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        v_asset_number,
        p_asset_data->>'asset_name',
        p_asset_data->>'description',
        (p_asset_data->>'asset_type_id')::BIGINT,
        (p_asset_data->>'asset_category_id')::BIGINT,
        p_asset_data->>'manufacturer_name',
        p_asset_data->>'model_number',
        p_asset_data->>'serial_number',
        (p_asset_data->>'acquisition_date')::DATE,
        (p_asset_data->>'in_service_date')::DATE,
        (p_asset_data->>'original_cost')::NUMERIC(19,4),
        (p_asset_data->>'original_cost')::NUMERIC(19,4),
        COALESCE((p_asset_data->>'salvage_value')::NUMERIC(19,4), 0),
        (p_asset_data->>'original_cost')::NUMERIC(19,4),
        COALESCE(p_asset_data->>'currency_code', 'USD'),
        (p_asset_data->>'location_id')::BIGINT,
        (p_asset_data->>'custodian_id')::BIGINT,
        'ACTIVE',
        COALESCE(p_asset_data->>'source_code', 'PURCHASE'),
        (p_asset_data->>'purchase_order_id')::BIGINT,
        (p_asset_data->>'supplier_id')::BIGINT,
        'EXCELLENT',
        COALESCE(p_asset_data->>'tenant_id', 'GLOBAL'),
        (p_asset_data->>'organization_id')::BIGINT,
        (p_asset_data->>'entity_id')::BIGINT,
        COALESCE(p_asset_data->>'created_by', 'SYSTEM')
    )
    RETURNING asset_id INTO v_asset_id;

    -- Create transaction record
    INSERT INTO fa.fa_transactions (
        asset_id, transaction_type_code, transaction_number, transaction_date,
        asset_number, asset_name, cost_amount, currency_code,
        approval_status, tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        v_asset_id, 'ADDITION',
        'ADD-' || v_asset_number,
        (p_asset_data->>'acquisition_date')::DATE,
        v_asset_number,
        p_asset_data->>'asset_name',
        (p_asset_data->>'original_cost')::NUMERIC(19,4),
        COALESCE(p_asset_data->>'currency_code', 'USD'),
        'POSTED',
        COALESCE(p_asset_data->>'tenant_id', 'GLOBAL'),
        (p_asset_data->>'organization_id')::BIGINT,
        (p_asset_data->>'entity_id')::BIGINT,
        COALESCE(p_asset_data->>'created_by', 'SYSTEM')
    )
    RETURNING transaction_id INTO v_transaction_id;

    -- Create addition detail
    INSERT INTO fa.fa_additions (
        transaction_id, asset_id, addition_source_code,
        acquisition_date, in_service_date,
        purchase_price, total_cost, currency_code,
        tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        v_transaction_id, v_asset_id,
        COALESCE(p_asset_data->>'addition_source_code', 'PURCHASE'),
        (p_asset_data->>'acquisition_date')::DATE,
        (p_asset_data->>'in_service_date')::DATE,
        (p_asset_data->>'original_cost')::NUMERIC(19,4),
        (p_asset_data->>'original_cost')::NUMERIC(19,4),
        COALESCE(p_asset_data->>'currency_code', 'USD'),
        COALESCE(p_asset_data->>'tenant_id', 'GLOBAL'),
        (p_asset_data->>'organization_id')::BIGINT,
        (p_asset_data->>'entity_id')::BIGINT,
        COALESCE(p_asset_data->>'created_by', 'SYSTEM')
    );

    -- Assign to default books if book_ids provided
    IF p_asset_data ? 'book_assignments' THEN
        INSERT INTO fa.fa_asset_book_assignments (
            asset_id, book_id, deprn_method_id, deprn_convention_id,
            useful_life_months, salvage_value, deprn_start_date,
            original_cost, current_cost, tenant_id, organization_id, entity_id, created_by
        )
        SELECT
            v_asset_id,
            (ba->>'book_id')::BIGINT,
            COALESCE((ba->>'deprn_method_id')::BIGINT, (SELECT default_deprn_method_id FROM fa.fa_deprn_books WHERE book_id = (ba->>'book_id')::BIGINT)),
            COALESCE((ba->>'deprn_convention_id')::BIGINT, 2),
            COALESCE((ba->>'useful_life_months')::INTEGER, (SELECT default_useful_life FROM fa.fa_deprn_books WHERE book_id = (ba->>'book_id')::BIGINT)),
            COALESCE((ba->>'salvage_value')::NUMERIC(19,4), 0),
            (p_asset_data->>'in_service_date')::DATE,
            (p_asset_data->>'original_cost')::NUMERIC(19,4),
            (p_asset_data->>'original_cost')::NUMERIC(19,4),
            COALESCE(p_asset_data->>'tenant_id', 'GLOBAL'),
            (p_asset_data->>'organization_id')::BIGINT,
            (p_asset_data->>'entity_id')::BIGINT,
            COALESCE(p_asset_data->>'created_by', 'SYSTEM')
        FROM jsonb_array_elements(p_asset_data->'book_assignments') AS ba;
    END IF;

    RETURN v_asset_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_create_addition failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_create_physical_count(character varying, jsonb); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_create_physical_count(p_count_name character varying, p_scope jsonb) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_count_id BIGINT;
    v_location_id BIGINT;
    v_category_id BIGINT;
    v_asset_count INTEGER;
    v_asset RECORD;
    v_sheet_id BIGINT;
    v_sheet_number INTEGER := 0;
BEGIN
    -- Create count header
    INSERT INTO fa.fa_physical_counts (
        count_name, description, count_type_code, count_status_code,
        planned_date, scope_json, expected_asset_count,
        location_id, asset_category_id,
        tenant_id, organization_id, created_by
    ) VALUES (
        p_count_name,
        p_scope->>'description',
        COALESCE(p_scope->>'count_type', 'FULL'),
        'PLANNED',
        COALESCE((p_scope->>'planned_date')::DATE, CURRENT_DATE),
        p_scope,
        0,
        (p_scope->>'location_id')::BIGINT,
        (p_scope->>'asset_category_id')::BIGINT,
        COALESCE(p_scope->>'tenant_id', 'GLOBAL'),
        (p_scope->>'organization_id')::BIGINT,
        COALESCE(p_scope->>'created_by', 'SYSTEM')
    )
    RETURNING count_id INTO v_count_id;

    -- Create count sheets grouped by location
    FOR v_asset IN
        SELECT a.asset_id, a.asset_number, a.asset_name, a.description,
               a.location_id, a.custodian_id, a.barcode, a.asset_category_id,
               l.location_name
        FROM fa.fa_assets a
        JOIN fa.fa_locations l ON a.location_id = l.location_id
        WHERE a.is_active = 'Y'
          AND a.asset_status_code = 'ACTIVE'
          AND (p_scope->>'location_id' IS NULL OR a.location_id = (p_scope->>'location_id')::BIGINT)
          AND (p_scope->>'asset_category_id' IS NULL OR a.asset_category_id = (p_scope->>'asset_category_id')::BIGINT)
          AND (p_scope->>'custodian_id' IS NULL OR a.custodian_id = (p_scope->>'custodian_id')::BIGINT)
        ORDER BY a.location_id, a.asset_number
    LOOP
        -- Create or reuse sheet for this location
        SELECT sheet_id INTO v_sheet_id
        FROM fa.fa_count_sheets
        WHERE count_id = v_count_id AND location_id = v_asset.location_id;

        IF v_sheet_id IS NULL THEN
            v_sheet_number := v_sheet_number + 1;
            INSERT INTO fa.fa_count_sheets (
                count_id, sheet_number, location_id,
                expected_count, sheet_status_code, tenant_id, created_by
            ) VALUES (
                v_count_id,
                'CS-' || v_count_id || '-' || v_sheet_number,
                v_asset.location_id,
                0, 'ASSIGNED',
                COALESCE(p_scope->>'tenant_id', 'GLOBAL'),
                COALESCE(p_scope->>'created_by', 'SYSTEM')
            )
            RETURNING sheet_id INTO v_sheet_id;
        END IF;

        -- Create count line
        INSERT INTO fa.fa_count_lines (
            sheet_id, count_id, asset_id, asset_number,
            expected_location_id, expected_custodian_id,
            barcode_expected, line_status_code, tenant_id, created_by
        ) VALUES (
            v_sheet_id, v_count_id, v_asset.asset_id, v_asset.asset_number,
            v_asset.location_id, v_asset.custodian_id,
            v_asset.barcode, 'PENDING',
            COALESCE(p_scope->>'tenant_id', 'GLOBAL'),
            COALESCE(p_scope->>'created_by', 'SYSTEM')
        );

        v_asset_count := v_asset_count + 1;

        -- Update sheet count
        UPDATE fa.fa_count_sheets
        SET expected_count = expected_count + 1
        WHERE sheet_id = v_sheet_id;
    END LOOP;

    -- Update total expected count
    UPDATE fa.fa_physical_counts
    SET expected_asset_count = v_asset_count
    WHERE count_id = v_count_id;

    RETURN v_count_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_create_physical_count failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_generate_deprn_schedule(bigint, date, date); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_generate_deprn_schedule(p_book_id bigint, p_from_date date, p_to_date date) RETURNS TABLE(asset_id bigint, asset_number character varying, asset_name character varying, category_name character varying, period_name character varying, fiscal_year integer, period_num integer, beginning_nbv numeric, deprn_amount numeric, ending_nbv numeric, ytd_deprn numeric, ltd_deprn numeric, deprn_status character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        dc.asset_id,
        a.asset_number,
        a.asset_name,
        ac.category_name,
        dp.period_name,
        dp.fiscal_year,
        dp.period_num,
        dc.beginning_nbv,
        dc.deprn_amount,
        dc.ending_nbv,
        dc.ytd_deprn,
        dc.ltd_deprn,
        dc.deprn_status_code
    FROM fa.fa_deprn_calculation dc
    JOIN fa.fa_assets a ON dc.asset_id = a.asset_id
    JOIN fa.fa_deprn_book_periods dp ON dc.period_id = dp.period_id
    LEFT JOIN fa.fa_asset_categories ac ON a.asset_category_id = ac.asset_category_id
    WHERE dc.book_id = p_book_id
      AND dp.start_date >= p_from_date
      AND dp.end_date <= p_to_date
    ORDER BY a.asset_number, dp.fiscal_year, dp.period_num;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_generate_deprn_schedule failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_generate_roll_forward(bigint, date, date); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_generate_roll_forward(p_book_id bigint, p_from_date date, p_to_date date) RETURNS TABLE(asset_category character varying, beginning_cost numeric, beginning_deprn numeric, beginning_nbv numeric, beginning_count bigint, addition_cost numeric, addition_count bigint, retirement_cost numeric, retirement_nbv numeric, retirement_count bigint, deprn_expense numeric, ending_cost numeric, ending_deprn numeric, ending_nbv numeric, ending_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH beginning AS (
        SELECT
            ac.category_name,
            COALESCE(SUM(aba.original_cost), 0) AS total_cost,
            COALESCE(SUM(aba.accumulated_deprn), 0) AS total_deprn,
            COUNT(DISTINCT a.asset_id) AS asset_count
        FROM fa.fa_assets a
        JOIN fa.fa_asset_book_assignments aba ON a.asset_id = aba.asset_id AND aba.book_id = p_book_id
        LEFT JOIN fa.fa_asset_categories ac ON a.asset_category_id = ac.asset_category_id
        WHERE a.is_active = 'Y' AND aba.is_active = 'Y'
          AND (aba.deprn_start_date < p_from_date OR aba.deprn_start_date IS NULL)
        GROUP BY ac.category_name
    ),
    additions_data AS (
        SELECT
            ac.category_name,
            COALESCE(SUM(ad.total_cost), 0) AS total_additions,
            COUNT(DISTINCT ad.asset_id) AS addition_count
        FROM fa.fa_additions ad
        JOIN fa.fa_assets a ON ad.asset_id = a.asset_id
        LEFT JOIN fa.fa_asset_categories ac ON a.asset_category_id = ac.asset_category_id
        WHERE ad.acquisition_date BETWEEN p_from_date AND p_to_date
        GROUP BY ac.category_name
    ),
    retirements_data AS (
        SELECT
            ac.category_name,
            COALESCE(SUM(ret.original_cost), 0) AS total_retirements,
            COALESCE(SUM(ret.net_book_value), 0) AS retirement_nbv,
            COUNT(DISTINCT ret.asset_id) AS retirement_count
        FROM fa.fa_retirements ret
        JOIN fa.fa_assets a ON ret.asset_id = a.asset_id
        LEFT JOIN fa.fa_asset_categories ac ON a.asset_category_id = ac.asset_category_id
        WHERE ret.retirement_date BETWEEN p_from_date AND p_to_date
        GROUP BY ac.category_name
    ),
    deprn_data AS (
        SELECT
            ac.category_name,
            COALESCE(SUM(dc.deprn_amount), 0) AS total_deprn
        FROM fa.fa_deprn_calculation dc
        JOIN fa.fa_assets a ON dc.asset_id = a.asset_id
        JOIN fa.fa_deprn_book_periods dp ON dc.period_id = dp.period_id
        LEFT JOIN fa.fa_asset_categories ac ON a.asset_category_id = ac.asset_category_id
        WHERE dc.book_id = p_book_id
          AND dp.start_date >= p_from_date AND dp.end_date <= p_to_date
        GROUP BY ac.category_name
    )
    SELECT
        COALESCE(b.category_name, 'UNCATEGORIZED'),
        COALESCE(b.total_cost, 0),
        COALESCE(b.total_deprn, 0),
        COALESCE(b.total_cost - b.total_deprn, 0),
        COALESCE(b.asset_count, 0),
        COALESCE(a.total_additions, 0),
        COALESCE(a.addition_count, 0),
        COALESCE(r.total_retirements, 0),
        COALESCE(r.retirement_nbv, 0),
        COALESCE(r.retirement_count, 0),
        COALESCE(d.total_deprn, 0),
        COALESCE(b.total_cost, 0) + COALESCE(a.total_additions, 0) - COALESCE(r.total_retirements, 0),
        COALESCE(b.total_deprn, 0) + COALESCE(d.total_deprn, 0),
        (COALESCE(b.total_cost, 0) + COALESCE(a.total_additions, 0) - COALESCE(r.total_retirements, 0)) -
        (COALESCE(b.total_deprn, 0) + COALESCE(d.total_deprn, 0)),
        COALESCE(b.asset_count, 0) + COALESCE(a.addition_count, 0) - COALESCE(r.retirement_count, 0)
    FROM beginning b
    FULL OUTER JOIN additions_data a ON b.category_name = a.category_name
    FULL OUTER JOIN retirements_data r ON COALESCE(b.category_name, a.category_name) = r.category_name
    FULL OUTER JOIN deprn_data d ON COALESCE(b.category_name, a.category_name, r.category_name) = d.category_name
    ORDER BY COALESCE(b.category_name, a.category_name, r.category_name, d.category_name);

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_generate_roll_forward failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_optimize_asset_storage(jsonb); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_optimize_asset_storage(p_problem_data jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_problem_id BIGINT;
    v_result JSONB;
BEGIN
    INSERT INTO fa.fa_optimization_problems (
        problem_name, problem_type_code, problem_description,
        objective_type_code, objective_function, constraints, variables, parameters,
        solver_type_code, problem_status_code,
        tenant_id, created_by
    ) VALUES (
        p_problem_data->>'problem_name',
        'ASSET_STORAGE',
        p_problem_data->>'description',
        COALESCE(p_problem_data->>'objective_type', 'MINIMIZE_SPACE'),
        p_problem_data->'objective_function',
        p_problem_data->'constraints',
        p_problem_data->'variables',
        p_problem_data->'parameters',
        'OR_TOOLS', 'DRAFT',
        COALESCE(p_problem_data->>'tenant_id', 'GLOBAL'),
        'SYSTEM'
    )
    RETURNING problem_id INTO v_problem_id;

    v_result := jsonb_build_object(
        'problem_id', v_problem_id,
        'status', 'DRAFT',
        'message', 'Storage optimization problem created. Execute OR-Tools solver externally.',
        'containers', p_problem_data->'containers',
        'assets_to_store', p_problem_data->'assets'
    );

    RETURN v_result;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_optimize_asset_storage failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_optimize_count_routing(bigint); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_optimize_count_routing(p_count_id bigint) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_assets JSONB;
    v_problem_id BIGINT;
    v_result JSONB;
BEGIN
    -- Get asset locations for this count
    SELECT jsonb_agg(
        jsonb_build_object(
            'asset_id', a.asset_id,
            'asset_number', a.asset_number,
            'location_id', a.location_id,
            'location_name', l.location_name,
            'latitude', l.latitude,
            'longitude', l.longitude,
            'priority', CASE a.criticality_code
                WHEN 'CRITICAL' THEN 10 WHEN 'HIGH' THEN 8
                WHEN 'NORMAL' THEN 5 ELSE 3 END
        )
        ORDER BY a.criticality_code DESC, a.asset_number
    ) INTO v_assets
    FROM fa.fa_count_lines cl
    JOIN fa.fa_assets a ON cl.asset_id = a.asset_id
    LEFT JOIN fa.fa_locations l ON a.location_id = l.location_id
    WHERE cl.count_id = p_count_id;

    -- Create optimization problem
    INSERT INTO fa.fa_optimization_problems (
        problem_name, problem_type_code, problem_description,
        objective_type_code, objective_function, constraints, variables,
        data_sources, solver_type_code, problem_status_code,
        tenant_id, created_by
    ) VALUES (
        'Count Routing - Count #' || p_count_id,
        'COUNT_ROUTING', 'Optimize counter routes for physical count',
        'MINIMIZE_TIME',
        '{"type": "minimize", "function": "total_travel_time + sum(priority_weights * count_order)"}',
        '{"max_stops_per_counter": 50, "max_work_hours": 8, "counter_skills": []}',
        '{"asset_locations": "array", "counters": "array", "distance_matrix": "matrix"}',
        jsonb_build_object('source', 'fa_count_lines', 'count_id', p_count_id, 'assets', v_assets),
        'OR_TOOLS', 'DRAFT',
        COALESCE((SELECT tenant_id FROM fa.fa_physical_counts WHERE count_id = p_count_id), 'GLOBAL'),
        'SYSTEM'
    )
    RETURNING problem_id INTO v_problem_id;

    -- Build result
    v_result := jsonb_build_object(
        'problem_id', v_problem_id,
        'count_id', p_count_id,
        'assets_to_count', jsonb_array_length(COALESCE(v_assets, '[]'::JSONB)),
        'status', 'DRAFT',
        'message', 'Routing problem created. Execute OR-Tools solver externally to generate routes.'
    );

    -- Update problem status
    UPDATE fa.fa_optimization_problems
    SET problem_status_code = 'DRAFT'
    WHERE problem_id = v_problem_id;

    RETURN v_result;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_optimize_count_routing failed for count_id=%: % (SQLSTATE: %)',
            p_count_id, SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_process_mobile_scan(jsonb); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_process_mobile_scan(p_scan_data jsonb) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_scan_id BIGINT;
    v_asset_id BIGINT;
    v_count_line_id BIGINT;
    v_expected_location_id BIGINT;
    v_actual_location_id BIGINT;
    v_variance_type VARCHAR(50);
BEGIN
    -- Lookup asset by number or barcode
    SELECT asset_id INTO v_asset_id
    FROM fa.fa_assets
    WHERE (asset_number = p_scan_data->>'asset_number'
           OR barcode = p_scan_data->>'barcode_scanned')
      AND is_active = 'Y';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Asset not found: %', COALESCE(p_scan_data->>'asset_number', p_scan_data->>'barcode_scanned');
    END IF;

    -- Determine variance
    SELECT expected_location_id INTO v_expected_location_id
    FROM fa.fa_count_lines
    WHERE count_id = (p_scan_data->>'count_id')::BIGINT
      AND asset_id = v_asset_id;

    v_actual_location_id := (p_scan_data->>'actual_location_id')::BIGINT;

    IF v_expected_location_id IS NULL THEN
        v_variance_type := 'VARIANCE_EXCESS';
    ELSIF v_actual_location_id IS NOT NULL AND v_expected_location_id != v_actual_location_id THEN
        v_variance_type := 'VARIANCE_WRONG_LOCATION';
    ELSE
        v_variance_type := 'SCANNED';
    END IF;

    -- Insert scan
    INSERT INTO fa.fa_mobile_scans (
        count_id, asset_id, asset_number, barcode_scanned,
        scan_type_code, scan_timestamp,
        gps_latitude, gps_longitude, gps_accuracy,
        expected_location_id, actual_location_id,
        scan_status_code, variance_notes,
        counter_id, counter_name,
        device_id, device_name,
        sync_status_code, source_scan_id,
        tenant_id, created_by
    ) VALUES (
        (p_scan_data->>'count_id')::BIGINT,
        v_asset_id,
        p_scan_data->>'asset_number',
        p_scan_data->>'barcode_scanned',
        COALESCE(p_scan_data->>'scan_type', 'BARCODE'),
        COALESCE((p_scan_data->>'scan_timestamp')::TIMESTAMP, CURRENT_TIMESTAMP),
        (p_scan_data->>'gps_latitude')::NUMERIC(19,8),
        (p_scan_data->>'gps_longitude')::NUMERIC(19,8),
        (p_scan_data->>'gps_accuracy')::NUMERIC(19,4),
        v_expected_location_id,
        v_actual_location_id,
        v_variance_type,
        p_scan_data->>'variance_notes',
        (p_scan_data->>'counter_id')::BIGINT,
        p_scan_data->>'counter_name',
        (p_scan_data->>'device_id')::BIGINT,
        p_scan_data->>'device_name',
        'SYNCED',
        p_scan_data->>'source_scan_id',
        COALESCE(p_scan_data->>'tenant_id', 'GLOBAL'),
        COALESCE(p_scan_data->>'created_by', 'SYSTEM')
    )
    RETURNING scan_id INTO v_scan_id;

    -- Update count line
    UPDATE fa.fa_count_lines
    SET is_scanned = 'Y',
        scan_id = v_scan_id,
        scan_timestamp = CURRENT_TIMESTAMP,
        actual_location_id = v_actual_location_id,
        line_status_code = CASE WHEN v_variance_type = 'SCANNED' THEN 'VERIFIED' ELSE 'VARIANCE' END,
        variance_type_code = CASE WHEN v_variance_type != 'SCANNED' THEN v_variance_type ELSE NULL END,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = 'SYSTEM'
    WHERE count_id = (p_scan_data->>'count_id')::BIGINT
      AND asset_id = v_asset_id;

    -- Update count summary
    UPDATE fa.fa_physical_counts
    SET scanned_asset_count = (
        SELECT COUNT(*) FROM fa.fa_count_lines
        WHERE count_id = (p_scan_data->>'count_id')::BIGINT AND is_scanned = 'Y'
    )
    WHERE count_id = (p_scan_data->>'count_id')::BIGINT;

    RETURN v_scan_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_process_mobile_scan failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_process_retirement(bigint, date, numeric); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_process_retirement(p_asset_id bigint, p_retirement_date date, p_proceeds numeric DEFAULT 0) RETURNS TABLE(retirement_id bigint, transaction_id bigint, gain_loss numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_asset RECORD;
    v_retirement_id BIGINT;
    v_transaction_id BIGINT;
    v_original_cost NUMERIC(19,4);
    v_accumulated_deprn NUMERIC(19,4);
    v_net_book_value NUMERIC(19,4);
    v_gain_loss NUMERIC(19,4);
BEGIN
    -- Get asset data
    SELECT * INTO v_asset FROM fa.fa_assets WHERE asset_id = p_asset_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Asset ID % not found', p_asset_id;
    END IF;

    v_original_cost := v_asset.current_cost;
    v_accumulated_deprn := v_asset.accumulated_depreciation;
    v_net_book_value := v_original_cost - v_accumulated_deprn;
    v_gain_loss := p_proceeds - v_net_book_value;

    -- Create transaction
    INSERT INTO fa.fa_transactions (
        asset_id, transaction_type_code, transaction_number, transaction_date,
        asset_number, cost_amount, deprn_amount, nbv_amount, proceeds_amount,
        gain_loss_amount, approval_status,
        tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        p_asset_id, 'RETIREMENT',
        'RET-' || v_asset.asset_number || '-' || TO_CHAR(p_retirement_date, 'YYYYMMDD'),
        p_retirement_date,
        v_asset.asset_number,
        v_original_cost, v_accumulated_deprn, v_net_book_value,
        p_proceeds, v_gain_loss,
        'POSTED',
        v_asset.tenant_id, v_asset.organization_id, v_asset.entity_id, 'SYSTEM'
    )
    RETURNING transaction_id INTO v_transaction_id;

    -- Create retirement record
    INSERT INTO fa.fa_retirements (
        transaction_id, asset_id, retirement_type_code, retirement_date,
        original_cost, accumulated_deprn, net_book_value, proceeds_amount,
        gain_loss_amount, approval_status, tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        v_transaction_id, p_asset_id, 'SALE', p_retirement_date,
        v_original_cost, v_accumulated_deprn, v_net_book_value,
        p_proceeds, v_gain_loss,
        'APPROVED',
        v_asset.tenant_id, v_asset.organization_id, v_asset.entity_id, 'SYSTEM'
    )
    RETURNING retirement_id INTO v_retirement_id;

    -- Update asset status
    UPDATE fa.fa_assets
    SET asset_status_code = 'FULLY_RETIRED',
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = 'SYSTEM',
        object_version_number = object_version_number + 1
    WHERE asset_id = p_asset_id;

    -- Update book assignments
    UPDATE fa.fa_asset_book_assignments
    SET deprn_status_code = 'FULLY_RETIRED',
        deprn_end_date = p_retirement_date,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = 'SYSTEM',
        object_version_number = object_version_number + 1
    WHERE asset_id = p_asset_id AND is_active = 'Y';

    -- Return result
    retirement_id := v_retirement_id;
    transaction_id := v_transaction_id;
    gain_loss := v_gain_loss;
    RETURN NEXT;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_process_retirement failed for asset_id=%: % (SQLSTATE: %)',
            p_asset_id, SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_process_transfer(bigint, bigint, bigint); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_process_transfer(p_asset_id bigint, p_new_location_id bigint DEFAULT NULL::bigint, p_new_custodian_id bigint DEFAULT NULL::bigint) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_asset RECORD;
    v_transaction_id BIGINT;
    v_transfer_type VARCHAR(50);
BEGIN
    SELECT * INTO v_asset FROM fa.fa_assets WHERE asset_id = p_asset_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Asset ID % not found', p_asset_id;
    END IF;

    -- Determine transfer type
    IF p_new_location_id IS NOT NULL AND p_new_custodian_id IS NOT NULL THEN
        v_transfer_type := 'LOCATION';
    ELSIF p_new_location_id IS NOT NULL THEN
        v_transfer_type := 'LOCATION';
    ELSIF p_new_custodian_id IS NOT NULL THEN
        v_transfer_type := 'CUSTODIAN';
    ELSE
        RAISE EXCEPTION 'Must specify at least a new location or new custodian';
    END IF;

    -- Validate location exists
    IF p_new_location_id IS NOT NULL THEN
        PERFORM 1 FROM fa.fa_locations WHERE location_id = p_new_location_id;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'Location ID % not found', p_new_location_id;
        END IF;
    END IF;

    -- Validate custodian exists
    IF p_new_custodian_id IS NOT NULL THEN
        PERFORM 1 FROM fa.fa_custodians WHERE custodian_id = p_new_custodian_id;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'Custodian ID % not found', p_new_custodian_id;
        END IF;
    END IF;

    -- Create transaction
    INSERT INTO fa.fa_transactions (
        asset_id, transaction_type_code, transaction_number, transaction_date,
        asset_number, from_location_id, to_location_id,
        from_custodian_id, to_custodian_id,
        nbv_amount, approval_status,
        tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        p_asset_id, 'TRANSFER',
        'TRF-' || v_asset.asset_number || '-' || TO_CHAR(CURRENT_DATE, 'YYYYMMDD'),
        CURRENT_DATE,
        v_asset.asset_number,
        v_asset.location_id, p_new_location_id,
        v_asset.custodian_id, p_new_custodian_id,
        v_asset.net_book_value,
        'POSTED',
        v_asset.tenant_id, v_asset.organization_id, v_asset.entity_id, 'SYSTEM'
    )
    RETURNING transaction_id INTO v_transaction_id;

    -- Create transfer detail
    INSERT INTO fa.fa_transfers (
        transaction_id, asset_id, transfer_type_code, transfer_date,
        from_location_id, to_location_id,
        from_custodian_id, to_custodian_id,
        transfer_reason, approval_status,
        tenant_id, organization_id, entity_id, created_by
    ) VALUES (
        v_transaction_id, p_asset_id, v_transfer_type, CURRENT_DATE,
        v_asset.location_id, p_new_location_id,
        v_asset.custodian_id, p_new_custodian_id,
        'System transfer',
        'APPROVED',
        v_asset.tenant_id, v_asset.organization_id, v_asset.entity_id, 'SYSTEM'
    );

    -- Update asset
    UPDATE fa.fa_assets
    SET location_id = COALESCE(p_new_location_id, location_id),
        custodian_id = COALESCE(p_new_custodian_id, custodian_id),
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = 'SYSTEM',
        object_version_number = object_version_number + 1
    WHERE asset_id = p_asset_id;

    RETURN v_transaction_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_process_transfer failed for asset_id=%: % (SQLSTATE: %)',
            p_asset_id, SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: fn_fa_run_depreciation(bigint, bigint); Type: FUNCTION; Schema: fa; Owner: -
--

CREATE FUNCTION fa.fn_fa_run_depreciation(p_book_id bigint, p_period_id bigint) RETURNS TABLE(asset_id bigint, asset_number character varying, deprn_amount numeric, beginning_nbv numeric, ending_nbv numeric, status character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_period RECORD;
    v_assignment RECORD;
    v_deprn_amount NUMERIC(19,4);
    v_monthly_deprn NUMERIC(19,4);
    v_months_elapsed INTEGER;
    v_beginning_nbv NUMERIC(19,4);
    v_ending_nbv NUMERIC(19,4);
    v_run_id VARCHAR(100);
BEGIN
    -- Validate period
    SELECT * INTO v_period FROM fa.fa_deprn_book_periods WHERE period_id = p_period_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Period ID % not found', p_period_id;
    END IF;

    IF v_period.period_status_code = 'CLOSED' THEN
        RAISE EXCEPTION 'Period % is closed. Cannot run depreciation.', v_period.period_name;
    END IF;

    -- Generate run ID
    v_run_id := 'DEPRN-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS');

    -- Process each active assignment
    FOR v_assignment IN
        SELECT aba.*, a.asset_number, a.asset_name, a.original_cost,
               dm.method_type_code, dm.deprn_parameter_1, dm.is_macrs,
               dp.start_date AS period_start, dp.end_date AS period_end
        FROM fa.fa_asset_book_assignments aba
        JOIN fa.fa_assets a ON aba.asset_id = a.asset_id
        JOIN fa.fa_deprn_methods dm ON aba.deprn_method_id = dm.deprn_method_id
        CROSS JOIN fa.fa_deprn_book_periods dp
        WHERE aba.book_id = p_book_id
          AND aba.is_active = 'Y'
          AND a.is_active = 'Y'
          AND a.asset_status_code IN ('ACTIVE', 'PARTIALLY_RETIRED')
          AND aba.deprn_status_code = 'ACTIVE'
          AND dp.period_id = p_period_id
          AND aba.deprn_start_date <= dp.end_date
          AND (aba.deprn_end_date IS NULL OR aba.deprn_end_date >= dp.start_date)
    LOOP
        -- Calculate monthly depreciation based on method
        v_beginning_nbv := v_assignment.current_cost - v_assignment.accumulated_deprn;

        IF v_assignment.method_type_code = 'STRAIGHT_LINE' THEN
            v_monthly_deprn := (v_assignment.current_cost - v_assignment.salvage_value)
                / GREATEST(v_assignment.useful_life_months, 1);
        ELSIF v_assignment.method_type_code = 'DECLINING_BALANCE' THEN
            v_monthly_deprn := (v_beginning_nbv * (v_assignment.deprn_parameter_1 / 100.0))
                / GREATEST(v_assignment.useful_life_months, 1);
        ELSE
            v_monthly_deprn := (v_assignment.current_cost - v_assignment.salvage_value)
                / GREATEST(v_assignment.useful_life_months, 1);
        END IF;

        v_deprn_amount := GREATEST(v_monthly_deprn, 0);
        v_deprn_amount := LEAST(v_deprn_amount, v_beginning_nbv - v_assignment.salvage_value);
        v_deprn_amount := GREATEST(v_deprn_amount, 0);

        v_ending_nbv := v_beginning_nbv - v_deprn_amount;

        -- Insert calculation record
        INSERT INTO fa.fa_deprn_calculation (
            asset_id, book_id, period_id, deprn_run_id,
            beginning_nbv, deprn_amount, ending_nbv,
            ytd_deprn, ltd_deprn,
            deprn_status_code, tenant_id, organization_id, entity_id, created_by
        ) VALUES (
            v_assignment.asset_id, p_book_id, p_period_id, v_run_id,
            v_beginning_nbv, v_deprn_amount, v_ending_nbv,
            v_assignment.prior_ytd_deprn + v_deprn_amount,
            v_assignment.prior_ltd_deprn + v_deprn_amount,
            'CALCULATED', v_assignment.tenant_id, v_assignment.organization_id,
            (SELECT entity_id FROM fa.fa_assets WHERE asset_id = v_assignment.asset_id),
            'SYSTEM'
        )
        ON CONFLICT (asset_id, book_id, period_id)
        DO UPDATE SET
            deprn_amount = EXCLUDED.deprn_amount,
            beginning_nbv = EXCLUDED.beginning_nbv,
            ending_nbv = EXCLUDED.ending_nbv,
            deprn_run_id = v_run_id,
            deprn_status_code = 'CALCULATED',
            last_update_date = CURRENT_TIMESTAMP,
            last_updated_by = 'SYSTEM',
            object_version_number = fa.fa_deprn_calculation.object_version_number + 1;

        -- Return row
        asset_id := v_assignment.asset_id;
        asset_number := v_assignment.asset_number;
        deprn_amount := v_deprn_amount;
        beginning_nbv := v_beginning_nbv;
        ending_nbv := v_ending_nbv;
        status := 'CALCULATED';
        RETURN NEXT;
    END LOOP;

    -- Update book period
    UPDATE fa.fa_deprn_book_periods
    SET is_deprn_calculated = 'Y',
        deprn_run_date = CURRENT_TIMESTAMP,
        last_update_date = CURRENT_TIMESTAMP
    WHERE period_id = p_period_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'fn_fa_run_depreciation failed for book_id=%, period_id=%: % (SQLSTATE: %)',
            p_book_id, p_period_id, SQLERRM, SQLSTATE;
END;
$$;


--
-- Name: allocate_fifo(uuid, numeric); Type: FUNCTION; Schema: inv; Owner: -
--

CREATE FUNCTION inv.allocate_fifo(p_item_id uuid, p_qty_needed numeric) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_remaining NUMERIC := p_qty_needed;
    v_row RECORD;
    v_result TEXT := '';
BEGIN
    FOR v_row IN SELECT warehouse_id, qty_onhand FROM inv.inv_onhand_balances WHERE item_id = p_item_id AND qty_onhand > 0 ORDER BY created_at ASC LOOP
        IF v_remaining <= 0 THEN EXIT; END IF;
        v_result := v_result || format('Alloc %s from WH %s; ', LEAST(v_remaining, v_row.qty_onhand), v_row.warehouse_id);
        v_remaining := v_remaining - LEAST(v_remaining, v_row.qty_onhand);
    END LOOP;
    IF v_remaining > 0 THEN v_result := v_result || format('Shortage: %s', v_remaining); END IF;
    RETURN v_result;
END;
$$;


--
-- Name: process_transaction(character varying, uuid, uuid, uuid, numeric, character varying, character varying, uuid, character varying, character varying); Type: FUNCTION; Schema: inv; Owner: -
--

CREATE FUNCTION inv.process_transaction(p_transaction_type character varying, p_item_id uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_location_id uuid DEFAULT NULL::uuid, p_qty numeric DEFAULT 0, p_lot_number character varying DEFAULT NULL::character varying, p_serial_number character varying DEFAULT NULL::character varying, p_source_doc_id uuid DEFAULT NULL::uuid, p_source_doc_type character varying DEFAULT NULL::character varying, p_reference character varying DEFAULT NULL::character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_txn_id UUID;
    v_unit_cost NUMERIC(19,4);
    v_total_cost NUMERIC(19,4);
BEGIN
    IF p_qty = 0 THEN RAISE EXCEPTION 'Quantity cannot be zero'; END IF;
    SELECT COALESCE(unit_cost, 0) INTO v_unit_cost FROM inv.item_attributes WHERE item_id = p_item_id;
    v_total_cost := ABS(p_qty) * v_unit_cost;
    v_txn_id := uuidv7();
    INSERT INTO inv.material_transactions (transaction_id, transaction_type, item_id, warehouse_id, location_id, lot_number, serial_number, qty, unit_cost, total_cost, source_doc_id, source_doc_type, reference, transaction_date, posted)
    VALUES (v_txn_id, p_transaction_type, p_item_id, p_warehouse_id, p_location_id, p_lot_number, p_serial_number, p_qty, v_unit_cost, v_total_cost, p_source_doc_id, p_source_doc_type, p_reference, NOW(), TRUE);
    UPDATE inv.inv_onhand_balances SET qty_onhand = qty_onhand + p_qty, unit_cost = CASE WHEN p_qty > 0 THEN v_unit_cost ELSE unit_cost END, updated_at = NOW()
    WHERE item_id = p_item_id AND (p_warehouse_id IS NULL OR warehouse_id = p_warehouse_id) AND (p_location_id IS NULL OR location_id = p_location_id);
    IF NOT FOUND AND p_qty > 0 THEN
        INSERT INTO inv.inv_onhand_balances (onhand_id, item_id, warehouse_id, location_id, qty_onhand, unit_cost)
        VALUES (uuidv7(), p_item_id, p_warehouse_id, p_location_id, p_qty, v_unit_cost);
    END IF;
    RETURN v_txn_id;
END;
$$;


--
-- Name: process_transaction(character varying, uuid, uuid, uuid, uuid, numeric, character varying, character varying, uuid, character varying, character varying); Type: FUNCTION; Schema: inv; Owner: -
--

CREATE FUNCTION inv.process_transaction(p_transaction_type character varying, p_item_id uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_location_from_id uuid DEFAULT NULL::uuid, p_location_to_id uuid DEFAULT NULL::uuid, p_qty numeric DEFAULT 0, p_lot_number character varying DEFAULT NULL::character varying, p_serial_number character varying DEFAULT NULL::character varying, p_source_doc_id uuid DEFAULT NULL::uuid, p_source_doc_type character varying DEFAULT NULL::character varying, p_reference character varying DEFAULT NULL::character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_txn_id UUID;
    v_unit_cost NUMERIC(19,4);
BEGIN
    IF p_qty = 0 THEN RAISE EXCEPTION 'Quantity cannot be zero'; END IF;
    SELECT COALESCE(unit_cost, 0) INTO v_unit_cost FROM inv.item_attributes WHERE item_id = p_item_id;
    v_txn_id := uuidv7();
    INSERT INTO inv.material_transactions (
        transaction_id, transaction_type, item_id, warehouse_id,
        location_from_id, location_to_id, lot_number, serial_number,
        qty, unit_cost, total_cost, source_doc_id, source_doc_type,
        reference_number, transaction_date
    ) VALUES (
        v_txn_id, p_transaction_type, p_item_id, p_warehouse_id,
        p_location_from_id, p_location_to_id, p_lot_number, p_serial_number,
        p_qty, v_unit_cost, ABS(p_qty) * v_unit_cost,
        p_source_doc_id, p_source_doc_type,
        p_reference, NOW()
    );
    IF p_qty > 0 THEN
        INSERT INTO inv.inv_onhand_balances (onhand_id, item_id, warehouse_id, qty_onhand, unit_cost)
        VALUES (uuidv7(), p_item_id, p_warehouse_id, p_qty, v_unit_cost)
        ON CONFLICT (onhand_id) DO NOTHING;
    END IF;
    RETURN v_txn_id;
END;
$$;


--
-- Name: snapshot_onhand(); Type: FUNCTION; Schema: inv; Owner: -
--

CREATE FUNCTION inv.snapshot_onhand() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_count INTEGER;
BEGIN
    INSERT INTO inv.inv_onhand_balances (item_id, warehouse_id, location_id, lot_number, qty_onhand, created_at)
    SELECT item_id, warehouse_id, location_id, lot_number, qty_onhand, NOW()
    FROM inv.inv_onhand_balances
    WHERE is_active = TRUE
    ON CONFLICT DO NOTHING;

    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$$;


--
-- Name: genealogy_trace(character varying, uuid, character varying, integer); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.genealogy_trace(p_entity_type character varying, p_entity_id uuid, p_direction character varying, p_max_depth integer DEFAULT 3) RETURNS TABLE(depth integer, direction character varying, entity_type character varying, entity_id uuid, lot_serial character varying, qty numeric, uom character varying, path text)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  WITH RECURSIVE trace AS (
    -- Anchor: first level
    SELECT
      1::integer AS depth,
      g.direction,
      CASE WHEN g.direction = 'FORWARD' THEN g.child_type ELSE g.parent_type END AS entity_type,
      CASE WHEN g.direction = 'FORWARD' THEN g.child_id ELSE g.parent_id END AS entity_id,
      CASE WHEN g.direction = 'FORWARD' THEN COALESCE(g.child_lot, g.child_serial) ELSE COALESCE(g.parent_lot, g.parent_serial) END AS lot_serial,
      g.qty,
      g.uom,
      CASE WHEN g.direction = 'FORWARD' THEN g.parent_lot ELSE g.child_lot END::text AS path
    FROM mes.mes_genealogy g
    WHERE (p_direction = 'FORWARD' AND (
          (p_entity_type = 'MATERIAL' AND g.parent_lot = (SELECT lot_number FROM mes.mes_material_consumption WHERE consumption_id = p_entity_id))
       OR (p_entity_type = 'WORK_ORDER' AND g.parent_id = p_entity_id)
       OR g.parent_id = p_entity_id))
      AND g.direction = p_direction

    UNION ALL

    -- Recursive: parent/child chain
    SELECT
      t.depth + 1,
      g.direction,
      CASE WHEN g.direction = 'FORWARD' THEN g.child_type ELSE g.parent_type END,
      CASE WHEN g.direction = 'FORWARD' THEN g.child_id ELSE g.parent_id END,
      CASE WHEN g.direction = 'FORWARD' THEN COALESCE(g.child_lot, g.child_serial) ELSE COALESCE(g.parent_lot, g.parent_serial) END,
      g.qty,
      g.uom,
      CONCAT(t.path, ' → ', CASE WHEN g.direction = 'FORWARD' THEN COALESCE(g.child_lot, g.child_serial::text) ELSE COALESCE(g.parent_lot, g.parent_serial::text) END)
    FROM mes.mes_genealogy g
    JOIN trace t ON (p_direction = 'FORWARD' AND g.parent_id = t.entity_id)
                 OR (p_direction = 'BACKWARD' AND g.child_id = t.entity_id)
    WHERE t.depth < p_max_depth
      AND g.direction = p_direction
  )
  SELECT DISTINCT
    t.depth,
    t.direction,
    t.entity_type,
    t.entity_id,
    t.lot_serial,
    t.qty,
    t.uom,
    t.path
  FROM trace t
  ORDER BY t.depth, t.entity_type;
END;
$$;


--
-- Name: inspection_routing_assign(uuid, character varying, character varying); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.inspection_routing_assign(p_operation_exec_id uuid, p_inspection_type character varying, p_priority character varying DEFAULT 'MEDIUM'::character varying) RETURNS TABLE(inspector_id uuid, inspector_name text, skill_match text, current_load integer, estimated_wait_min integer, assignment_note text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_inspector_id uuid;
  v_work_center_id uuid;
  v_skilled_available integer;
  v_first_available uuid;
  v_min_load integer;
BEGIN
  -- Get the work center for this operation
  SELECT work_center_id INTO v_work_center_id
  FROM mes.mes_operation_execution
  WHERE operation_exec_id = p_operation_exec_id;

  -- Find best inspector: skilled, least loaded, available
  WITH inspector_ranking AS (
    SELECT
      o.operator_id,
      CONCAT(o.first_name, ' ', o.last_name) AS name,
      CASE 
        WHEN os.certified THEN 'CERTIFIED'
        WHEN os.proficiency_level >= 3 THEN 'QUALIFIED'
        ELSE 'TRAINEE'
      END AS skill_level,
      ls.current_load,
      COALESCE(ls.current_load, 0) * 
        CASE 
          WHEN os.certified THEN 1
          WHEN os.proficiency_level >= 3 THEN 2
          ELSE 5
        END AS weighted_load
    FROM mes.mes_operators o
    JOIN mes.mes_operator_skills os ON os.operator_id = o.operator_id
    LEFT JOIN (
      SELECT 
        assigned_to AS operator_id,
        COUNT(*) AS current_load
      FROM mes.mes_alerts
      WHERE status = 'ACTIVE'
        AND alert_type = 'QUALITY'
      GROUP BY assigned_to
    ) ls ON ls.operator_id = o.operator_id
    WHERE o.is_active = true
      AND os.skill_code IN ('GD&T', 'CMM-PROG', 'INSPECTION')
      AND os.proficiency_level >= 2
  )
  SELECT 
    operator_id,
    name,
    skill_level,
    COALESCE(current_load, 0),
    operator_id INTO v_inspector_id
  FROM inspector_ranking
  WHERE skill_level IN ('CERTIFIED', 'QUALIFIED')
  ORDER BY weighted_load ASC, skill_level DESC
  LIMIT 1;

  -- Create the inspection alert
  IF v_inspector_id IS NOT NULL THEN
    INSERT INTO mes.mes_alerts (
      alert_type, severity, source_type, source_id,
      title, message, status, assigned_to, assigned_at
    ) VALUES (
      'QUALITY',
      CASE WHEN p_priority = 'HIGH' THEN 'HIGH' WHEN p_priority = 'MEDIUM' THEN 'MEDIUM' ELSE 'LOW' END,
      'OPERATION', p_operation_exec_id,
      CONCAT('Inspection Required: ', p_inspection_type),
      CONCAT('Operation ', p_operation_exec_id, ' requires ', p_inspection_type, 
             ' inspection. Priority: ', p_priority),
      'ACTIVE', v_inspector_id, NOW()
    );

    RETURN QUERY
    SELECT 
      o.operator_id,
      CONCAT(o.first_name, ' ', o.last_name)::text,
      COALESCE(os2.skill_level, 'ASSIGNED')::text,
      COALESCE(la.current_load, 0)::integer,
      (COALESCE(la.current_load, 0) * 15)::integer,
      CONCAT('Assigned to ', o.first_name, ' ', o.last_name, 
             '. Estimated wait: ', COALESCE(la.current_load, 0) * 15, ' minutes.')::text
    FROM mes.mes_operators o
    LEFT JOIN (
      SELECT assigned_to AS operator_id, COUNT(*) AS current_load
      FROM mes.mes_alerts WHERE status = 'ACTIVE' GROUP BY assigned_to
    ) la ON la.operator_id = o.operator_id
    LEFT JOIN (
      SELECT 'CERTIFIED'::text AS skill_level, operator_id FROM mes.mes_operator_skills WHERE certified = true AND (skill_code IN ('GD&T', 'CMM-PROG', 'INSPECTION'))
    ) os2 ON os2.operator_id = o.operator_id
    WHERE o.operator_id = v_inspector_id;
  ELSE
    RETURN QUERY SELECT 
      NULL::uuid, 'No qualified inspector available'::text,
      'NONE'::text, 0::integer, 999::integer,
      'CRITICAL: No inspector with required skills is currently available. Escalate to QC supervisor.'::text;
  END IF;
END;
$$;


--
-- Name: maintenance_schedule_generate(integer); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.maintenance_schedule_generate(p_lookahead_days integer DEFAULT 7) RETURNS TABLE(mwo_id uuid, equipment_code character varying, equipment_name character varying, maintenance_type character varying, due_date date, priority character varying, description text, estimated_min integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  INSERT INTO mes.mes_maintenance_work_orders (
    equipment_id, maintenance_type, title, description, priority, status,
    scheduled_date, cost_estimated
  )
  SELECT
    ms.equipment_id,
    ms.maintenance_type,
    CONCAT(e.equipment_code, ' - ', INITCAP(ms.maintenance_type), ' Maintenance (Due: ', ms.next_due, ')'),
    ms.description,
    CASE 
      WHEN ms.next_due <= CURRENT_DATE THEN 'CRITICAL'
      WHEN ms.next_due <= CURRENT_DATE + 2 THEN 'HIGH'
      WHEN ms.next_due <= CURRENT_DATE + 5 THEN 'MEDIUM'
      ELSE 'LOW'
    END,
    'OPEN',
    ms.next_due,
    CASE ms.maintenance_type
      WHEN 'PREVENTIVE' THEN 500.00
      WHEN 'PREDICTIVE' THEN 300.00
      ELSE 200.00
    END
  FROM mes.mes_maintenance_schedules ms
  JOIN mes.mes_equipment e ON e.equipment_id = ms.equipment_id
  WHERE ms.next_due <= CURRENT_DATE + p_lookahead_days
    AND ms.is_active = true
    AND NOT EXISTS (
      SELECT 1 FROM mes.mes_maintenance_work_orders mwo
      WHERE mwo.equipment_id = ms.equipment_id
        AND mwo.maintenance_type = ms.maintenance_type
        AND mwo.status IN ('OPEN', 'IN_PROGRESS')
    )
  RETURNING
    mes_maintenance_work_orders.mwo_id,
    (SELECT e2.equipment_code FROM mes.mes_equipment e2 WHERE e2.equipment_id = mes_maintenance_work_orders.equipment_id),
    (SELECT e2.equipment_name FROM mes.mes_equipment e2 WHERE e2.equipment_id = mes_maintenance_work_orders.equipment_id),
    mes_maintenance_work_orders.maintenance_type,
    mes_maintenance_work_orders.scheduled_date,
    mes_maintenance_work_orders.priority,
    mes_maintenance_work_orders.description,
    NULL::integer;
END;
$$;


--
-- Name: oee_calculate(character varying, uuid, date, date, character varying); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.oee_calculate(p_entity_type character varying, p_entity_id uuid, p_start_date date, p_end_date date, p_period_type character varying DEFAULT 'DAY'::character varying) RETURNS TABLE(calc_date date, available_min numeric, operating_min numeric, downtime_min numeric, ideal_cycle_sec numeric, total_parts integer, good_parts integer, defect_parts integer, availability_pct numeric, performance_pct numeric, quality_pct numeric, oee_pct numeric, oee_target numeric, gap_pct numeric)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_target_oee numeric(5,2);
BEGIN
  SELECT t.oee_target INTO v_target_oee
  FROM mes.mes_oee_targets t
  WHERE (p_entity_type = 'EQUIPMENT' AND t.equipment_id = p_entity_id)
     OR (p_entity_type = 'WORK_CENTER' AND t.work_center_id = p_entity_id)
  ORDER BY t.effective_from DESC NULLS LAST
  LIMIT 1;
  v_target_oee := COALESCE(v_target_oee, 85.00);
  RETURN QUERY
  WITH daily_metrics AS (
    SELECT
      o.calculation_date,
      AVG(o.available_time_min)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS avail_ma,
      AVG(o.operating_time_min)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS oper_ma,
      AVG(o.downtime_min)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS dt_ma,
      AVG(o.ideal_cycle_time)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS cycle_ma,
      SUM(o.total_parts)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS parts_sum,
      SUM(o.good_parts)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS good_sum,
      SUM(o.defect_parts)
      OVER (ORDER BY o.calculation_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS defect_sum
    FROM mes.mes_oee_calculations o
    WHERE (p_entity_type = 'EQUIPMENT' AND o.equipment_id = p_entity_id)
       OR (p_entity_type = 'WORK_CENTER' AND o.work_center_id = p_entity_id)
      AND o.calculation_date BETWEEN p_start_date AND p_end_date
  )
  SELECT DISTINCT
    d.calculation_date,
    d.avail_ma::numeric(10,2)           AS available_min,
    d.oper_ma::numeric(10,2)            AS operating_min,
    d.dt_ma::numeric(10,2)              AS downtime_min,
    d.cycle_ma::numeric(10,2)           AS ideal_cycle_sec,
    d.parts_sum::integer                AS total_parts,
    d.good_sum::integer                 AS good_parts,
    d.defect_sum::integer               AS defect_parts,
    CASE WHEN d.avail_ma > 0 
      THEN (d.oper_ma / d.avail_ma * 100)::numeric(5,2)
      ELSE 0 END                        AS availability_pct,
    CASE WHEN d.oper_ma > 0 AND d.cycle_ma > 0
      THEN ((d.parts_sum * d.cycle_ma / d.oper_ma / 60) * 100)::numeric(5,2)
      ELSE 0 END                        AS performance_pct,
    CASE WHEN d.parts_sum > 0 
      THEN (d.good_sum::numeric / d.parts_sum * 100)::numeric(5,2)
      ELSE 0 END                        AS quality_pct,
    CASE WHEN d.avail_ma > 0 AND d.cycle_ma > 0 AND d.parts_sum > 0
      THEN (
        (d.oper_ma / d.avail_ma) * 
        ((d.parts_sum * d.cycle_ma / d.oper_ma / 60)) * 
        (d.good_sum::numeric / d.parts_sum) * 100
      )::numeric(5,2)
      ELSE 0 END                        AS oee_pct,
    v_target_oee                        AS oee_target,
    (v_target_oee - 
      CASE WHEN d.avail_ma > 0 AND d.cycle_ma > 0 AND d.parts_sum > 0
        THEN (
          (d.oper_ma / d.avail_ma) * 
          ((d.parts_sum * d.cycle_ma / d.oper_ma / 60)) * 
          (d.good_sum::numeric / d.parts_sum) * 100
        )::numeric(5,2)
        ELSE 0 END
    )::numeric(5,2)                     AS gap_pct
  FROM daily_metrics d
  ORDER BY d.calculation_date DESC;
END;
$$;


--
-- Name: reset_sample_data(); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.reset_sample_data() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
  tbl text;
BEGIN
  FOR tbl IN 
    SELECT table_name FROM information_schema.tables 
    WHERE table_schema = 'mes' AND table_type = 'BASE TABLE'
    ORDER BY table_name
  LOOP
    EXECUTE format('DELETE FROM mes.%I', tbl);
  END LOOP;
END;
$$;


--
-- Name: sampling_optimize_frequency(uuid, numeric); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.sampling_optimize_frequency(p_operation_exec_id uuid, p_target_cpk numeric DEFAULT 1.33) RETURNS TABLE(current_cpk numeric, recommended_freq integer, current_freq integer, risk_level text, recommendation text)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_cpk        numeric(10,4);
  v_ocount     integer;
  v_total      integer;
  v_defect_pct numeric(5,2);
BEGIN
  -- Get current process capability
  SELECT s.cpk INTO v_cpk
  FROM mes.spc_calculate_capability(p_operation_exec_id) s;

  -- Get defect rate
  SELECT 
    COUNT(*) FILTER (WHERE result = 'FAIL' OR result = 'OUT_OF_SPEC'),
    COUNT(*)
  INTO v_ocount, v_total
  FROM mes.mes_quality_inspections
  WHERE operation_exec_id = p_operation_exec_id;

  v_defect_pct := CASE WHEN v_total > 0 
    THEN (v_ocount::numeric / v_total * 100) 
    ELSE 0 END;

  RETURN QUERY
  SELECT
    v_cpk                                                     AS current_cpk,
    CASE
      WHEN v_cpk >= 1.67 THEN 50                              -- Very capable: inspect every 50th
      WHEN v_cpk >= 1.33 THEN 20                              -- Capable: inspect every 20th
      WHEN v_cpk >= 1.00 THEN 10                              -- Marginally capable: inspect every 10th
      WHEN v_cpk >= 0.67 THEN 5                               -- Poor: inspect every 5th
      ELSE 1                                                  -- Not capable: 100% inspection
    END                                                       AS recommended_freq,
    CASE
      WHEN v_cpk >= 1.67 THEN 10
      WHEN v_cpk >= 1.33 THEN 10
      WHEN v_cpk >= 1.00 THEN 10
      WHEN v_cpk >= 0.67 THEN 10
      ELSE 1
    END                                                       AS current_freq,
    CASE
      WHEN v_cpk >= 1.67 THEN 'LOW'
      WHEN v_cpk >= 1.33 THEN 'NORMAL'
      WHEN v_cpk >= 1.00 THEN 'MODERATE'
      WHEN v_cpk >= 0.67 THEN 'HIGH'
      ELSE 'CRITICAL'
    END                                                       AS risk_level,
    CASE
      WHEN v_cpk >= 1.67 THEN 'Process highly capable. Reduce sampling by 80%. Monitor weekly.'
      WHEN v_cpk >= 1.33 THEN 'Process capable. Maintain or slightly reduce sampling.'
      WHEN v_cpk >= 1.00 THEN 'Process marginally capable. Maintain current sampling. Consider process improvement.'
      WHEN v_cpk >= 0.67 THEN 'Process not fully capable. Increase sampling frequency. Immediate process review needed.'
      ELSE 'Process not capable. 100% inspection required. Stop production and investigate.'
    END                                                       AS recommendation;
END;
$$;


--
-- Name: spc_calculate_capability(uuid, uuid); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.spc_calculate_capability(p_operation_exec_id uuid, p_inspection_id uuid DEFAULT NULL::uuid) RETURNS TABLE(sample_size integer, mean_value numeric, std_dev numeric, cp numeric, cpk numeric, cpk_lower numeric, cpk_upper numeric, usl numeric, lsl numeric, out_of_control boolean, violations text)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_usl        numeric(14,4);
  v_lsl        numeric(14,4);
  v_mean       numeric(14,4);
  v_std        numeric(14,4);
  v_n          integer;
  v_usl_actual numeric(14,4);
  v_lsl_actual numeric(14,4);
BEGIN
  -- Get spec limits from the operation's inspection(s)
  SELECT 
    AVG(qi.spec_max)::numeric(14,4),
    AVG(qi.spec_min)::numeric(14,4)
  INTO v_usl_actual, v_lsl_actual
  FROM mes.mes_quality_inspections qi
  WHERE qi.operation_exec_id = p_operation_exec_id
    AND (p_inspection_id IS NULL OR qi.inspection_id = p_inspection_id);

  -- Calculate statistics from SPC data
  SELECT 
    COUNT(*),
    AVG(sd.mean_value)::numeric(14,4),
    AVG(sd.std_dev)::numeric(14,4),
    AVG(sd.usl)::numeric(14,4),
    AVG(sd.lsl)::numeric(14,4)
  INTO v_n, v_mean, v_std, v_usl, v_lsl
  FROM mes.mes_quality_spc_data sd
  WHERE sd.operation_exec_id = p_operation_exec_id
    AND (p_inspection_id IS NULL OR sd.inspection_id = p_inspection_id);

  IF v_n IS NULL OR v_n = 0 THEN
    RETURN QUERY SELECT 
      0::integer, NULL::numeric, NULL::numeric,
      NULL::numeric, NULL::numeric, NULL::numeric, NULL::numeric,
      NULL::numeric, NULL::numeric, false, 'No SPC data found'::text;
    RETURN;
  END IF;

  -- Use spec limits from inspections if available, else from SPC data
  IF v_usl IS NULL THEN v_usl := v_usl_actual; END IF;
  IF v_lsl IS NULL THEN v_lsl := v_lsl_actual; END IF;

  RETURN QUERY
  WITH stats AS (
    SELECT
      v_n                                                                    AS sample_size,
      v_mean                                                                 AS mean_value,
      GREATEST(v_std, 0.0001)                                                AS std_dev,
      CASE WHEN v_std > 0 AND v_usl IS NOT NULL AND v_lsl IS NOT NULL
        THEN ((v_usl - v_lsl) / (6.0 * GREATEST(v_std, 0.0001)))::numeric(10,4)
        ELSE NULL END                                                        AS cp,
      CASE WHEN v_std > 0 AND v_usl IS NOT NULL
        THEN ((v_usl - v_mean) / (3.0 * GREATEST(v_std, 0.0001)))::numeric(10,4)
        ELSE NULL END                                                        AS cpu,
      CASE WHEN v_std > 0 AND v_lsl IS NOT NULL
        THEN ((v_mean - v_lsl) / (3.0 * GREATEST(v_std, 0.0001)))::numeric(10,4)
        ELSE NULL END                                                        AS cpl,
      v_usl                                                                   AS usl,
      v_lsl                                                                   AS lsl
  )
  SELECT
    s.sample_size,
    s.mean_value,
    s.std_dev,
    s.cp,
    LEAST(s.cpu, s.cpl)                           AS cpk,
    s.cpl                                          AS cpk_lower,
    s.cpu                                          AS cpk_upper,
    s.usl,
    s.lsl,
    (s.cp < 1.0 OR LEAST(s.cpu, s.cpl) < 0.8)     AS out_of_control,
    CASE
      WHEN s.cp IS NULL THEN 'Insufficient spec limits'
      WHEN s.cp < 0.67 THEN 'CRITICAL: Process not capable of meeting spec'
      WHEN s.cp < 1.0 THEN 'WARNING: Process marginally capable (Cp < 1.0)'
      WHEN LEAST(s.cpu, s.cpl) < 0.8 THEN 'WARNING: Process off-center (Cpk < 0.8)'
      WHEN s.cp >= 1.33 THEN 'GOOD: Process capable (Cp >= 1.33)'
      ELSE 'ACCEPTABLE: Process capable'
    END                                           AS violations
  FROM stats s;
END;
$$;


--
-- Name: spc_control_chart_data(uuid, integer); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.spc_control_chart_data(p_operation_exec_id uuid, p_lookback_samples integer DEFAULT 25) RETURNS TABLE(sample_index integer, sample_mean numeric, sample_range numeric, cl_mean numeric, ucl_mean numeric, lcl_mean numeric, cl_range numeric, ucl_range numeric, lcl_range numeric, centerline numeric, rule_violation text)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_overall_mean numeric(14,4);
  v_avg_range    numeric(14,4);
  v_n            integer;
BEGIN
  -- Compute overall mean and average range from SPC data
  WITH sample_stats AS (
    SELECT
      ROW_NUMBER() OVER (ORDER BY s.sample_at) AS rn,
      s.mean_value,
      (s.usl - s.lsl) / 2.0 + s.lsl AS target,
      ABS(s.mean_value - ((s.usl - s.lsl) / 2.0 + s.lsl)) AS deviation
    FROM mes.mes_quality_spc_data s
    WHERE s.operation_exec_id = p_operation_exec_id
    ORDER BY s.sample_at DESC
    LIMIT p_lookback_samples
  )
  SELECT
    AVG(s.mean_value),
    AVG(s.deviation) * 2.0
  INTO v_overall_mean, v_avg_range
  FROM sample_stats s;

  IF v_overall_mean IS NULL THEN
    RETURN;
  END IF;

  v_n := p_lookback_samples;

  -- A2, D3, D4 constants for X-bar and R charts (n=5 standard)
  -- Using constants for subgroup size = 5: A2=0.577, D3=0, D4=2.114
  RETURN QUERY
  WITH sample_data AS (
    SELECT
      ROW_NUMBER() OVER (ORDER BY s.sample_at)::integer AS idx,
      s.mean_value,
      COALESCE(s.std_dev * 2.0, 0) AS rng,
      s.mean_value - v_overall_mean AS deviation
    FROM mes.mes_quality_spc_data s
    WHERE s.operation_exec_id = p_operation_exec_id
    ORDER BY s.sample_at
    LIMIT p_lookback_samples
  )
  SELECT
    s.idx                                                               AS sample_index,
    s.mean_value                                                        AS sample_mean,
    s.rng                                                               AS sample_range,
    v_overall_mean                                                      AS cl_mean,
    (v_overall_mean + 0.577 * v_avg_range)::numeric(10,4)               AS ucl_mean,
    (v_overall_mean - 0.577 * v_avg_range)::numeric(10,4)               AS lcl_mean,
    v_avg_range                                                         AS cl_range,
    (2.114 * v_avg_range)::numeric(10,4)                                AS ucl_range,
    (GREATEST(0, 0 * v_avg_range))::numeric(10,4)                       AS lcl_range,
    v_overall_mean                                                      AS centerline,
    CASE
      WHEN ABS(s.deviation) > 3 * v_avg_range / 1.128 THEN 'Rule 1: Beyond 3σ'
      WHEN (COUNT(*) OVER (ORDER BY s.idx ROWS BETWEEN 2 PRECEDING AND CURRENT ROW)) >= 2
           AND AVG(s.deviation) OVER (ORDER BY s.idx ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) > 2 * v_avg_range / 1.128
        THEN 'Rule 2: 2 of 3 beyond 2σ'
      WHEN (COUNT(*) OVER (ORDER BY s.idx ROWS BETWEEN 4 PRECEDING AND CURRENT ROW)) >= 4
           AND AVG(s.deviation) OVER (ORDER BY s.idx ROWS BETWEEN 4 PRECEDING AND CURRENT ROW) > v_avg_range / 1.128
        THEN 'Rule 3: 4 of 5 beyond 1σ'
      WHEN (COUNT(*) OVER (ORDER BY s.idx ROWS BETWEEN 7 PRECEDING AND CURRENT ROW)) >= 7
           AND AVG(SIGN(s.deviation)) OVER (ORDER BY s.idx ROWS BETWEEN 7 PRECEDING AND CURRENT ROW) = 1
        THEN 'Rule 4: 8+ consecutive above centerline'
      ELSE NULL
    END                                                                 AS rule_violation
  FROM sample_data s;
END;
$$;


--
-- Name: trigger_set_updated_at(); Type: FUNCTION; Schema: mes; Owner: -
--

CREATE FUNCTION mes.trigger_set_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.updated_at := NOW();
  NEW.object_version_number := COALESCE(OLD.object_version_number, 0) + 1;
  RETURN NEW;
END;
$$;


--
-- Name: refresh_mv_concurrently(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_mv_concurrently(p_mv_name text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    EXECUTE format('REFRESH MATERIALIZED VIEW CONCURRENTLY %I', p_mv_name);
EXCEPTION WHEN others THEN
    EXECUTE format('REFRESH MATERIALIZED VIEW %I', p_mv_name);
END;
$$;


--
-- Name: set_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_updated_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.updated_at = CURRENT_TIMESTAMP;
  RETURN NEW;
END;
$$;


--
-- Name: uuidv7(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.uuidv7() RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  ts_msec   BIGINT;
  rand_bytes BYTEA;
BEGIN
  ts_msec := (EXTRACT(EPOCH FROM clock_timestamp()) * 1000)::BIGINT;
  rand_bytes := gen_random_bytes(10);
  RETURN encode(
    set_byte(
      set_byte(
        overlay(rand_bytes PLACING (substring(int8send(ts_msec) FROM 3)) FROM 1 FOR 6),
        6, (get_byte(rand_bytes, 6) & 15) | 112
      ),
      8, (get_byte(rand_bytes, 8) & 63) | 128
    ),
    'hex'
  )::uuid;
END;
$$;


--
-- Name: fn_qc_calculate_capability(bigint, bigint, jsonb, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_calculate_capability(p_characteristic_id bigint, p_item_id bigint, p_data_points jsonb, p_created_by character varying) RETURNS TABLE(cp numeric, cpk numeric, pp numeric, ppk numeric, sample_mean numeric, sample_std numeric, sample_size integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_cp NUMERIC(19,8);
    v_cpk NUMERIC(19,8);
    v_pp NUMERIC(19,8);
    v_ppk NUMERIC(19,8);
    v_mean NUMERIC(19,8);
    v_std NUMERIC(19,8);
    v_std_pp NUMERIC(19,8);
    v_usl NUMERIC(19,8);
    v_lsl NUMERIC(19,8);
    v_count INTEGER;
    v_sum NUMERIC(19,8) := 0;
    v_sum_sq NUMERIC(19,8) := 0;
    v_val NUMERIC(19,8);
    v_arr NUMERIC[];
BEGIN
    SELECT sl.upper_limit, sl.lower_limit INTO v_usl, v_lsl
    FROM qc.qc_spec_limits sl
    WHERE sl.characteristic_id = p_characteristic_id AND sl.is_active = 'Y'
    LIMIT 1;

    SELECT jsonb_array_length(p_data_points) INTO v_count;
    v_count := COALESCE(v_count, 0);

    IF v_count < 2 THEN
        RAISE EXCEPTION 'Need at least 2 data points for capability analysis';
    END IF;

    FOR i IN 0..v_count-1 LOOP
        v_val := (p_data_points->>i)::NUMERIC;
        v_sum := v_sum + v_val;
        v_sum_sq := v_sum_sq + (v_val * v_val);
    END LOOP;

    v_mean := v_sum / v_count;
    v_std := SQRT((v_sum_sq - (v_sum * v_sum) / v_count) / (v_count - 1));
    v_std_pp := SQRT((v_sum_sq - (v_sum * v_sum) / v_count) / v_count);

    IF v_std > 0 AND v_usl IS NOT NULL AND v_lsl IS NOT NULL THEN
        v_cp := (v_usl - v_lsl) / (6 * v_std);
        v_cpk := LEAST((v_usl - v_mean) / (3 * v_std), (v_mean - v_lsl) / (3 * v_std));
        v_pp := (v_usl - v_lsl) / (6 * v_std_pp);
        v_ppk := LEAST((v_usl - v_mean) / (3 * v_std_pp), (v_mean - v_lsl) / (3 * v_std_pp));
    END IF;

    INSERT INTO qc.qc_spc_charts (chart_code, chart_name, chart_type_code, characteristic_id, item_id, subgroup_size,
        chart_status_code, upper_spec_limit, lower_spec_limit, target_value, cp_value, cpk_value, pp_value, ppk_value,
        sigma_estimate, created_by)
    VALUES ('CAPA-' || TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD-HH24MISS'),
        'Capability Study - Char ' || p_characteristic_id, 'CAPABILITY',
        p_characteristic_id, p_item_id, v_count, 'ACTIVE', v_usl, v_lsl, v_mean,
        v_cp, v_cpk, v_pp, v_ppk, v_std, p_created_by);

    RETURN QUERY SELECT v_cp, v_cpk, v_pp, v_ppk, v_mean, v_std, v_count;
END;
$$;


--
-- Name: fn_qc_calculate_sample_size(integer, numeric, character varying, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_calculate_sample_size(p_lot_size integer, p_aql_value numeric, p_inspection_level character varying, p_sampling_type character varying, p_tenant_id character varying) RETURNS TABLE(sample_size integer, accept_number integer, reject_number integer, plan_code character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_sample_size INTEGER;
    v_accept INTEGER;
    v_reject INTEGER;
    v_plan_code VARCHAR(100);
BEGIN
    -- Use ANSI/ASQ Z1.4 General Level II as default
    IF p_inspection_level IS NULL OR p_inspection_level = '' THEN
        p_inspection_level := 'GENERAL_II';
    END IF;
    IF p_sampling_type IS NULL OR p_sampling_type = '' THEN
        p_sampling_type := 'SINGLE';
    END IF;

    SELECT sp.sample_size, sp.accept_number, sp.reject_number, sp.plan_code
    INTO v_sample_size, v_accept, v_reject, v_plan_code
    FROM qc.qc_sampling_plans sp
    JOIN qc.qc_sampling_plan_lines spl ON spl.sampling_plan_id = sp.sampling_plan_id
    WHERE sp.sampling_level_code = p_inspection_level
        AND sp.sampling_type_code = p_sampling_type
        AND (sp.aql_value = p_aql_value OR (sp.aql_value IS NULL AND p_aql_value IS NULL))
        AND p_lot_size BETWEEN spl.lot_size_from AND spl.lot_size_to
        AND sp.is_active = 'Y'
    LIMIT 1;

    IF v_sample_size IS NULL THEN
        -- Fallback: use square root approximation
        v_sample_size := GREATEST(1, LEAST(p_lot_size, CEIL(SQRT(p_lot_size::NUMERIC) * 2)::INTEGER));
        v_accept := GREATEST(1, CEIL(v_sample_size * 0.01));
        v_reject := v_accept + 1;
        v_plan_code := 'CALCULATED';
    END IF;

    RETURN QUERY SELECT v_sample_size, v_accept, v_reject, v_plan_code;
END;
$$;


--
-- Name: fn_qc_close_ncr(bigint, character varying, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_close_ncr(p_ncr_id bigint, p_closure_notes character varying, p_closed_by character varying, p_tenant_id character varying) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_ncr_status VARCHAR(50);
    v_capa_id BIGINT;
    v_capa_status VARCHAR(50);
    v_open_capa_actions INTEGER;
BEGIN
    SELECT ncr_status_code, capa_id INTO v_ncr_status, v_capa_id
    FROM qc.qc_ncr_headers WHERE ncr_id = p_ncr_id AND is_active = 'Y';

    IF v_ncr_status IS NULL THEN
        RAISE EXCEPTION 'NCR % not found', p_ncr_id;
    END IF;

    IF v_ncr_status = 'CLOSED' THEN
        RAISE EXCEPTION 'NCR % is already closed', p_ncr_id;
    END IF;

    -- Check linked CAPA is closed
    IF v_capa_id IS NOT NULL THEN
        SELECT capa_status_code INTO v_capa_status
        FROM qc.qc_capa_headers WHERE capa_id = v_capa_id;

        SELECT COUNT(*) INTO v_open_capa_actions
        FROM qc.qc_capa_actions
        WHERE capa_id = v_capa_id AND action_status_code NOT IN ('COMPLETED', 'CLOSED');

        IF v_capa_status != 'CLOSED' THEN
            RAISE EXCEPTION 'Cannot close NCR - linked CAPA % is still %', v_capa_id, v_capa_status;
        END IF;

        IF v_open_capa_actions > 0 THEN
            RAISE EXCEPTION 'Cannot close NCR - % CAPA actions are still open', v_open_capa_actions;
        END IF;
    END IF;

    UPDATE qc.qc_ncr_headers
    SET ncr_status_code = 'CLOSED',
        closed_date = CURRENT_TIMESTAMP,
        closed_by = p_closed_by,
        closure_notes = p_closure_notes,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_closed_by
    WHERE ncr_id = p_ncr_id;

    RETURN 'CLOSED';
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to close NCR: %', SQLERRM;
END;
$$;


--
-- Name: fn_qc_complete_inspection(bigint, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_complete_inspection(p_inspection_id bigint, p_created_by character varying) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total_lines INTEGER;
    v_fail_lines INTEGER;
    v_warning_lines INTEGER;
    v_overall_result VARCHAR(50);
BEGIN
    SELECT COUNT(*), COUNT(*) FILTER (WHERE result_status_code = 'FAIL'), COUNT(*) FILTER (WHERE result_status_code = 'WARNING')
    INTO v_total_lines, v_fail_lines, v_warning_lines
    FROM qc.qc_test_result_lines trl
    JOIN qc.qc_test_results tr ON tr.test_result_id = trl.test_result_id
    WHERE tr.inspection_id = p_inspection_id AND trl.is_active = 'Y';

    IF v_fail_lines > 0 THEN
        v_overall_result := 'FAIL';
    ELSIF v_warning_lines > 0 THEN
        v_overall_result := 'CONDITIONAL_PASS';
    ELSE
        v_overall_result := 'PASS';
    END IF;

    UPDATE qc.qc_test_results
    SET test_result_status_code = 'COMPLETED',
        overall_result_code = v_overall_result,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_created_by
    WHERE test_result_id IN (
        SELECT test_result_id FROM qc.qc_test_results WHERE inspection_id = p_inspection_id
    );

    UPDATE qc.qc_inspections
    SET inspection_status_code = 'COMPLETED',
        overall_result_code = v_overall_result,
        completed_date = CURRENT_TIMESTAMP,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_created_by
    WHERE inspection_id = p_inspection_id;

    RETURN v_overall_result;
END;
$$;


--
-- Name: fn_qc_create_capa(bigint, character varying, character varying, character varying, character varying, character varying, character varying, date, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_create_capa(p_source_ncr_id bigint, p_capa_type_code character varying, p_capa_priority_code character varying, p_capa_title character varying, p_problem_description character varying, p_requested_by character varying, p_assigned_to character varying, p_due_date date, p_tenant_id character varying, p_created_by character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_capa_id BIGINT;
    v_capa_number VARCHAR(100);
    v_root_cause_analysis_id BIGINT;
    v_ncr_exists INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_ncr_exists FROM qc.qc_ncr_headers WHERE ncr_id = p_source_ncr_id AND is_active = 'Y';
    IF v_ncr_exists = 0 THEN
        RAISE EXCEPTION 'NCR % not found', p_source_ncr_id;
    END IF;

    SELECT root_cause_analysis_id INTO v_root_cause_analysis_id
    FROM qc.qc_ncr_headers WHERE ncr_id = p_source_ncr_id;

    v_capa_number := 'CAPA-' || TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD-HH24MISS');

    INSERT INTO qc.qc_capa_headers (
        capa_number, capa_title, capa_type_code, capa_source_code,
        source_ncr_id, capa_priority_code, capa_status_code,
        root_cause_analysis_id, problem_description,
        requested_by, requested_date, assigned_to, due_date,
        created_by, tenant_id
    ) VALUES (
        v_capa_number, p_capa_title, p_capa_type_code, 'NCR',
        p_source_ncr_id, p_capa_priority_code, 'OPEN',
        v_root_cause_analysis_id, p_problem_description,
        p_requested_by, CURRENT_TIMESTAMP, p_assigned_to, p_due_date,
        p_created_by, p_tenant_id
    ) RETURNING capa_id INTO v_capa_id;

    UPDATE qc.qc_ncr_headers
    SET capa_id = v_capa_id, last_update_date = CURRENT_TIMESTAMP, last_updated_by = p_created_by
    WHERE ncr_id = p_source_ncr_id;

    RETURN v_capa_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to create CAPA: %', SQLERRM;
END;
$$;


--
-- Name: fn_qc_create_inspection(character varying, character varying, bigint, bigint, character varying, bigint, bigint, numeric, character varying, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_create_inspection(p_inspection_type_code character varying, p_source_type_code character varying, p_source_document_id bigint, p_item_id bigint, p_lot_number character varying, p_organization_id bigint, p_quality_plan_id bigint, p_quantity numeric, p_inspector_name character varying, p_tenant_id character varying, p_created_by character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $_$
DECLARE
    v_inspection_id BIGINT;
    v_inspection_number VARCHAR(100);
    v_sampling_plan_id BIGINT;
    v_sample_size NUMERIC(19,4);
    v_plan_count INTEGER;
BEGIN
    -- Generate inspection number
    SELECT 'INS-' || TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD-') || LPAD(COALESCE(MAX(SUBSTRING(inspection_number FROM '\d+$')::INTEGER), 0) + 1::VARCHAR, 4, '0')
    INTO v_inspection_number
    FROM qc.qc_inspections
    WHERE inspection_number LIKE 'INS-' || TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD') || '%';

    IF v_inspection_number IS NULL THEN
        v_inspection_number := 'INS-' || TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD-0001');
    END IF;

    -- Get sampling plan and sample size from quality plan
    SELECT pe.sampling_plan_id, sp.sample_size
    INTO v_sampling_plan_id, v_sample_size
    FROM qc.qc_plan_elements pe
    JOIN qc.qc_sampling_plans sp ON sp.sampling_plan_id = pe.sampling_plan_id
    WHERE pe.plan_id = p_quality_plan_id AND pe.is_active = 'Y'
    LIMIT 1;

    IF v_sample_size IS NULL THEN
        v_sample_size := LEAST(p_quantity, 50);
    END IF;

    -- Validate plan exists
    SELECT COUNT(*) INTO v_plan_count FROM qc.qc_plans WHERE plan_id = p_quality_plan_id AND is_active = 'Y';
    IF v_plan_count = 0 THEN
        RAISE EXCEPTION 'Quality plan % not found or inactive', p_quality_plan_id;
    END IF;

    INSERT INTO qc.qc_inspections (
        inspection_number, inspection_type_code, source_type_code,
        source_document_id, item_id, lot_number, organization_id,
        quality_plan_id, sampling_plan_id, inspector_name,
        inspection_quantity, sample_quantity,
        inspection_status_code, planned_date, created_by, tenant_id
    ) VALUES (
        v_inspection_number, p_inspection_type_code, p_source_type_code,
        p_source_document_id, p_item_id, p_lot_number, p_organization_id,
        p_quality_plan_id, v_sampling_plan_id, p_inspector_name,
        p_quantity, v_sample_size,
        'PLANNED', CURRENT_TIMESTAMP, p_created_by, p_tenant_id
    ) RETURNING inspection_id INTO v_inspection_id;

    RETURN v_inspection_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to create inspection: %', SQLERRM;
END;
$_$;


--
-- Name: fn_qc_create_ncr(bigint, character varying, character varying, character varying, character varying, character varying, date, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_create_ncr(p_inspection_id bigint, p_ncr_type_code character varying, p_ncr_severity_code character varying, p_description character varying, p_reported_by character varying, p_assigned_to character varying, p_due_date date, p_tenant_id character varying, p_created_by character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_ncr_id BIGINT;
    v_ncr_number VARCHAR(100);
    v_item_id BIGINT;
    v_lot_number VARCHAR(100);
    v_org_id BIGINT;
    v_quantity NUMERIC(19,4);
    v_inspection_status VARCHAR(50);
BEGIN
    SELECT inspection_status_code, item_id, lot_number, organization_id, rejected_quantity
    INTO v_inspection_status, v_item_id, v_lot_number, v_org_id, v_quantity
    FROM qc.qc_inspections WHERE inspection_id = p_inspection_id;

    IF v_inspection_status NOT IN ('COMPLETED', 'REJECTED') THEN
        RAISE EXCEPTION 'Cannot create NCR - inspection status % requires completed or rejected', v_inspection_status;
    END IF;

    v_ncr_number := 'NCR-' || TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD-HH24MISS');

    INSERT INTO qc.qc_ncr_headers (
        ncr_number, ncr_type_code, ncr_severity_code, ncr_status_code,
        discovery_source_code, source_inspection_id, item_id, lot_number,
        organization_id, quantity_affected, description, reported_by, reported_date,
        assigned_to, due_date, created_by, tenant_id
    ) VALUES (
        v_ncr_number, p_ncr_type_code, p_ncr_severity_code, 'OPEN',
        'INSPECTION', p_inspection_id, v_item_id, v_lot_number,
        v_org_id, v_quantity, p_description, p_reported_by, CURRENT_TIMESTAMP,
        p_assigned_to, p_due_date, p_created_by, p_tenant_id
    ) RETURNING ncr_id INTO v_ncr_id;

    UPDATE qc.qc_inspections
    SET ncr_id = v_ncr_id, last_update_date = CURRENT_TIMESTAMP, last_updated_by = p_created_by
    WHERE inspection_id = p_inspection_id;

    RETURN v_ncr_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to create NCR: %', SQLERRM;
END;
$$;


--
-- Name: fn_qc_disposition_lot(bigint, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_disposition_lot(p_inspection_id bigint, p_disposition_code character varying, p_disposition_reason character varying, p_disposition_by character varying, p_approved_by character varying, p_tenant_id character varying, p_created_by character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_disposition_id BIGINT;
    v_disposition_number VARCHAR(100);
    v_item_id BIGINT;
    v_lot_number VARCHAR(100);
    v_quantity NUMERIC(19,4);
    v_inspection_status VARCHAR(50);
BEGIN
    SELECT inspection_status_code, item_id, lot_number, inspection_quantity
    INTO v_inspection_status, v_item_id, v_lot_number, v_quantity
    FROM qc.qc_inspections WHERE inspection_id = p_inspection_id;

    IF v_inspection_status NOT IN ('COMPLETED', 'ACCEPTED', 'REJECTED') THEN
        RAISE EXCEPTION 'Inspection must be completed before disposition. Current status: %', v_inspection_status;
    END IF;

    v_disposition_number := 'DISP-' || TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD-HH24MISS');

    INSERT INTO qc.qc_lot_dispositions (
        disposition_number, inspection_id, item_id, lot_number, quantity,
        disposition_code, disposition_reason, disposition_date, disposition_by,
        approved_by, approved_date, created_by, tenant_id
    ) VALUES (
        v_disposition_number, p_inspection_id, v_item_id, v_lot_number, v_quantity,
        p_disposition_code, p_disposition_reason, CURRENT_TIMESTAMP, p_disposition_by,
        p_approved_by, CURRENT_TIMESTAMP, p_created_by, p_tenant_id
    ) RETURNING lot_disposition_id INTO v_disposition_id;

    UPDATE qc.qc_inspections
    SET disposition_code = p_disposition_code,
        inspection_status_code = CASE
            WHEN p_disposition_code = 'ACCEPT' THEN 'ACCEPTED'
            WHEN p_disposition_code = 'REJECT' THEN 'REJECTED'
            ELSE inspection_status_code
        END,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_created_by
    WHERE inspection_id = p_inspection_id;

    IF p_disposition_code IN ('REJECT', 'SCRAP') THEN
        INSERT INTO qc.qc_notifications (notification_number, notification_type_code, notification_severity, notification_status_code, title, message_body, source_type_code, source_id, created_by, tenant_id)
        VALUES ('NOTIF-' || v_disposition_number, 'LOT_REJECTED', 'HIGH', 'SENT',
            'Lot ' || COALESCE(v_lot_number, 'N/A') || ' Disposition: ' || p_disposition_code,
            'Lot has been dispositioned as ' || p_disposition_code || ': ' || p_disposition_reason,
            'INSPECTION', p_inspection_id, p_created_by, p_tenant_id);
    END IF;

    RETURN v_disposition_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to disposition lot: %', SQLERRM;
END;
$$;


--
-- Name: fn_qc_generate_control_limits(bigint, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_generate_control_limits(p_spc_chart_id bigint, p_created_by character varying) RETURNS TABLE(ucl numeric, cl numeric, lcl numeric, sigma_estimate numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_chart_type VARCHAR(50);
    v_subgroup_size INTEGER;
    v_mean NUMERIC(19,8);
    v_mean_range NUMERIC(19,8);
    v_mean_std NUMERIC(19,8);
    v_ucl NUMERIC(19,8);
    v_lcl NUMERIC(19,8);
    v_cl NUMERIC(19,8);
    v_sigma NUMERIC(19,8);
    v_a2 CONSTANT NUMERIC(19,8) := 0.577; -- For subgroup size 5
    v_d3 CONSTANT NUMERIC(19,8) := 0.0;
    v_d4 CONSTANT NUMERIC(19,8) := 2.114;
    v_c4 CONSTANT NUMERIC(19,8) := 0.940; -- For subgroup size 5
    v_count INTEGER;
BEGIN
    SELECT sc.chart_type_code, sc.subgroup_size
    INTO v_chart_type, v_subgroup_size
    FROM qc.qc_spc_charts sc WHERE sc.spc_chart_id = p_spc_chart_id;

    IF v_chart_type IS NULL THEN
        RAISE EXCEPTION 'SPC chart % not found', p_spc_chart_id;
    END IF;

    SELECT COUNT(*), AVG(sample_mean), AVG(sample_range), AVG(sample_std_dev)
    INTO v_count, v_mean, v_mean_range, v_mean_std
    FROM qc.qc_spc_data_points
    WHERE spc_chart_id = p_spc_chart_id AND is_active = 'Y';

    IF v_count < 20 THEN
        RAISE EXCEPTION 'Need at least 20 subgroups to calculate control limits. Have: %', v_count;
    END IF;

    IF v_chart_type = 'X_BAR_R' THEN
        v_cl := v_mean;
        v_ucl := v_mean + (v_a2 * v_mean_range);
        v_lcl := v_mean - (v_a2 * v_mean_range);
        v_sigma := v_mean_range / (v_subgroup_size * 0.326 / 0.577); -- d2 approximation
    ELSIF v_chart_type = 'X_BAR_S' THEN
        v_cl := v_mean;
        v_sigma := v_mean_std / v_c4;
        v_ucl := v_mean + (3 * v_sigma / SQRT(v_subgroup_size));
        v_lcl := v_mean - (3 * v_sigma / SQRT(v_subgroup_size));
    ELSE
        v_cl := v_mean;
        v_ucl := v_mean + (3 * v_mean_std);
        v_lcl := v_mean - (3 * v_mean_std);
        v_sigma := v_mean_std;
    END IF;

    UPDATE qc.qc_spc_charts
    SET upper_control_limit = v_ucl,
        lower_control_limit = v_lcl,
        center_line = v_cl,
        sigma_estimate = v_sigma,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_created_by
    WHERE spc_chart_id = p_spc_chart_id;

    UPDATE qc.qc_spc_data_points
    SET ucl = v_ucl, lcl = v_lcl, center_line = v_cl
    WHERE spc_chart_id = p_spc_chart_id;

    RETURN QUERY SELECT v_ucl, v_cl, v_lcl, v_sigma;
END;
$$;


--
-- Name: fn_qc_record_result_line(bigint, bigint, numeric, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_record_result_line(p_test_result_id bigint, p_characteristic_id bigint, p_measured_value numeric, p_tenant_id character varying, p_created_by character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_result_line_id BIGINT;
    v_spec_limit_id BIGINT;
    v_upper_limit NUMERIC(19,8);
    v_lower_limit NUMERIC(19,8);
    v_target NUMERIC(19,8);
    v_deviation NUMERIC(19,8);
    v_status VARCHAR(50);
    v_oos VARCHAR(1);
    v_test_result_id_check INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_test_result_id_check FROM qc.qc_test_results WHERE test_result_id = p_test_result_id;
    IF v_test_result_id_check = 0 THEN
        RAISE EXCEPTION 'Test result % not found', p_test_result_id;
    END IF;

    SELECT sl.spec_limit_id, sl.upper_limit, sl.lower_limit, sl.target_value
    INTO v_spec_limit_id, v_upper_limit, v_lower_limit, v_target
    FROM qc.qc_test_results tr
    JOIN qc.qc_inspections i ON i.inspection_id = tr.inspection_id
    JOIN qc.qc_plans p ON p.plan_id = i.quality_plan_id
    JOIN qc.qc_spec_limits sl ON sl.spec_id = p.spec_id AND sl.characteristic_id = p_characteristic_id AND sl.is_active = 'Y'
    WHERE tr.test_result_id = p_test_result_id
    LIMIT 1;

    v_deviation := COALESCE(p_measured_value - v_target, 0);

    IF v_upper_limit IS NOT NULL AND v_lower_limit IS NOT NULL THEN
        IF p_measured_value > v_upper_limit OR p_measured_value < v_lower_limit THEN
            v_status := 'FAIL';
            v_oos := 'Y';
        ELSIF p_measured_value >= v_upper_limit * 0.95 OR p_measured_value <= v_lower_limit * 1.05 THEN
            v_status := 'WARNING';
            v_oos := 'N';
        ELSE
            v_status := 'PASS';
            v_oos := 'N';
        END IF;
    ELSE
        v_status := 'PASS';
        v_oos := 'N';
    END IF;

    INSERT INTO qc.qc_test_result_lines (
        test_result_id, characteristic_id, spec_limit_id,
        measured_value, uom_code, deviation_from_target,
        result_status_code, is_out_of_spec, created_by, tenant_id
    ) VALUES (
        p_test_result_id, p_characteristic_id, v_spec_limit_id,
        p_measured_value, (SELECT uom_code FROM qc.qc_characteristics WHERE characteristic_id = p_characteristic_id),
        v_deviation, v_status, v_oos,
        p_created_by, p_tenant_id
    ) RETURNING test_result_line_id INTO v_result_line_id;

    RETURN v_result_line_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to record result line: %', SQLERRM;
END;
$$;


--
-- Name: fn_qc_record_results(bigint, character varying, character varying, bigint, bigint, character varying, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_record_results(p_inspection_id bigint, p_test_result_number character varying, p_operator_name character varying, p_test_method_id bigint, p_equipment_id bigint, p_tenant_id character varying, p_created_by character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_test_result_id BIGINT;
    v_inspection_exists INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_inspection_exists FROM qc.qc_inspections WHERE inspection_id = p_inspection_id AND is_active = 'Y';
    IF v_inspection_exists = 0 THEN
        RAISE EXCEPTION 'Inspection % not found', p_inspection_id;
    END IF;

    INSERT INTO qc.qc_test_results (
        test_result_number, inspection_id, test_result_status_code,
        operator_name, test_date, test_method_id, equipment_id,
        created_by, tenant_id
    ) VALUES (
        p_test_result_number, p_inspection_id, 'IN_PROGRESS',
        p_operator_name, CURRENT_TIMESTAMP, p_test_method_id, p_equipment_id,
        p_created_by, p_tenant_id
    ) RETURNING test_result_id INTO v_test_result_id;

    UPDATE qc.qc_inspections
    SET inspection_status_code = 'IN_PROGRESS',
        started_date = CURRENT_TIMESTAMP,
        inspector_name = COALESCE(p_operator_name, inspector_name),
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_created_by
    WHERE inspection_id = p_inspection_id;

    RETURN v_test_result_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to record test results: %', SQLERRM;
END;
$$;


--
-- Name: fn_qc_run_spc(bigint, character varying); Type: FUNCTION; Schema: qc; Owner: -
--

CREATE FUNCTION qc.fn_qc_run_spc(p_spc_chart_id bigint, p_created_by character varying) RETURNS TABLE(total_subgroups integer, ooc_subgroups integer, mean_cp numeric, mean_cpk numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total INTEGER;
    v_ooc INTEGER;
    v_cp NUMERIC(19,8);
    v_cpk NUMERIC(19,8);
    v_mean NUMERIC(19,8);
    v_std NUMERIC(19,8);
    v_usl NUMERIC(19,8);
    v_lsl NUMERIC(19,8);
    v_ucl NUMERIC(19,8);
    v_lcl NUMERIC(19,8);
    v_cl NUMERIC(19,8);
    v_subgroup_size INTEGER;
BEGIN
    SELECT sc.usl, sc.lsl, sc.ucl, sc.lcl, sc.cl, sc.subgroup_size
    INTO v_usl, v_lsl, v_ucl, v_lcl, v_cl, v_subgroup_size
    FROM qc.qc_spc_charts sc WHERE sc.spc_chart_id = p_spc_chart_id;

    IF v_subgroup_size IS NULL THEN
        RAISE EXCEPTION 'SPC chart % not found', p_spc_chart_id;
    END IF;

    UPDATE qc.qc_spc_data_points dp
    SET is_out_of_control = 'Y',
        out_of_control_rules = (
            SELECT jsonb_agg(rule) FROM (
                SELECT CASE
                    WHEN dp.sample_mean > v_ucl OR dp.sample_mean < v_lcl THEN 'RULE_1_BEYOND_3SIGMA'
                    ELSE NULL
                END AS rule
            ) sub WHERE rule IS NOT NULL
        ),
        pattern_detected = CASE
            WHEN dp.sample_mean > v_ucl OR dp.sample_mean < v_lcl THEN 'SHIFT'
            ELSE NULL
        END
    WHERE dp.spc_chart_id = p_spc_chart_id
        AND (dp.sample_mean > v_ucl OR dp.sample_mean < v_lcl);

    SELECT COUNT(*), COUNT(*) FILTER (WHERE is_out_of_control = 'Y')
    INTO v_total, v_ooc
    FROM qc.qc_spc_data_points
    WHERE spc_chart_id = p_spc_chart_id;

    SELECT AVG(sample_mean), STDDEV_POP(sample_mean)
    INTO v_mean, v_std
    FROM qc.qc_spc_data_points
    WHERE spc_chart_id = p_spc_chart_id;

    IF v_std > 0 AND v_usl IS NOT NULL AND v_lsl IS NOT NULL THEN
        v_cp := (v_usl - v_lsl) / (6 * v_std);
        v_cpk := LEAST((v_usl - v_mean) / (3 * v_std), (v_mean - v_lsl) / (3 * v_std));
    END IF;

    UPDATE qc.qc_spc_charts
    SET sigma_estimate = v_std,
        cp_value = v_cp,
        cpk_value = v_cpk,
        last_update_date = CURRENT_TIMESTAMP,
        last_updated_by = p_created_by
    WHERE spc_chart_id = p_spc_chart_id;

    IF v_ooc > 0 THEN
        INSERT INTO qc.qc_spc_alerts (spc_chart_id, alert_type_code, alert_severity_code, alert_status_code, rule_violated, description, created_by)
        VALUES (p_spc_chart_id, 'OOC', 'HIGH', 'NEW', 'RULE_1_BEYOND_3SIGMA',
            v_ooc || ' subgroups out of control detected on chart ' || p_spc_chart_id, p_created_by);
    END IF;

    RETURN QUERY SELECT v_total, v_ooc, v_cp, v_cpk;
END;
$$;


--
-- Name: calculate_tax(uuid, numeric, date); Type: FUNCTION; Schema: tax; Owner: -
--

CREATE FUNCTION tax.calculate_tax(p_tax_rate_id uuid, p_base_amount numeric, p_tax_date date) RETURNS TABLE(tax_code character varying, tax_rate_pct numeric, calculated_tax numeric, recovery_pct numeric, recoverable_amount numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_rate RECORD;
BEGIN
    SELECT r.tax_code, r.tax_rate_pct, r.recovery_rate_pct
    INTO v_rate
    FROM tax.tax_rates r
    WHERE r.tax_rate_id = p_tax_rate_id
      AND r.effective_from <= p_tax_date
      AND (r.effective_to IS NULL OR r.effective_to >= p_tax_date)
      AND r.is_active = TRUE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Tax rate % not active or not found on %', p_tax_rate_id, p_tax_date;
    END IF;

    RETURN QUERY SELECT
        v_rate.tax_code,
        v_rate.tax_rate_pct,
        ROUND(p_base_amount * v_rate.tax_rate_pct / 100, 2),
        v_rate.recovery_rate_pct,
        ROUND(p_base_amount * v_rate.tax_rate_pct / 100 * v_rate.recovery_rate_pct / 100, 2);
END;
$$;


--
-- Name: determine_tax(character varying, uuid, uuid, uuid, numeric, date, character varying, character varying, character varying); Type: FUNCTION; Schema: tax; Owner: -
--

CREATE FUNCTION tax.determine_tax(p_source_module character varying, p_source_doc_id uuid, p_partner_id uuid, p_product_id uuid, p_base_amount numeric, p_transaction_date date, p_ship_to_country character varying, p_ship_from_country character varying, p_transaction_type character varying DEFAULT 'SALES_ORDER'::character varying) RETURNS TABLE(tax_transaction_id uuid, doc_number character varying, tax_regime_code character varying, tax_type_code character varying, tax_code character varying, tax_rate_pct numeric, tax_amount numeric, recoverable_amount numeric, status character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_regime_id          UUID;
    v_type_id            UUID;
    v_rate_id            UUID;
    v_jurisdiction_id    UUID;
    v_tax_regime         RECORD;
    v_tax_type           RECORD;
    v_tax_rate           RECORD;
    v_doc_number         VARCHAR(50);
    v_period             VARCHAR(7);
    v_tax_amount         NUMERIC(18,2);
    v_recoverable        NUMERIC(18,2);
    v_tx_id              UUID;
    v_exemption_found    BOOLEAN;
BEGIN
    -- Step 1: Determine place of supply → jurisdiction
    SELECT tax_jurisdiction_id INTO v_jurisdiction_id
    FROM tax.tax_jurisdictions
    WHERE country_code = p_ship_to_country AND jurisdiction_type = 'NATIONAL'
    LIMIT 1;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'No jurisdiction found for country: %', p_ship_to_country;
    END IF;

    -- Step 2: Identify tax regime
    SELECT r.* INTO v_tax_regime
    FROM tax.tax_regimes r
    WHERE r.country_code = p_ship_to_country AND r.is_active = TRUE
    LIMIT 1;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'No active tax regime for country: %', p_ship_to_country;
    END IF;
    v_regime_id := v_tax_regime.tax_regime_id;

    -- Step 3: Identify tax type
    SELECT t.* INTO v_tax_type
    FROM tax.tax_types t
    WHERE t.tax_regime_id = v_regime_id AND t.is_active = TRUE
    LIMIT 1;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'No active tax type for regime: %', v_tax_regime.tax_regime_code;
    END IF;
    v_type_id := v_tax_type.tax_type_id;

    -- Step 4: Check exemptions
    SELECT EXISTS (
        SELECT 1 FROM tax.tax_exemptions e
        JOIN tax.tax_exemption_jurisdictions ej ON ej.exemption_id = e.exemption_id
        WHERE ej.tax_jurisdiction_id = v_jurisdiction_id
          AND e.effective_from <= p_transaction_date
          AND (e.effective_to IS NULL OR e.effective_to >= p_transaction_date)
          AND e.is_active = TRUE
    ) INTO v_exemption_found;

    -- Step 5: Look up tax rate
    IF v_exemption_found THEN
        v_tax_amount := 0;
        v_recoverable := 0;
        v_tax_rate.tax_code := 'EXEMPT';
        v_tax_rate.tax_rate_pct := 0;
        v_tax_rate.tax_rate_id := NULL;
        v_tax_rate.recovery_rate_pct := 0;
    ELSE
        SELECT r.* INTO v_tax_rate
        FROM tax.tax_rates r
        WHERE r.tax_type_id = v_type_id
          AND (r.tax_jurisdiction_id IS NULL OR r.tax_jurisdiction_id = v_jurisdiction_id)
          AND r.effective_from <= p_transaction_date
          AND (r.effective_to IS NULL OR r.effective_to >= p_transaction_date)
          AND r.is_active = TRUE
        ORDER BY r.tax_jurisdiction_id NULLS LAST, r.priority ASC
        LIMIT 1;

        IF NOT FOUND THEN
            RAISE EXCEPTION 'No active tax rate for type: %, jurisdiction: %', v_tax_type.tax_type_code, p_ship_to_country;
        END IF;

        v_tax_amount := ROUND(p_base_amount * v_tax_rate.tax_rate_pct / 100, 2);
        v_recoverable := ROUND(v_tax_amount * v_tax_rate.recovery_rate_pct / 100, 2);
    END IF;

    -- Step 6: Generate doc number
    v_doc_number := 'TAX-' || UPPER(p_source_module) || '-' || TO_CHAR(p_transaction_date, 'YYYYMMDD') || '-' || SUBSTRING(gen_random_uuid()::TEXT, 1, 8);

    -- Step 7: Determine period
    v_period := TO_CHAR(p_transaction_date, 'YYYY-MM');

    -- Step 8: Create transaction
    INSERT INTO tax.tax_transactions (
        tax_transaction_id, source_module, source_doc_id, doc_number,
        tax_date, tax_period, base_amount, tax_amount,
        recoverable_tax_amount, non_recoverable_tax_amount,
        tax_rate_id, tax_regime_id, tax_jurisdiction_id,
        transaction_type, status
    ) VALUES (
        gen_random_uuid(), p_source_module, p_source_doc_id, v_doc_number,
        p_transaction_date, v_period, p_base_amount, v_tax_amount,
        v_recoverable, v_tax_amount - v_recoverable,
        v_tax_rate.tax_rate_id, v_regime_id, v_jurisdiction_id,
        p_transaction_type, 'CALCULATED'
    ) RETURNING tax_transaction_id INTO v_tx_id;

    -- Step 9: Create tax line
    INSERT INTO tax.tax_lines (
        tax_line_id, tax_transaction_id, line_sequence,
        taxable_amount, tax_amount, non_recoverable_amount,
        tax_rate_pct, tax_code_id, tax_jurisdiction_id
    ) VALUES (
        gen_random_uuid(), v_tx_id, 1,
        p_base_amount, v_tax_amount, v_tax_amount - v_recoverable,
        COALESCE(v_tax_rate.tax_rate_pct, 0),
        (SELECT tax_code_id FROM tax.tax_codes WHERE tax_code = v_tax_rate.tax_code LIMIT 1),
        v_jurisdiction_id
    );

    -- Return result
    RETURN QUERY
    SELECT tx.tax_transaction_id, tx.doc_number,
           rg.tax_regime_code,
           tt.tax_type_code,
           COALESCE(tr.tax_code, 'EXEMPT') AS tax_code,
           COALESCE(tr.tax_rate_pct, 0),
           tx.tax_amount,
           tx.recoverable_tax_amount,
           tx.status
    FROM tax.tax_transactions tx
    JOIN tax.tax_regimes rg ON rg.tax_regime_id = tx.tax_regime_id
    JOIN tax.tax_types tt ON tt.tax_type_id = v_type_id
    LEFT JOIN tax.tax_rates tr ON tr.tax_rate_id = tx.tax_rate_id
    WHERE tx.tax_transaction_id = v_tx_id;
END;
$$;


--
-- Name: get_compliance_calendar(date, date); Type: FUNCTION; Schema: tax; Owner: -
--

CREATE FUNCTION tax.get_compliance_calendar(p_from_date date, p_to_date date) RETURNS TABLE(due_date date, obligation_name character varying, jurisdiction character varying, status character varying)
    LANGUAGE sql
    AS $$
    SELECT c.due_date, o.obligation_name,
           jd.country_code AS jurisdiction,
           c.status
    FROM tax.tax_compliance_calendars c
    JOIN tax.tax_compliance_obligations o ON o.obligation_id = c.obligation_id
    LEFT JOIN tax.tax_jurisdictions jd ON jd.tax_jurisdiction_id = o.tax_jurisdiction_id
    WHERE c.due_date BETWEEN p_from_date AND p_to_date
    ORDER BY c.due_date;
$$;


--
-- Name: prepare_tax_return(uuid, character varying, character varying); Type: FUNCTION; Schema: tax; Owner: -
--

CREATE FUNCTION tax.prepare_tax_return(p_tax_regime_id uuid, p_tax_period character varying, p_return_type character varying DEFAULT 'REGULAR'::character varying) RETURNS TABLE(tax_return_id uuid, return_number character varying, period_name character varying, transaction_count bigint, total_base numeric, total_tax numeric, total_recoverable numeric, net_payable numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_return_id           UUID;
    v_count               BIGINT;
    v_base                NUMERIC(19,4);
    v_tax                 NUMERIC(19,4);
    v_recoverable         NUMERIC(19,4);
    v_return_number       VARCHAR(100);
    v_period_name         VARCHAR(50);
    v_period_id           UUID;
    v_due_date            DATE;
BEGIN
    -- Find period
    SELECT p.tax_period_id, p.period_name, p.due_date
    INTO v_period_id, v_period_name, v_due_date
    FROM tax.tax_periods p
    WHERE p.period_code = p_tax_period
    LIMIT 1;

    -- Aggregate data
    SELECT COUNT(*), SUM(base_amount), SUM(tax_amount), SUM(recoverable_tax_amount)
    INTO v_count, v_base, v_tax, v_recoverable
    FROM tax.tax_transactions
    WHERE tax_regime_id = p_tax_regime_id
      AND tax_period = p_tax_period
      AND status = 'UNREPORTED';

    v_return_number := 'RTN-' || UPPER(TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS'));

    -- Create return
    INSERT INTO tax.tax_returns (
        tax_return_id, tax_regime_id, tax_period_id,
        return_type, return_number, period_name,
        due_date, status,
        taxable_sales, taxable_purchases,
        output_tax, input_tax,
        net_tax_payable, net_tax_refundable
    ) VALUES (
        gen_random_uuid(), p_tax_regime_id, v_period_id,
        p_return_type, v_return_number, v_period_name,
        v_due_date, 'DRAFT',
        v_base, 0,
        v_tax, v_recoverable,
        GREATEST(v_tax - v_recoverable, 0),
        GREATEST(v_recoverable - v_tax, 0)
    ) RETURNING tax_return_id INTO v_return_id;

    -- Mark transactions as reported
    UPDATE tax.tax_transactions
    SET status = 'REPORTED', tax_return_id = v_return_id, updated_at = NOW()
    WHERE tax_regime_id = p_tax_regime_id
      AND tax_period = p_tax_period
      AND status = 'UNREPORTED';

    RETURN QUERY
    SELECT r.tax_return_id, r.return_number, r.period_name,
           v_count, v_base, v_tax, v_recoverable, r.net_tax_payable
    FROM tax.tax_returns r
    WHERE r.tax_return_id = v_return_id;
END;
$$;


