--
-- Name: soft_delete(text, uuid); Type: FUNCTION; Schema: tax; Owner: -
--

CREATE FUNCTION tax.soft_delete(table_name text, record_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $_$
BEGIN
    EXECUTE format('UPDATE tax.%I SET is_active = FALSE, updated_at = NOW() WHERE %I = $1',
                   table_name,
                   (SELECT column_name FROM information_schema.columns
                    WHERE table_schema = 'tax' AND table_name = table_name
                      AND column_name LIKE '%_id' AND column_name != 'update_by'
                    LIMIT 1))
    USING record_id;
END;
$_$;


