--
-- Name: v_ap_aging; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_ap_aging AS
 SELECT i.supplier_id AS partner_id,
    p.legal_name AS supplier_name,
    p.partner_code,
    i.currency_id AS currency_code,
    i.ap_invoice_id,
    i.invoice_number,
    i.invoice_date,
    i.invoice_due_date AS due_date,
    i.amount_total,
    i.amount_paid,
    (i.amount_total - COALESCE(i.amount_paid, (0)::numeric)) AS amount_due,
        CASE
            WHEN ((CURRENT_DATE - i.invoice_due_date) <= 0) THEN (i.amount_total - COALESCE(i.amount_paid, (0)::numeric))
            ELSE (0)::numeric
        END AS current_amount,
        CASE
            WHEN (((CURRENT_DATE - i.invoice_due_date) >= 1) AND ((CURRENT_DATE - i.invoice_due_date) <= 30)) THEN (i.amount_total - COALESCE(i.amount_paid, (0)::numeric))
            ELSE (0)::numeric
        END AS aged_1_30,
        CASE
            WHEN (((CURRENT_DATE - i.invoice_due_date) >= 31) AND ((CURRENT_DATE - i.invoice_due_date) <= 60)) THEN (i.amount_total - COALESCE(i.amount_paid, (0)::numeric))
            ELSE (0)::numeric
        END AS aged_31_60,
        CASE
            WHEN (((CURRENT_DATE - i.invoice_due_date) >= 61) AND ((CURRENT_DATE - i.invoice_due_date) <= 90)) THEN (i.amount_total - COALESCE(i.amount_paid, (0)::numeric))
            ELSE (0)::numeric
        END AS aged_61_90,
        CASE
            WHEN ((CURRENT_DATE - i.invoice_due_date) > 90) THEN (i.amount_total - COALESCE(i.amount_paid, (0)::numeric))
            ELSE (0)::numeric
        END AS aged_90_plus,
    i.invoice_status,
    i.is_paid
   FROM (ap.ap_invoices i
     LEFT JOIN core.partners p ON ((p.partner_id = i.supplier_id)))
  WHERE ((i.is_active = true) AND (i.is_paid = false))
  ORDER BY i.invoice_due_date;


--
-- Name: mv_ap_aging; Type: MATERIALIZED VIEW; Schema: ap; Owner: -
--

CREATE MATERIALIZED VIEW ap.mv_ap_aging AS
 SELECT partner_id,
    supplier_name,
    partner_code,
    currency_code,
    ap_invoice_id,
    invoice_number,
    invoice_date,
    due_date,
    amount_total,
    amount_paid,
    amount_due,
    current_amount,
    aged_1_30,
    aged_31_60,
    aged_61_90,
    aged_90_plus,
    invoice_status,
    is_paid
   FROM ap.v_ap_aging
  WITH NO DATA;


