--
-- Name: v_ai_orchestration_status; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_ai_orchestration_status AS
 SELECT s.state_id,
    s.doc_id,
    s.doc_type,
    s.workflow_def_id,
    wd.workflow_name,
    s.thread_id,
    s.status AS workflow_status,
    s.checkpoint,
    s.created_at,
    s.updated_at,
    (count(l.log_id))::integer AS agent_call_count,
    max(l.created_at) AS last_agent_activity
   FROM ((ap.ai_workflow_state s
     LEFT JOIN ap.workflow_definitions wd ON ((wd.workflow_def_id = s.workflow_def_id)))
     LEFT JOIN ap.ai_agent_logs l ON ((l.state_id = s.state_id)))
  WHERE (s.is_active = true)
  GROUP BY s.state_id, s.doc_id, s.doc_type, s.workflow_def_id, wd.workflow_name, s.thread_id, s.status, s.checkpoint, s.created_at, s.updated_at
  ORDER BY s.created_at DESC;


--
-- Name: v_ap_aging_summary; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_ap_aging_summary AS
 SELECT partner_id,
    supplier_name,
    partner_code,
    (count(*))::integer AS invoice_count,
    (sum(current_amount))::numeric(19,2) AS total_current,
    (sum(aged_1_30))::numeric(19,2) AS total_1_30,
    (sum(aged_31_60))::numeric(19,2) AS total_31_60,
    (sum(aged_61_90))::numeric(19,2) AS total_61_90,
    (sum(aged_90_plus))::numeric(19,2) AS total_90_plus,
    (sum(amount_due))::numeric(19,2) AS total_due
   FROM ap.v_ap_aging
  GROUP BY partner_id, supplier_name, partner_code
  ORDER BY ((sum(amount_due))::numeric(19,2)) DESC;


