    NULL::character varying(30) AS payment_method,
    NULL::text AS description,
    NULL::numeric(18,2) AS amount_untaxed,
    NULL::numeric(18,2) AS amount_tax,
    NULL::numeric(18,2) AS amount_total,
    NULL::numeric(18,2) AS amount_paid,
    NULL::numeric(18,2) AS amount_residual,
    NULL::uuid AS tax_id,
    NULL::uuid AS account_payable_id,
    NULL::character varying(100) AS payment_reference,
    NULL::character varying(100) AS partner_ref,
    NULL::boolean AS is_paid,
    NULL::text AS notes,
    NULL::boolean AS is_active,
    NULL::timestamp with time zone AS created_at,
    NULL::timestamp with time zone AS updated_at,
    NULL::uuid AS update_by,
    NULL::integer AS line_count,
    NULL::numeric(18,2) AS lines_total;


--
-- Name: v_cash_flow_projection; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_cash_flow_projection AS
 SELECT i.ap_invoice_id,
    i.invoice_number,
    i.supplier_id AS partner_id,
    p.legal_name AS supplier_name,
    i.invoice_due_date AS due_date,
    (i.amount_total - COALESCE(i.amount_paid, (0)::numeric)) AS amount_due,
    i.currency_id AS currency_code,
    i.invoice_status,
        CASE
            WHEN (i.invoice_due_date <= CURRENT_DATE) THEN 'OVERDUE'::text
            WHEN (i.invoice_due_date <= (CURRENT_DATE + 7)) THEN 'DUE_SOON'::text
            ELSE 'FUTURE'::text
        END AS payment_urgency,
    d.discount_amount,
    d.discount_date
   FROM ((ap.ap_invoices i
     LEFT JOIN core.partners p ON ((p.partner_id = i.supplier_id)))
     LEFT JOIN ap.discount_tracking d ON ((d.invoice_id = i.ap_invoice_id)))
  WHERE ((i.is_active = true) AND (i.is_paid = false))
  ORDER BY i.invoice_due_date;


--
-- Name: v_invoice_approval_pending; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_invoice_approval_pending AS
 SELECT i.ap_invoice_id,
    i.invoice_number,
    i.invoice_date,
    i.amount_total,
    i.currency_id AS currency_code,
    i.invoice_status,
    p.legal_name AS supplier_name,
    p.partner_code,
    h.hold_id,
    h.hold_type,
    h.hold_reason,
    h.created_at AS hold_date
   FROM ((ap.ap_invoices i
     JOIN ap.invoice_holds h ON (((h.invoice_id = i.ap_invoice_id) AND ((h.status)::text = 'ACTIVE'::text))))
     LEFT JOIN core.partners p ON ((p.partner_id = i.supplier_id)))
  WHERE (i.is_active = true)
  ORDER BY h.created_at DESC;


--
-- Name: v_payment_batch_summary; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_payment_batch_summary AS
 SELECT b.batch_id,
    b.batch_number,
    b.batch_date,
    b.status,
    b.total_amount,
    b.payment_count,
    m.method_name,
    ba.account_name,
    ba.account_number,
    count(p.payment_id) AS processed_count,
    (COALESCE(sum(
        CASE
            WHEN ((p.status)::text = 'COMPLETED'::text) THEN p.amount
            ELSE (0)::numeric
        END), (0)::numeric))::numeric(19,2) AS completed_amount
   FROM (((ap.payment_batches b
     LEFT JOIN ap.payment_methods m ON ((m.method_id = b.method_id)))
     LEFT JOIN ap.bank_accounts ba ON ((ba.bank_account_id = b.bank_account_id)))
     LEFT JOIN ap.payment_instructions p ON ((p.batch_id = b.batch_id)))
  GROUP BY b.batch_id, b.batch_number, b.batch_date, b.status, b.total_amount, b.payment_count, m.method_name, ba.account_name, ba.account_number
  ORDER BY b.batch_date DESC;


--
-- Name: v_supplier_payment_summary; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_supplier_payment_summary AS
 SELECT p.partner_id,
    p.legal_name AS supplier_name,
    p.partner_code,
    (count(DISTINCT i.ap_invoice_id))::integer AS invoice_count,
    (count(DISTINCT pi.payment_id))::integer AS payment_count,
    (COALESCE(sum(i.amount_total), (0)::numeric))::numeric(19,2) AS total_invoiced,
    (COALESCE(sum(pi.amount), (0)::numeric))::numeric(19,2) AS total_paid,
    (COALESCE(sum((i.amount_total - i.amount_paid)), (0)::numeric))::numeric(19,2) AS balance_due
   FROM ((core.partners p
     LEFT JOIN ap.ap_invoices i ON (((i.supplier_id = p.partner_id) AND (i.is_active = true))))
     LEFT JOIN ap.payment_instructions pi ON (((pi.partner_id = p.partner_id) AND (pi.is_active = true))))
  GROUP BY p.partner_id, p.legal_name, p.partner_code
  ORDER BY ((COALESCE(sum((i.amount_total - i.amount_paid)), (0)::numeric))::numeric(19,2)) DESC;


--
-- Name: v_tax_summary; Type: VIEW; Schema: ap; Owner: -
--

CREATE VIEW ap.v_tax_summary AS
 SELECT currency_id AS currency_code,
    (date_trunc('month'::text, (invoice_date)::timestamp with time zone))::date AS period_start,
    (count(*))::integer AS invoice_count,
    (COALESCE(sum(amount_untaxed), (0)::numeric))::numeric(19,2) AS total_untaxed,
    (COALESCE(sum(amount_tax), (0)::numeric))::numeric(19,2) AS total_tax,
    (COALESCE(sum(amount_total), (0)::numeric))::numeric(19,2) AS total_amount
   FROM ap.ap_invoices i
  WHERE (is_active = true)
  GROUP BY currency_id, (date_trunc('month'::text, (invoice_date)::timestamp with time zone))
  ORDER BY ((date_trunc('month'::text, (invoice_date)::timestamp with time zone))::date) DESC;


