    gl_date date,
    due_date date,
    terms_id uuid,
    exchange_rate_type character varying(30),
    exchange_rate numeric(18,8),
    exchange_date date,
    currency_code character varying(3) DEFAULT 'USD'::character varying NOT NULL,
    total_lines_amount numeric(18,2) DEFAULT 0,
    total_tax_amount numeric(18,2) DEFAULT 0,
    total_freight_amount numeric(18,2) DEFAULT 0,
    total_charges_amount numeric(18,2) DEFAULT 0,
    total_discount_amount numeric(18,2) DEFAULT 0,
    total_amount numeric(18,2) GENERATED ALWAYS AS (((((COALESCE(total_lines_amount, (0)::numeric) + COALESCE(total_tax_amount, (0)::numeric)) + COALESCE(total_freight_amount, (0)::numeric)) + COALESCE(total_charges_amount, (0)::numeric)) - COALESCE(total_discount_amount, (0)::numeric))) STORED,
    amount_due numeric(18,2) DEFAULT 0 NOT NULL,
    amount_applied numeric(18,2) DEFAULT 0,
    amount_credited numeric(18,2) DEFAULT 0,
    amount_adjusted numeric(18,2) DEFAULT 0,
    salesperson_id uuid,
    collector_id uuid,
    description text,
    comments text,
    reference_number character varying(50),
    batch_source_id uuid,
    is_paid boolean DEFAULT false,
    paid_date date,
    payment_method character varying(30),
    attribute_category character varying(150),
    attribute1 character varying(150),
    attribute2 character varying(150),
    attribute3 character varying(150),
    attribute4 character varying(150),
    attribute5 character varying(150),
    attribute6 character varying(150),
    attribute7 character varying(150),
    attribute8 character varying(150),
    attribute9 character varying(150),
    attribute10 character varying(150),
    attribute11 character varying(150),
    attribute12 character varying(150),
    attribute13 character varying(150),
    attribute14 character varying(150),
    attribute15 character varying(150),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    corporate_id uuid,
    site_id uuid
);

