--
-- Name: mv_ar_aging; Type: MATERIALIZED VIEW; Schema: ar; Owner: -
--

CREATE MATERIALIZED VIEW ar.mv_ar_aging AS
 SELECT ar_invoice_id,
    invoice_number,
    invoice_type,
    invoice_date,
    due_date,
    currency_code,
    amount_due,
    amount_applied,
    amount_credited,
    amount_adjusted,
    is_paid,
    customer_id,
    customer_site_id,
    collector_id,
    (CURRENT_DATE - due_date) AS days_overdue,
        CASE
            WHEN (is_paid = true) THEN 'PAID'::text
            WHEN (due_date IS NULL) THEN 'NOT_DUE'::text
            WHEN ((CURRENT_DATE - due_date) <= 0) THEN 'CURRENT'::text
            WHEN ((CURRENT_DATE - due_date) <= 30) THEN '1_30_DAYS'::text
            WHEN ((CURRENT_DATE - due_date) <= 60) THEN '31_60_DAYS'::text
            WHEN ((CURRENT_DATE - due_date) <= 90) THEN '61_90_DAYS'::text
            WHEN ((CURRENT_DATE - due_date) <= 120) THEN '91_120_DAYS'::text
            ELSE '120_PLUS_DAYS'::text
        END AS aging_bucket,
    (((amount_due - amount_applied) - amount_credited) - amount_adjusted) AS outstanding
   FROM ar.ar_invoices inv
  WHERE ((is_paid = false) AND ((invoice_status)::text = 'ACTIVE'::text))
  WITH NO DATA;


