--
-- Name: v_ar_invoice_with_lines; Type: VIEW; Schema: ar; Owner: -
--

CREATE VIEW ar.v_ar_invoice_with_lines AS
 SELECT inv.ar_invoice_id,
    inv.invoice_number,
    inv.invoice_type,
    inv.invoice_status,
    inv.invoice_class,
    inv.invoice_date,
    inv.gl_date,
    inv.due_date,
    inv.currency_code,
    inv.total_lines_amount,
    inv.total_tax_amount,
    inv.total_freight_amount,
    inv.total_charges_amount,
    inv.total_discount_amount,
    inv.total_amount,
    inv.amount_due,
    inv.amount_applied,
    inv.amount_credited,
    inv.amount_adjusted,
    inv.is_paid,
    inv.paid_date,
    inv.description,
    inv.reference_number,
    inv.customer_id,
    inv.customer_site_id,
    inv.so_id,
    inv.salesperson_id,
    inv.collector_id,
    inv.created_at,
    il.ar_invoice_line_id,
    il.line_number,
    il.line_type,
    il.item_id,
    il.item_description,
    il.uom_code,
    i.item_number,
    il.qty,
    il.unit_price,
    il.unit_list_price,
    il.discount_percent,
    il.discount_amount,
    il.line_total,
    il.net_amount,
    il.tax_code_id,
    il.tax_amount,
    il.tax_exempt_flag,
    il.so_line_id,
    il.revenue_account_id,
    il.receivable_account_id,
    c.account_number AS customer_number,
    p.legal_name AS customer_name
   FROM ((((ar.ar_invoices inv
     LEFT JOIN ar.ar_invoice_lines il ON ((il.ar_invoice_id = inv.ar_invoice_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = il.item_id)))
     LEFT JOIN ar.ar_customers c ON ((c.cust_account_id = inv.customer_id)))
     LEFT JOIN core.partners p ON ((p.partner_id = c.partner_id)));


