CREATE VIEW core.v_event_log AS
 SELECT event_id,
    aggregate_id,
    aggregate_type,
    event_type,
    event_version,
    (payload ->> 'action'::text) AS action_summary,
    (metadata ->> 'user'::text) AS actor,
    "timestamp"
   FROM core.event_store e
  ORDER BY "timestamp" DESC;


