    longitude numeric(10,7)
);


--
-- Name: v_location_utilization; Type: VIEW; Schema: core; Owner: -
--

CREATE VIEW core.v_location_utilization AS
 SELECT w.warehouse_id,
    w.warehouse_code,
    w.warehouse_name,
    count(l.location_id) AS total_locations,
    count(l.location_id) FILTER (WHERE (l.is_active = true)) AS active_locations
   FROM (core.warehouses w
     LEFT JOIN core.locations l ON ((l.warehouse_id = w.warehouse_id)))
  GROUP BY w.warehouse_id, w.warehouse_code, w.warehouse_name;


--
-- Name: v_partners_full; Type: VIEW; Schema: core; Owner: -
--

CREATE VIEW core.v_partners_full AS
 SELECT p.partner_id,
    p.partner_code,
    p.legal_name,
    p.trade_name,
    p.party_type,
    p.party_status,
    p.tax_reference,
    p.registration_number,
    p.duns_number,
    p.country_code,
    p.is_active,
    ps.partner_site_id,
    ps.partner_site_name,
    ps.partner_site_number,
    a.address_id,
    a.address_line1,
    a.address_line2,
    a.city,
    a.state,
    a.province,
    a.country,
    a.postal_code
   FROM ((core.partners p
     LEFT JOIN core.partner_sites ps ON (((ps.partner_id = p.partner_id) AND (ps.is_active = true))))
     LEFT JOIN core.addresses a ON ((a.address_id = ps.address_id)));


--
-- Name: v_warehouse_hierarchy; Type: VIEW; Schema: core; Owner: -
--

CREATE VIEW core.v_warehouse_hierarchy AS
 SELECT s.site_id,
    s.site_code,
    s.site_name,
    s.site_type,
    w.warehouse_id,
    w.warehouse_code,
    w.warehouse_name,
    l.location_id,
    l.location_code,
    l.zone_name
   FROM ((core.sites s
     LEFT JOIN core.warehouses w ON ((w.site_id = s.site_id)))
     LEFT JOIN core.locations l ON ((l.warehouse_id = w.warehouse_id)));


