--

CREATE TABLE eam.eam_budgets (
    budget_id bigint NOT NULL,
    budget_year integer NOT NULL,
    budget_code character varying(100) NOT NULL,
    budget_name character varying(360) NOT NULL,
    description text,
    budget_category_code character varying(50) NOT NULL,
    asset_id bigint,
    functional_location_id bigint,
    planned_amount numeric(19,4) NOT NULL,
    actual_amount numeric(19,4) DEFAULT 0,
    committed_amount numeric(19,4) DEFAULT 0,
    variance_amount numeric(19,4) GENERATED ALWAYS AS ((planned_amount - actual_amount)) STORED,
    variance_pct numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (planned_amount > (0)::numeric) THEN ((((planned_amount - actual_amount) / planned_amount) * (100)::numeric))::numeric(5,2)
    ELSE (0)::numeric
END) STORED,
    currency_code character varying(15),
    budget_status_code character varying(50) DEFAULT 'ACTIVE'::character varying,
    fiscal_period character varying(30),
    approval_required boolean DEFAULT true,
    approved_by character varying(100),
    approved_date timestamp without time zone,
    creation_date timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    created_by character varying(100),
    last_update_date timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    last_updated_by character varying(100),
    object_version_number integer DEFAULT 1,
    is_active character varying(1) DEFAULT 'Y'::character varying,
    tenant_id character varying(50),
    organization_id bigint,
    site_id bigint,
    corporate_id uuid,
    company_id uuid
);


