--
-- Name: v_asset_criticality_matrix; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_asset_criticality_matrix AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    at.asset_type_name,
    a.criticality_code,
    ac.impact_level,
    ac.safety_impact,
    ac.environmental_impact,
    ac.operational_impact,
    ac.financial_impact,
    a.condition_code,
    a.asset_status_code,
    a.replacement_value,
    a.acquisition_cost,
    ( SELECT count(*) AS count
           FROM eam.eam_work_orders wo
          WHERE ((wo.asset_id = a.asset_id) AND ((wo.work_order_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[])))) AS open_work_orders,
    ( SELECT count(*) AS count
           FROM eam.eam_failure_history fh
          WHERE ((fh.asset_id = a.asset_id) AND (fh.failure_date >= (CURRENT_DATE - '365 days'::interval)))) AS failures_last_year,
    ( SELECT COALESCE(sum(mc.cost_amount), (0)::numeric) AS "coalesce"
           FROM eam.eam_maintenance_costs mc
          WHERE ((mc.asset_id = a.asset_id) AND (mc.cost_date >= (CURRENT_DATE - '365 days'::interval)))) AS maintenance_cost_ytd,
    a.last_update_date
   FROM ((eam.eam_assets a
     JOIN eam.eam_asset_types at ON ((at.asset_type_id = a.asset_type_id)))
     LEFT JOIN eam.eam_asset_criticality ac ON (((ac.criticality_code)::text = (a.criticality_code)::text)));


--
-- Name: v_asset_hierarchy; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_asset_hierarchy AS
 WITH RECURSIVE asset_tree AS (
         SELECT a.asset_id,
            a.asset_number,
            a.asset_name,
            a.asset_type_id,
            a.asset_class_code,
            a.criticality_code,
            a.asset_status_code,
            a.condition_code,
            0 AS hierarchy_level,
            (a.asset_number)::character varying(500) AS hierarchy_path,
            (a.asset_name)::character varying(500) AS hierarchy_name_path
           FROM eam.eam_assets a
          WHERE (NOT (EXISTS ( SELECT 1
                   FROM eam.eam_asset_hierarchy ah
                  WHERE (ah.child_asset_id = a.asset_id))))
        UNION ALL
         SELECT a.asset_id,
            a.asset_number,
            a.asset_name,
            a.asset_type_id,
            a.asset_class_code,
            a.criticality_code,
            a.asset_status_code,
            a.condition_code,
            (pt.hierarchy_level + 1),
            ((((pt.hierarchy_path)::text || ' -> '::text) || (a.asset_number)::text))::character varying(500) AS "varchar",
            ((((pt.hierarchy_name_path)::text || ' -> '::text) || (a.asset_name)::text))::character varying(500) AS "varchar"
           FROM ((eam.eam_assets a
             JOIN eam.eam_asset_hierarchy ah ON ((ah.child_asset_id = a.asset_id)))
             JOIN asset_tree pt ON ((pt.asset_id = ah.parent_asset_id)))
        )
 SELECT asset_id,
    asset_number,
    asset_name,
    asset_type_id,
    asset_class_code,
    criticality_code,
    asset_status_code,
    condition_code,
    hierarchy_level,
    hierarchy_path,
    hierarchy_name_path
   FROM asset_tree
  ORDER BY hierarchy_path;


--
-- Name: v_asset_lifecycle; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_asset_lifecycle AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    at.asset_type_name,
    a.asset_status_code,
    a.condition_code,
    a.criticality_code,
    a.manufacture_date,
    a.commission_date,
    a.in_service_date,
    (CURRENT_DATE - a.in_service_date) AS days_in_service,
    a.warranty_end_date,
    a.acquisition_cost,
    a.replacement_value,
    a.book_value,
    a.salvage_value,
    a.depreciation_method,
    a.useful_life_months,
        CASE
            WHEN ((a.useful_life_months > 0) AND (a.in_service_date IS NOT NULL)) THEN round(((((EXTRACT(year FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone)) * (12)::numeric) + EXTRACT(month FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone))) / (a.useful_life_months)::numeric) * (100)::numeric), 1)
            ELSE NULL::numeric
        END AS lifecycle_pct,
        CASE
            WHEN ((a.useful_life_months IS NOT NULL) AND (((EXTRACT(year FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone)) * (12)::numeric) + EXTRACT(month FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone))) >= (a.useful_life_months)::numeric)) THEN 'END_OF_LIFE'::text
            WHEN ((a.useful_life_months IS NOT NULL) AND (((EXTRACT(year FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone)) * (12)::numeric) + EXTRACT(month FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone))) >= ((a.useful_life_months)::numeric * 0.8))) THEN 'NEARING_END_OF_LIFE'::text
            WHEN ((a.useful_life_months IS NOT NULL) AND (((EXTRACT(year FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone)) * (12)::numeric) + EXTRACT(month FROM age((CURRENT_DATE)::timestamp with time zone, (a.in_service_date)::timestamp with time zone))) >= ((a.useful_life_months)::numeric * 0.5))) THEN 'MATURE'::text
            ELSE 'EARLY_LIFE'::text
        END AS lifecycle_stage,
    ( SELECT count(*) AS count
           FROM eam.eam_decommission_plans dp
          WHERE ((dp.asset_id = a.asset_id) AND ((dp.plan_status_code)::text = 'COMPLETED'::text))) AS decommissioned
   FROM (eam.eam_assets a
     LEFT JOIN eam.eam_asset_types at ON ((at.asset_type_id = a.asset_type_id)));


--
-- Name: v_asset_summary; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_asset_summary AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    a.description,
    at.asset_type_name,
    a.asset_class_code,
    a.criticality_code,
    a.asset_status_code,
    a.condition_code,
    a.serial_number,
    a.manufacturer_name,
    a.model_number,
    a.commission_date,
    a.warranty_end_date,
    a.acquisition_cost,
    a.replacement_value,
    a.book_value,
    a.ownership_code,
    fl.location_code AS functional_location_code,
    fl.location_name AS functional_location_name,
    pl.location_code AS physical_location_code,
    pl.location_name AS physical_location_name,
    ( SELECT count(*) AS count
           FROM eam.eam_work_orders wo
          WHERE ((wo.asset_id = a.asset_id) AND ((wo.work_order_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[])))) AS open_work_orders,
    ( SELECT count(*) AS count
           FROM eam.eam_pm_schedules ps
          WHERE ((ps.asset_id = a.asset_id) AND ((ps.schedule_status_code)::text = 'PENDING'::text) AND (ps.due_date <= CURRENT_TIMESTAMP))) AS overdue_pm_count,
    ( SELECT max(pdm.health_score) AS max
           FROM eam.eam_predictive_maintenance pdm
          WHERE ((pdm.asset_id = a.asset_id) AND ((pdm.pdm_status_code)::text = 'ACTIVE'::text))) AS current_health_score,
    ( SELECT max(pdm.rul_days) AS max
           FROM eam.eam_predictive_maintenance pdm
          WHERE ((pdm.asset_id = a.asset_id) AND ((pdm.pdm_status_code)::text = 'ACTIVE'::text))) AS remaining_useful_life_days,
    a.creation_date,
    a.last_update_date,
    a.tenant_id,
    a.organization_id,
    a.site_id
   FROM (((eam.eam_assets a
     LEFT JOIN eam.eam_asset_types at ON ((at.asset_type_id = a.asset_type_id)))
     LEFT JOIN eam.eam_functional_locations fl ON ((fl.functional_location_id = a.functional_location_id)))
     LEFT JOIN eam.eam_physical_locations pl ON ((pl.physical_location_id = a.physical_location_id)));


--
-- Name: v_budget_vs_actual; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_budget_vs_actual AS
 SELECT b.budget_id,
    b.budget_year,
    b.budget_code,
    b.budget_name,
    b.budget_category_code,
    a.asset_number,
    a.asset_name,
    b.planned_amount,
    b.actual_amount,
    b.committed_amount,
    b.variance_amount,
    b.variance_pct,
        CASE
            WHEN (b.variance_pct < ('-10'::integer)::numeric) THEN 'OVER_BUDGET'::text
            WHEN ((b.variance_pct >= ('-10'::integer)::numeric) AND (b.variance_pct <= (10)::numeric)) THEN 'ON_TRACK'::text
            WHEN (b.variance_pct > (10)::numeric) THEN 'UNDER_BUDGET'::text
            ELSE NULL::text
        END AS budget_status,
    b.budget_status_code,
    b.fiscal_period
   FROM (eam.eam_budgets b
     LEFT JOIN eam.eam_assets a ON ((a.asset_id = b.asset_id)));


--
-- Name: v_calibration_status; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_calibration_status AS
 SELECT cr.cal_req_id,
    cr.calibration_code,
    cr.calibration_name,
    cr.calibration_type_code,
    cr.frequency_days,
    cr.standard_reference,
    a.asset_number,
    a.asset_name,
    t.tool_code,
    t.tool_name,
    cr_result.calibration_date AS last_calibration_date,
    cr_result.next_due_date,
    cr_result.result_code AS last_result,
        CASE
            WHEN (cr_result.next_due_date IS NULL) THEN 'NOT_CALIBRATED'::text
            WHEN (cr_result.next_due_date < CURRENT_DATE) THEN 'OVERDUE'::text
            WHEN (cr_result.next_due_date <= (CURRENT_DATE + '30 days'::interval)) THEN 'DUE_SOON'::text
            ELSE 'CURRENT'::text
        END AS calibration_status,
    (cr_result.next_due_date - CURRENT_DATE) AS days_until_due
   FROM (((eam.eam_calibration_requirements cr
     LEFT JOIN eam.eam_assets a ON ((a.asset_id = cr.asset_id)))
     LEFT JOIN eam.eam_tools t ON ((t.tool_id = cr.tool_id)))
     LEFT JOIN LATERAL ( SELECT cr2.calibration_date,
            cr2.next_due_date,
            cr2.result_code
           FROM eam.eam_calibration_results cr2
          WHERE (cr2.cal_req_id = cr.cal_req_id)
          ORDER BY cr2.calibration_date DESC
         LIMIT 1) cr_result ON (true));


--
-- Name: v_failure_pareto; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_failure_pareto AS
 SELECT fc.failure_code,
    fc.failure_name,
    fc.failure_type_code,
    at.asset_type_name,
    count(fh.failure_history_id) AS failure_count,
    COALESCE(sum(fh.downtime_hours), (0)::numeric) AS total_downtime_hours,
    COALESCE(sum(fh.total_cost), (0)::numeric) AS total_cost,
    row_number() OVER (ORDER BY (count(fh.failure_history_id)) DESC) AS rank,
    round((((count(fh.failure_history_id))::numeric * 100.0) / sum(count(fh.failure_history_id)) OVER ()), 2) AS pct_of_total,
    round(((sum(count(fh.failure_history_id)) OVER (ORDER BY (count(fh.failure_history_id)) DESC) * 100.0) / sum(count(fh.failure_history_id)) OVER ()), 2) AS cumulative_pct
   FROM ((eam.eam_failure_codes fc
     JOIN eam.eam_failure_history fh ON ((fh.failure_code_id = fc.failure_code_id)))
     LEFT JOIN eam.eam_asset_types at ON ((at.asset_type_id = fc.asset_type_id)))
  WHERE (fh.failure_date >= (CURRENT_DATE - '365 days'::interval))
  GROUP BY fc.failure_code, fc.failure_name, fc.failure_type_code, at.asset_type_name
  ORDER BY (count(fh.failure_history_id)) DESC;


--
-- Name: v_inspection_status; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_inspection_status AS
 SELECT i.inspection_id,
    i.inspection_number,
    i.inspection_name,
    i.inspection_type_code,
    a.asset_number,
    a.asset_name,
    a.criticality_code,
    i.last_inspection_date,
    i.next_inspection_date,
    i.result_code AS last_result,
    i.inspection_status_code,
        CASE
            WHEN (i.next_inspection_date IS NULL) THEN 'NOT_SCHEDULED'::text
            WHEN (i.next_inspection_date < CURRENT_DATE) THEN 'OVERDUE'::text
            WHEN (i.next_inspection_date <= (CURRENT_DATE + '30 days'::interval)) THEN 'DUE_SOON'::text
            ELSE 'CURRENT'::text
        END AS inspection_health,
    i.regulatory_body,
    i.certificate_number,
    i.certificate_expiry
   FROM (eam.eam_inspections i
     JOIN eam.eam_assets a ON ((a.asset_id = i.asset_id)));


--
-- Name: v_kpi_dashboard; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_kpi_dashboard AS
 SELECT kd.kpi_code,
    kd.kpi_name,
    kd.description,
    kd.formula,
    kd.unit_of_measure,
    kd.higher_is_better,
    kd.target_value,
    kd.benchmark_value,
    kv.actual_value,
    kv.period_start_date,
    kv.period_end_date,
    kv.status_code,
    kv.variance_pct,
        CASE
            WHEN ((kv.status_code)::text = 'CRITICAL'::text) THEN '🔴'::text
            WHEN ((kv.status_code)::text = 'WARNING'::text) THEN '🟡'::text
            WHEN ((kv.status_code)::text = 'ON_TARGET'::text) THEN '🟢'::text
            ELSE '⚪'::text
        END AS status_indicator,
    kv.asset_id,
    a.asset_number,
    a.asset_name
   FROM ((eam.eam_kpi_definitions kd
     LEFT JOIN eam.eam_kpi_values kv ON ((((kv.kpi_code)::text = (kd.kpi_code)::text) AND (kv.calculation_date = ( SELECT max(kv2.calculation_date) AS max
           FROM eam.eam_kpi_values kv2
          WHERE ((kv2.kpi_code)::text = (kd.kpi_code)::text))))))
     LEFT JOIN eam.eam_assets a ON ((a.asset_id = kv.asset_id)));


--
-- Name: v_maintenance_cost_summary; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_maintenance_cost_summary AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    at.asset_type_name,
    a.criticality_code,
    date_trunc('month'::text, (mc.cost_date)::timestamp with time zone) AS cost_month,
    mc.cost_category_code,
    sum(mc.cost_amount) AS total_cost,
    count(DISTINCT mc.work_order_id) AS work_order_count,
    count(DISTINCT mc.cost_id) AS transaction_count
   FROM ((eam.eam_maintenance_costs mc
     JOIN eam.eam_assets a ON ((a.asset_id = mc.asset_id)))
     LEFT JOIN eam.eam_asset_types at ON ((at.asset_type_id = a.asset_type_id)))
  GROUP BY a.asset_id, a.asset_number, a.asset_name, at.asset_type_name, a.criticality_code, (date_trunc('month'::text, (mc.cost_date)::timestamp with time zone)), mc.cost_category_code
  ORDER BY (date_trunc('month'::text, (mc.cost_date)::timestamp with time zone)) DESC, (sum(mc.cost_amount)) DESC;


--
-- Name: v_mtbf_mttr; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_mtbf_mttr AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    at.asset_type_name,
    a.criticality_code,
    count(fh.failure_history_id) AS total_failures,
    COALESCE(sum(fh.downtime_hours), (0)::numeric) AS total_downtime_hours,
    COALESCE(sum(fh.repair_hours), (0)::numeric) AS total_repair_hours,
        CASE
            WHEN (count(fh.failure_history_id) > 0) THEN round((((EXTRACT(epoch FROM (CURRENT_TIMESTAMP - (a.commission_date)::timestamp with time zone)) / (3600)::numeric) - COALESCE(sum(fh.downtime_hours), (0)::numeric)) / (count(fh.failure_history_id))::numeric), 2)
            ELSE NULL::numeric
        END AS mtbf_hours,
        CASE
            WHEN (count(fh.failure_history_id) > 0) THEN round((COALESCE(sum(fh.repair_hours), (0)::numeric) / (count(fh.failure_history_id))::numeric), 2)
            ELSE NULL::numeric
        END AS mttr_hours,
        CASE
            WHEN ((count(fh.failure_history_id) > 0) AND (COALESCE(sum(fh.repair_hours), (0)::numeric) > (0)::numeric)) THEN round((((EXTRACT(epoch FROM (CURRENT_TIMESTAMP - (a.commission_date)::timestamp with time zone)) / (3600)::numeric) - COALESCE(sum(fh.downtime_hours), (0)::numeric)) / COALESCE(sum(fh.repair_hours), (0)::numeric)), 2)
            ELSE NULL::numeric
        END AS mtbf_mttr_ratio,
    a.commission_date
   FROM ((eam.eam_assets a
     LEFT JOIN eam.eam_asset_types at ON ((at.asset_type_id = a.asset_type_id)))
     LEFT JOIN eam.eam_failure_history fh ON ((fh.asset_id = a.asset_id)))
  GROUP BY a.asset_id, a.asset_number, a.asset_name, at.asset_type_name, a.criticality_code, a.commission_date;


--
-- Name: v_pm_schedule_summary; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_pm_schedule_summary AS
 SELECT ps.pm_schedule_id,
    pt.template_code,
    pt.template_name,
    a.asset_number,
    a.asset_name,
    a.criticality_code,
    pt.frequency_value,
    pt.frequency_uom,
    ps.due_date,
    ps.earliest_date,
    ps.latest_date,
    ps.scheduled_date,
    ps.completed_date,
    ps.schedule_status_code,
        CASE
            WHEN ((ps.due_date < CURRENT_TIMESTAMP) AND ((ps.schedule_status_code)::text = 'PENDING'::text)) THEN 'OVERDUE'::text
            WHEN ((ps.due_date <= (CURRENT_TIMESTAMP + '7 days'::interval)) AND ((ps.schedule_status_code)::text = 'PENDING'::text)) THEN 'DUE_SOON'::text
            WHEN ((ps.due_date <= (CURRENT_TIMESTAMP + '30 days'::interval)) AND ((ps.schedule_status_code)::text = 'PENDING'::text)) THEN 'UPCOMING'::text
            WHEN ((ps.schedule_status_code)::text = 'COMPLETED'::text) THEN 'COMPLETED'::text
            ELSE 'FUTURE'::text
        END AS due_category,
    ps.work_order_id,
    wo.work_order_number,
    wo.work_order_status_code,
    ps.creation_date,
    ps.tenant_id
   FROM ((((eam.eam_pm_schedules ps
     JOIN eam.eam_pm_assignments pa ON ((pa.pm_assignment_id = ps.pm_assignment_id)))
     JOIN eam.eam_pm_templates pt ON ((pt.pm_template_id = ps.pm_template_id)))
     JOIN eam.eam_assets a ON ((a.asset_id = ps.asset_id)))
     LEFT JOIN eam.eam_work_orders wo ON ((wo.work_order_id = ps.work_order_id)));


--
-- Name: v_predictive_maintenance_alerts; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_predictive_maintenance_alerts AS
 SELECT pdm.pdm_id,
    a.asset_number,
    a.asset_name,
    a.criticality_code,
    pdm.health_score,
    pdm.rul_days,
    pdm.failure_probability,
    pdm.predicted_failure_mode,
    pdm.recommended_action,
    pdm.priority_code,
    pdm.pdm_status_code,
    pdm.evaluation_date,
    al.alert_id,
    al.title AS alert_title,
    al.severity_code AS alert_severity,
    al.alert_status_code,
        CASE
            WHEN ((pdm.health_score <= (30)::numeric) OR (pdm.rul_days <= (7)::numeric)) THEN 'CRITICAL'::text
            WHEN ((pdm.health_score <= (50)::numeric) OR (pdm.rul_days <= (30)::numeric)) THEN 'WARNING'::text
            WHEN ((pdm.health_score <= (70)::numeric) OR (pdm.rul_days <= (90)::numeric)) THEN 'CAUTION'::text
            ELSE 'NORMAL'::text
        END AS priority_level
   FROM ((eam.eam_predictive_maintenance pdm
     JOIN eam.eam_assets a ON ((a.asset_id = pdm.asset_id)))
     LEFT JOIN eam.eam_alerts al ON ((al.alert_id = pdm.alert_id)))
  WHERE ((pdm.pdm_status_code)::text = 'ACTIVE'::text)
  ORDER BY pdm.health_score, pdm.rul_days;


--
-- Name: v_spare_parts_availability; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_spare_parts_availability AS
 SELECT ab.item_id,
    ab.item_code,
    ab.item_name,
    ab.description,
    ab.unit_of_measure,
    ab.quantity_per_asset,
    ab.min_stock_level,
    ab.max_stock_level,
    ab.reorder_point,
    ab.safety_stock,
    ab.unit_cost,
    ab.lead_time_days,
    ab.critical_spare,
    ab.long_lead_item,
    COALESCE(wo_issued.issued_qty, (0)::numeric) AS onhand_quantity,
    (COALESCE(wo_issued.issued_qty, (0)::numeric) - COALESCE(wo_reserved.reserved_qty, (0)::numeric)) AS available_quantity,
        CASE
            WHEN (COALESCE(wo_issued.issued_qty, (0)::numeric) <= (0)::numeric) THEN 'OUT_OF_STOCK'::text
            WHEN (COALESCE(wo_issued.issued_qty, (0)::numeric) <= ab.safety_stock) THEN 'BELOW_SAFETY_STOCK'::text
            WHEN (COALESCE(wo_issued.issued_qty, (0)::numeric) <= ab.reorder_point) THEN 'BELOW_REORDER'::text
            ELSE 'IN_STOCK'::text
        END AS stock_status,
    count(DISTINCT a.asset_id) AS used_on_assets
   FROM (((eam.eam_asset_bom ab
     LEFT JOIN ( SELECT eam_spare_parts_consumption.item_id,
            sum(eam_spare_parts_consumption.quantity_issued) AS issued_qty
           FROM eam.eam_spare_parts_consumption
          WHERE (eam_spare_parts_consumption.quantity_issued > (0)::numeric)
          GROUP BY eam_spare_parts_consumption.item_id) wo_issued ON ((wo_issued.item_id = ab.item_id)))
     LEFT JOIN ( SELECT eam_spare_parts_consumption.item_id,
            sum((eam_spare_parts_consumption.quantity_required - eam_spare_parts_consumption.quantity_consumed)) AS reserved_qty
           FROM eam.eam_spare_parts_consumption
          WHERE (eam_spare_parts_consumption.quantity_issued > (0)::numeric)
          GROUP BY eam_spare_parts_consumption.item_id) wo_reserved ON ((wo_reserved.item_id = ab.item_id)))
     LEFT JOIN eam.eam_assets a ON ((a.asset_id IN ( SELECT eam_asset_bom.asset_id
           FROM eam.eam_asset_bom
          WHERE (eam_asset_bom.item_id = ab.item_id)))))
  GROUP BY ab.item_id, ab.item_code, ab.item_name, ab.description, ab.unit_of_measure, ab.quantity_per_asset, ab.min_stock_level, ab.max_stock_level, ab.reorder_point, ab.safety_stock, ab.unit_cost, ab.lead_time_days, ab.critical_spare, ab.long_lead_item, wo_issued.issued_qty, wo_reserved.reserved_qty;


--
-- Name: v_technician_schedule; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_technician_schedule AS
 SELECT t.technician_id,
    t.technician_code,
    (((t.first_name)::text || ' '::text) || (t.last_name)::text) AS technician_name,
    c.craft_name AS primary_craft,
    wo.work_order_id,
    wo.work_order_number,
    wo.title,
    wo.priority_code,
    wo.work_order_status_code,
    wo.scheduled_start,
    wo.scheduled_end,
    wo.estimated_hours,
    wo.actual_hours,
    a.asset_number,
    a.asset_name,
    fl.location_code AS functional_location,
        CASE
            WHEN ((wo.scheduled_start IS NOT NULL) AND (wo.scheduled_start <= CURRENT_TIMESTAMP) AND (wo.scheduled_end >= CURRENT_TIMESTAMP) AND ((wo.work_order_status_code)::text = 'IN_PROGRESS'::text)) THEN 'CURRENT'::text
            WHEN ((wo.scheduled_start > CURRENT_TIMESTAMP) AND (wo.scheduled_end > CURRENT_TIMESTAMP)) THEN 'UPCOMING'::text
            WHEN ((wo.scheduled_end < CURRENT_TIMESTAMP) AND ((wo.work_order_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying, 'COMPLETED'::character varying])::text[]))) THEN 'OVERDUE'::text
            WHEN ((wo.work_order_status_code)::text = ANY ((ARRAY['COMPLETED'::character varying, 'VERIFIED'::character varying, 'CLOSED'::character varying])::text[])) THEN 'DONE'::text
            ELSE 'OTHER'::text
        END AS schedule_status
   FROM (((((eam.eam_technicians t
     JOIN eam.eam_wo_labor wl ON ((wl.technician_id = t.technician_id)))
     JOIN eam.eam_work_orders wo ON ((wo.work_order_id = wl.work_order_id)))
     LEFT JOIN eam.eam_crafts c ON (((c.craft_code)::text = (t.primary_craft_code)::text)))
     LEFT JOIN eam.eam_assets a ON ((a.asset_id = wo.asset_id)))
     LEFT JOIN eam.eam_functional_locations fl ON ((fl.functional_location_id = wo.functional_location_id)))
  ORDER BY t.technician_code, wo.scheduled_start;


--
-- Name: v_technician_workload; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_technician_workload AS
 SELECT t.technician_id,
    t.technician_code,
    (((t.first_name)::text || ' '::text) || (t.last_name)::text) AS technician_name,
    c.craft_name AS primary_craft,
    count(DISTINCT wo.work_order_id) FILTER (WHERE ((wo.work_order_status_code)::text = ANY ((ARRAY['ASSIGNED'::character varying, 'IN_PROGRESS'::character varying])::text[]))) AS active_work_orders,
    count(DISTINCT wo.work_order_id) FILTER (WHERE ((wo.work_order_status_code)::text = 'SCHEDULED'::text)) AS scheduled_work_orders,
    COALESCE(sum(wo.estimated_hours) FILTER (WHERE ((wo.work_order_status_code)::text = ANY ((ARRAY['ASSIGNED'::character varying, 'IN_PROGRESS'::character varying, 'SCHEDULED'::character varying])::text[]))), (0)::numeric) AS total_estimated_hours,
    COALESCE(sum(wo.actual_hours) FILTER (WHERE ((wo.work_order_status_code)::text = 'IN_PROGRESS'::text)), (0)::numeric) AS hours_worked_today,
    COALESCE(sum(wl.hours_actual) FILTER (WHERE (wl.start_time >= CURRENT_DATE)), (0)::numeric) AS hours_logged_today,
    t.technician_status_code,
    t.max_travel_distance_km
   FROM (((eam.eam_technicians t
     LEFT JOIN eam.eam_crafts c ON (((c.craft_code)::text = (t.primary_craft_code)::text)))
     LEFT JOIN eam.eam_wo_labor wl ON ((wl.technician_id = t.technician_id)))
     LEFT JOIN eam.eam_work_orders wo ON (((wo.work_order_id = wl.work_order_id) OR (wo.work_order_id IN ( SELECT wl2.work_order_id
           FROM eam.eam_wo_labor wl2
          WHERE (wl2.technician_id = t.technician_id))))))
  GROUP BY t.technician_id, t.technician_code, t.first_name, t.last_name, c.craft_name, t.technician_status_code, t.max_travel_distance_km;


--
-- Name: v_warranty_status; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_warranty_status AS
 SELECT w.warranty_id,
    w.warranty_number,
    w.warranty_name,
    a.asset_number,
    a.asset_name,
    a.serial_number,
    w.warranty_type_code,
    w.warranty_provider,
    w.start_date,
    w.end_date,
    w.warranty_status_code,
        CASE
            WHEN (w.end_date < CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (w.end_date <= (CURRENT_DATE + '90 days'::interval)) THEN 'EXPIRING_SOON'::text
            WHEN (w.end_date <= (CURRENT_DATE + '365 days'::interval)) THEN 'EXPIRING'::text
            ELSE 'ACTIVE'::text
        END AS warranty_health,
    (w.end_date - CURRENT_DATE) AS days_remaining,
    ( SELECT count(*) AS count
           FROM eam.eam_warranty_claims wc
          WHERE (wc.warranty_id = w.warranty_id)) AS claim_count,
    ( SELECT COALESCE(sum(wc.claim_amount), (0)::numeric) AS "coalesce"
           FROM eam.eam_warranty_claims wc
          WHERE (wc.warranty_id = w.warranty_id)) AS total_claims
   FROM (eam.eam_warranties w
     JOIN eam.eam_assets a ON ((a.asset_id = w.asset_id)));


--
-- Name: v_work_order_dashboard; Type: VIEW; Schema: eam; Owner: -
--

CREATE VIEW eam.v_work_order_dashboard AS
 SELECT wo.work_order_id,
    wo.work_order_number,
    wo.title,
    wo.description,
    wot.work_order_type_name,
    wos.work_order_status_name,
    wo.priority_code,
    a.asset_number,
    a.asset_name,
    a.criticality_code,
    fl.location_code AS functional_location,
    wo.requested_by,
    wo.requested_date,
    wo.due_date,
    wo.scheduled_start,
    wo.scheduled_end,
    wo.actual_start,
    wo.actual_end,
    wo.estimated_hours,
    wo.actual_hours,
    wo.estimated_cost,
    wo.actual_cost,
    wo.downtime_hours,
        CASE
            WHEN ((wo.due_date IS NOT NULL) AND (wo.due_date < CURRENT_TIMESTAMP) AND ((wo.work_order_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying, 'VERIFIED'::character varying])::text[]))) THEN 'OVERDUE'::text
            WHEN ((wo.due_date IS NOT NULL) AND (wo.due_date <= (CURRENT_TIMESTAMP + '7 days'::interval)) AND ((wo.work_order_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying, 'VERIFIED'::character varying])::text[]))) THEN 'DUE_SOON'::text
            ELSE 'ON_TRACK'::text
        END AS due_status,
        CASE
            WHEN ((wo.work_order_status_code)::text = ANY ((ARRAY['REQUESTED'::character varying, 'APPROVED'::character varying])::text[])) THEN 'PLANNING'::text
            WHEN ((wo.work_order_status_code)::text = ANY ((ARRAY['PLANNED'::character varying, 'SCHEDULED'::character varying, 'ASSIGNED'::character varying])::text[])) THEN 'SCHEDULED'::text
            WHEN ((wo.work_order_status_code)::text = 'IN_PROGRESS'::text) THEN 'IN_PROGRESS'::text
            WHEN ((wo.work_order_status_code)::text = ANY ((ARRAY['COMPLETED'::character varying, 'VERIFIED'::character varying])::text[])) THEN 'COMPLETED'::text
            WHEN ((wo.work_order_status_code)::text = 'CLOSED'::text) THEN 'CLOSED'::text
            ELSE 'OTHER'::text
        END AS status_category,
    wo.creation_date,
    wo.tenant_id,
    wo.organization_id,
    wo.site_id
   FROM ((((eam.eam_work_orders wo
     LEFT JOIN eam.eam_work_order_types wot ON (((wot.work_order_type_code)::text = (wo.work_order_type_code)::text)))
     LEFT JOIN eam.eam_work_order_statuses wos ON (((wos.work_order_status_code)::text = (wo.work_order_status_code)::text)))
     LEFT JOIN eam.eam_assets a ON ((a.asset_id = wo.asset_id)))
     LEFT JOIN eam.eam_functional_locations fl ON ((fl.functional_location_id = wo.functional_location_id)));


