--
-- Name: mv_expense_by_category; Type: MATERIALIZED VIEW; Schema: exp; Owner: -
--

CREATE MATERIALIZED VIEW exp.mv_expense_by_category AS
 SELECT ec.category_code,
    ec.category_name,
    EXTRACT(year FROM cl.expense_date) AS yr,
    EXTRACT(month FROM cl.expense_date) AS mon,
    sum(cl.amount) AS total_amount,
    sum(cl.tax_amount) AS total_tax,
    count(*) AS entry_count
   FROM (exp.claim_lines cl
     LEFT JOIN exp.exp_categories ec ON ((ec.category_id = cl.category_id)))
  GROUP BY ec.category_code, ec.category_name, (EXTRACT(year FROM cl.expense_date)), (EXTRACT(month FROM cl.expense_date))
  WITH NO DATA;


--
-- Name: v_claim_summary; Type: VIEW; Schema: exp; Owner: -
--

CREATE VIEW exp.v_claim_summary AS
 SELECT ch.claim_id,
    ch.claim_number,
    ch.purpose,
    ch.total_amount,
    ch.status,
    ch.created_at,
    count(cl.claim_line_id) AS line_count,
    sum(cl.amount) AS line_total,
    sum(cl.tax_amount) AS total_tax
   FROM (exp.claim_headers ch
     LEFT JOIN exp.claim_lines cl ON ((cl.claim_id = ch.claim_id)))
  GROUP BY ch.claim_id, ch.claim_number, ch.purpose, ch.total_amount, ch.status, ch.created_at;


