--
-- Name: v_fa_asset_register; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_asset_register AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    a.description,
    db.book_id,
    db.book_code,
    db.book_name,
    bbt.book_type_name,
    ac.category_code,
    ac.category_name,
    atp.asset_type_name,
    aba.deprn_method_id,
    dm.method_name AS deprn_method_name,
    dc.convention_name AS deprn_convention_name,
    aba.useful_life_months,
    aba.salvage_value,
    aba.salvage_pct,
    aba.deprn_start_date,
    aba.deprn_end_date,
    aba.original_cost AS book_cost,
    aba.current_cost AS book_current_cost,
    aba.accumulated_deprn,
    aba.net_book_value,
    aba.deprn_status_code,
    aba.enable_bonus_deprn,
    aba.enable_section_179,
    l.location_name,
    c.custodian_name,
    a.asset_status_code,
    a.in_service_date,
    a.tenant_id,
    a.organization_id,
    a.entity_id
   FROM (((((((((fa.fa_assets a
     JOIN fa.fa_asset_book_assignments aba ON (((a.asset_id = aba.asset_id) AND ((aba.is_active)::text = 'Y'::text))))
     JOIN fa.fa_deprn_books db ON ((aba.book_id = db.book_id)))
     JOIN fa.fa_book_types bbt ON ((db.book_type_id = bbt.book_type_id)))
     LEFT JOIN fa.fa_deprn_methods dm ON ((aba.deprn_method_id = dm.deprn_method_id)))
     LEFT JOIN fa.fa_deprn_conventions dc ON ((aba.deprn_convention_id = dc.deprn_convention_id)))
     LEFT JOIN fa.fa_asset_categories ac ON ((a.asset_category_id = ac.asset_category_id)))
     LEFT JOIN fa.fa_asset_types atp ON ((a.asset_type_id = atp.asset_type_id)))
     LEFT JOIN fa.fa_locations l ON ((a.location_id = l.location_id)))
     LEFT JOIN fa.fa_custodians c ON ((a.custodian_id = c.custodian_id)))
  WHERE ((a.is_active)::text = 'Y'::text);


--
-- Name: v_fa_asset_roll_forward; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_asset_roll_forward AS
 WITH asset_beginning AS (
         SELECT db.book_id,
            db.book_code,
            db.book_name,
            a.asset_category_id,
            ac.category_name,
            a.location_id,
            l.location_name,
            COALESCE(sum(aba.original_cost), (0)::numeric) AS beginning_cost,
            COALESCE(sum(aba.accumulated_deprn), (0)::numeric) AS beginning_deprn,
            COALESCE(sum(aba.net_book_value), (0)::numeric) AS beginning_nbv,
            count(DISTINCT a.asset_id) AS beginning_count
           FROM ((((fa.fa_deprn_books db
             CROSS JOIN fa.fa_assets a)
             JOIN fa.fa_asset_book_assignments aba ON (((a.asset_id = aba.asset_id) AND (aba.book_id = db.book_id))))
             LEFT JOIN fa.fa_asset_categories ac ON ((a.asset_category_id = ac.asset_category_id)))
             LEFT JOIN fa.fa_locations l ON ((a.location_id = l.location_id)))
          WHERE (((a.is_active)::text = 'Y'::text) AND ((aba.is_active)::text = 'Y'::text))
          GROUP BY db.book_id, db.book_code, db.book_name, a.asset_category_id, ac.category_name, a.location_id, l.location_name
        ), additions AS (
         SELECT aba.book_id,
            a.asset_category_id,
            a.location_id,
            COALESCE(sum(ad_1.total_cost), (0)::numeric) AS addition_cost,
            count(DISTINCT a.asset_id) AS addition_count
           FROM ((fa.fa_additions ad_1
             JOIN fa.fa_assets a ON ((ad_1.asset_id = a.asset_id)))
             JOIN fa.fa_asset_book_assignments aba ON ((a.asset_id = aba.asset_id)))
          WHERE ((ad_1.is_active)::text = 'Y'::text)
          GROUP BY aba.book_id, a.asset_category_id, a.location_id
        ), retirements AS (
         SELECT aba.book_id,
            a.asset_category_id,
            a.location_id,
            COALESCE(sum(ret_1.original_cost), (0)::numeric) AS retirement_cost,
            COALESCE(sum(ret_1.net_book_value), (0)::numeric) AS retirement_nbv,
            count(DISTINCT a.asset_id) AS retirement_count
           FROM ((fa.fa_retirements ret_1
             JOIN fa.fa_assets a ON ((ret_1.asset_id = a.asset_id)))
             JOIN fa.fa_asset_book_assignments aba ON ((a.asset_id = aba.asset_id)))
          WHERE ((ret_1.is_active)::text = 'Y'::text)
          GROUP BY aba.book_id, a.asset_category_id, a.location_id
        )
 SELECT ab.book_id,
    ab.book_code,
    ab.book_name,
    ab.asset_category_id,
    ab.category_name,
    ab.location_id,
    ab.location_name,
    ab.beginning_cost,
    ab.beginning_deprn,
    ab.beginning_nbv,
    ab.beginning_count,
    COALESCE(ad.addition_cost, (0)::numeric) AS addition_cost,
    COALESCE(ad.addition_count, (0)::bigint) AS addition_count,
    COALESCE(ret.retirement_cost, (0)::numeric) AS retirement_cost,
    COALESCE(ret.retirement_nbv, (0)::numeric) AS retirement_nbv,
    COALESCE(ret.retirement_count, (0)::bigint) AS retirement_count,
    ((ab.beginning_cost + COALESCE(ad.addition_cost, (0)::numeric)) - COALESCE(ret.retirement_cost, (0)::numeric)) AS ending_cost,
    ((ab.beginning_count + COALESCE(ad.addition_count, (0)::bigint)) - COALESCE(ret.retirement_count, (0)::bigint)) AS ending_count
   FROM ((asset_beginning ab
     LEFT JOIN additions ad ON (((ab.book_id = ad.book_id) AND ((ab.asset_category_id = ad.asset_category_id) OR ((ab.asset_category_id IS NULL) AND (ad.asset_category_id IS NULL))))))
     LEFT JOIN retirements ret ON (((ab.book_id = ret.book_id) AND ((ab.asset_category_id = ret.asset_category_id) OR ((ab.asset_category_id IS NULL) AND (ret.asset_category_id IS NULL))))));


--
-- Name: v_fa_asset_summary; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_asset_summary AS
 SELECT a.asset_id,
    a.asset_number,
    a.asset_name,
    a.description,
    atp.asset_type_name,
    atp.asset_class_code,
    ac.category_name,
    a.original_cost,
    a.current_cost,
    a.salvage_value,
    a.accumulated_depreciation,
    a.net_book_value,
    a.fair_value,
    a.asset_status_code,
    a.condition_code,
    a.criticality_code,
    a.source_code,
    a.manufacturer_name,
    a.model_number,
    a.serial_number,
    a.acquisition_date,
    a.in_service_date,
    l.location_name,
    l.location_code,
    l.city,
    l.state,
    l.country_code,
    c.custodian_name,
    c.custodian_type_code,
    a.currency_code,
    a.barcode,
    a.rfid_tag,
    a.organization_id,
    a.entity_id,
    a.tenant_id
   FROM ((((fa.fa_assets a
     LEFT JOIN fa.fa_asset_types atp ON ((a.asset_type_id = atp.asset_type_id)))
     LEFT JOIN fa.fa_asset_categories ac ON ((a.asset_category_id = ac.asset_category_id)))
     LEFT JOIN fa.fa_locations l ON ((a.location_id = l.location_id)))
     LEFT JOIN fa.fa_custodians c ON ((a.custodian_id = c.custodian_id)))
  WHERE ((a.is_active)::text = 'Y'::text);


--
-- Name: v_fa_cip_summary; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_cip_summary AS
 SELECT cp.cip_project_id,
    cp.project_code,
    cp.project_name,
    cp.cip_status_code,
    cp.start_date,
    cp.expected_completion_date,
    cp.actual_completion_date,
    cp.capitalization_date,
    cp.progress_pct,
    cp.total_budget,
    cp.total_costs,
    cp.capitalized_cost,
    cp.remaining_cost,
    cp.material_cost,
    cp.labor_cost,
    cp.overhead_cost,
    cp.interest_cost,
    cp.other_cost,
    (cp.total_budget - cp.total_costs) AS budget_remaining,
        CASE
            WHEN (cp.total_budget > (0)::numeric) THEN round(((cp.total_costs / cp.total_budget) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS budget_utilization_pct,
    cp.project_manager,
    a_target.asset_number AS target_asset_number,
    a_target.asset_name AS target_asset_name,
    count(DISTINCT cc.cip_cost_id) AS cost_transactions
   FROM ((fa.fa_cip_projects cp
     LEFT JOIN fa.fa_assets a_target ON ((cp.target_asset_id = a_target.asset_id)))
     LEFT JOIN fa.fa_cip_costs cc ON ((cp.cip_project_id = cc.cip_project_id)))
  GROUP BY cp.cip_project_id, cp.project_code, cp.project_name, cp.cip_status_code, cp.start_date, cp.expected_completion_date, cp.actual_completion_date, cp.capitalization_date, cp.progress_pct, cp.total_budget, cp.total_costs, cp.capitalized_cost, cp.remaining_cost, cp.material_cost, cp.labor_cost, cp.overhead_cost, cp.interest_cost, cp.other_cost, cp.project_manager, a_target.asset_number, a_target.asset_name;


--
-- Name: v_fa_deprn_expense_by_period; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_deprn_expense_by_period AS
 SELECT db.book_id,
    db.book_code,
    db.book_name,
    bbt.book_type_name,
    dp.period_id,
    dp.period_name,
    dp.fiscal_year,
    dp.period_num,
    dp.start_date,
    dp.end_date,
    count(DISTINCT dc.asset_id) AS assets_depreciated,
    COALESCE(sum(dc.deprn_amount), (0)::numeric) AS total_deprn_expense,
    COALESCE(sum(dc.bonus_deprn_amount), (0)::numeric) AS total_bonus_deprn,
    COALESCE(sum(dc.section_179_amount), (0)::numeric) AS total_section_179,
    COALESCE(sum(((dc.deprn_amount + dc.bonus_deprn_amount) + dc.section_179_amount)), (0)::numeric) AS total_deprn_all,
    COALESCE(sum(dc.beginning_nbv), (0)::numeric) AS total_beginning_nbv,
    COALESCE(sum(dc.ending_nbv), (0)::numeric) AS total_ending_nbv,
        CASE
            WHEN ((dp.is_deprn_posted)::text = 'Y'::text) THEN 'POSTED'::text
            ELSE 'CALCULATED'::text
        END AS posting_status
   FROM (((fa.fa_deprn_book_periods dp
     JOIN fa.fa_deprn_books db ON ((dp.book_id = db.book_id)))
     JOIN fa.fa_book_types bbt ON ((db.book_type_id = bbt.book_type_id)))
     LEFT JOIN fa.fa_deprn_calculation dc ON (((dp.period_id = dc.period_id) AND (dc.book_id = db.book_id))))
  GROUP BY db.book_id, db.book_code, db.book_name, bbt.book_type_name, dp.period_id, dp.period_name, dp.fiscal_year, dp.period_num, dp.start_date, dp.end_date, dp.is_deprn_posted
  ORDER BY dp.fiscal_year, dp.period_num;


--
-- Name: v_fa_deprn_schedule; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_deprn_schedule AS
 SELECT dc.deprn_calc_id,
    a.asset_id,
    a.asset_number,
    a.asset_name,
    ac.category_name,
    atp.asset_type_name,
    db.book_id,
    db.book_code,
    db.book_name,
    bbt.book_type_name,
    dp.period_id,
    dp.period_name,
    dp.fiscal_year,
    dp.period_num,
    dp.start_date AS period_start_date,
    dp.end_date AS period_end_date,
    dc.beginning_nbv,
    dc.deprn_amount,
    dc.bonus_deprn_amount,
    dc.section_179_amount,
    dc.ending_nbv,
    dc.ytd_deprn,
    dc.ltd_deprn,
    dc.deprn_status_code,
    dc.deprn_posting_date,
    aba.useful_life_months,
    aba.deprn_start_date,
    aba.deprn_end_date,
    dm.method_name AS deprn_method_name,
    dc.tenant_id,
    dc.organization_id
   FROM ((((((((fa.fa_deprn_calculation dc
     JOIN fa.fa_assets a ON ((dc.asset_id = a.asset_id)))
     JOIN fa.fa_deprn_books db ON ((dc.book_id = db.book_id)))
     JOIN fa.fa_book_types bbt ON ((db.book_type_id = bbt.book_type_id)))
     JOIN fa.fa_deprn_book_periods dp ON ((dc.period_id = dp.period_id)))
     LEFT JOIN fa.fa_asset_categories ac ON ((a.asset_category_id = ac.asset_category_id)))
     LEFT JOIN fa.fa_asset_types atp ON ((a.asset_type_id = atp.asset_type_id)))
     LEFT JOIN fa.fa_asset_book_assignments aba ON (((a.asset_id = aba.asset_id) AND (aba.book_id = dc.book_id))))
     LEFT JOIN fa.fa_deprn_methods dm ON ((aba.deprn_method_id = dm.deprn_method_id)));


--
-- Name: v_fa_disposal_gain_loss; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_disposal_gain_loss AS
 SELECT r.retirement_id,
    r.transaction_id,
    r.asset_id,
    a.asset_number,
    a.asset_name,
    ac.category_name,
    atp.asset_type_name,
    r.retirement_type_code,
    r.retirement_date,
    r.original_cost,
    r.accumulated_deprn,
    r.net_book_value,
    r.proceeds_amount,
    r.gain_loss_amount,
        CASE
            WHEN (r.gain_loss_amount > (0)::numeric) THEN 'GAIN'::text
            WHEN (r.gain_loss_amount < (0)::numeric) THEN 'LOSS'::text
            ELSE 'ZERO'::text
        END AS gain_loss_type,
    r.buyer_name,
    r.retirement_reason,
    t.transaction_number,
    t.approval_status
   FROM ((((fa.fa_retirements r
     JOIN fa.fa_assets a ON ((r.asset_id = a.asset_id)))
     JOIN fa.fa_transactions t ON ((r.transaction_id = t.transaction_id)))
     LEFT JOIN fa.fa_asset_categories ac ON ((a.asset_category_id = ac.asset_category_id)))
     LEFT JOIN fa.fa_asset_types atp ON ((a.asset_type_id = atp.asset_type_id)));


--
-- Name: v_fa_insurance_status; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_insurance_status AS
 SELECT ip.policy_id,
    ip.policy_number,
    ip.policy_name,
    ip.insurance_company,
    ip.coverage_type_code,
    ip.coverage_amount,
    ip.deductible_amount,
    ip.premium_amount,
    ip.effective_date,
    ip.expiration_date,
    ip.policy_status_code,
        CASE
            WHEN (ip.expiration_date < CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (ip.expiration_date < (CURRENT_DATE + '30 days'::interval)) THEN 'EXPIRING_SOON'::text
            WHEN (ip.expiration_date < (CURRENT_DATE + '90 days'::interval)) THEN 'EXPIRING'::text
            ELSE 'ACTIVE'::text
        END AS insurance_status,
    (ip.expiration_date - CURRENT_DATE) AS days_remaining,
    count(DISTINCT a.asset_id) AS covered_asset_count,
    COALESCE(sum(a.current_cost), (0)::numeric) AS total_covered_value
   FROM (fa.fa_insurance_policies ip
     LEFT JOIN fa.fa_assets a ON ((a.insurance_policy_id = ip.policy_id)))
  GROUP BY ip.policy_id, ip.policy_number, ip.policy_name, ip.insurance_company, ip.coverage_type_code, ip.coverage_amount, ip.deductible_amount, ip.premium_amount, ip.effective_date, ip.expiration_date, ip.policy_status_code;


--
-- Name: v_fa_lease_summary; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_lease_summary AS
 SELECT l.lease_id,
    l.lease_number,
    l.lease_name,
    l.lease_type_code,
    l.lease_class_code,
    l.lease_status_code,
    l.lessor_name,
    l.commencement_date,
    l.lease_end_date,
    l.lease_term_months,
    l.fixed_payment_amount,
    l.discount_rate,
    l.incremental_borrowing_rate,
    l.lease_liability,
    l.rou_asset_cost,
    l.rou_asset_accumulated_deprn,
    l.rou_asset_nbv,
    (l.lease_liability - COALESCE(ls.total_paid, (0)::numeric)) AS outstanding_liability,
    count(DISTINCT la.asset_id) AS rou_asset_count,
        CASE
            WHEN (l.lease_end_date < CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (l.lease_end_date < (CURRENT_DATE + '90 days'::interval)) THEN 'EXPIRING'::text
            ELSE 'ACTIVE'::text
        END AS lease_age_status
   FROM ((fa.fa_leases l
     LEFT JOIN fa.fa_lease_assets la ON ((l.lease_id = la.lease_id)))
     LEFT JOIN ( SELECT fa_lease_schedules.lease_id,
            COALESCE(sum(fa_lease_schedules.actual_payment_amount), sum(fa_lease_schedules.payment_amount)) AS total_paid
           FROM fa.fa_lease_schedules
          WHERE ((fa_lease_schedules.payment_status_code)::text = 'PAID'::text)
          GROUP BY fa_lease_schedules.lease_id) ls ON ((l.lease_id = ls.lease_id)))
  GROUP BY l.lease_id, l.lease_number, l.lease_name, l.lease_type_code, l.lease_class_code, l.lease_status_code, l.lessor_name, l.commencement_date, l.lease_end_date, l.lease_term_months, l.fixed_payment_amount, l.discount_rate, l.incremental_borrowing_rate, l.lease_liability, l.rou_asset_cost, l.rou_asset_accumulated_deprn, l.rou_asset_nbv, ls.total_paid;


--
-- Name: v_fa_mobile_scan_progress; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_mobile_scan_progress AS
 SELECT ms.count_id,
    pc.count_name,
    ms.counter_id,
    ms.counter_name,
    l.location_name,
    l.location_code,
    count(*) AS total_scans,
    sum(
        CASE
            WHEN ((ms.scan_status_code)::text = 'VERIFIED'::text) THEN 1
            ELSE 0
        END) AS verified_count,
    sum(
        CASE
            WHEN ((ms.scan_status_code)::text ~~ 'VARIANCE_%'::text) THEN 1
            ELSE 0
        END) AS variance_count,
    sum(
        CASE
            WHEN ((ms.sync_status_code)::text = 'PENDING'::text) THEN 1
            ELSE 0
        END) AS pending_sync,
    sum(
        CASE
            WHEN ((ms.sync_status_code)::text = 'SYNCED'::text) THEN 1
            ELSE 0
        END) AS synced_count,
    sum(
        CASE
            WHEN ((ms.sync_status_code)::text = 'FAILED'::text) THEN 1
            ELSE 0
        END) AS failed_count,
    min(ms.scan_timestamp) AS first_scan_time,
    max(ms.scan_timestamp) AS last_scan_time,
    count(DISTINCT ms.device_id) AS devices_used
   FROM ((fa.fa_mobile_scans ms
     JOIN fa.fa_physical_counts pc ON ((ms.count_id = pc.count_id)))
     LEFT JOIN fa.fa_locations l ON ((ms.actual_location_id = l.location_id)))
  GROUP BY ms.count_id, pc.count_name, ms.counter_id, ms.counter_name, l.location_name, l.location_code;


--
-- Name: v_fa_physical_count_summary; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_physical_count_summary AS
 SELECT pc.count_id,
    pc.count_name,
    pc.count_type_code,
    pc.count_status_code,
    pc.planned_date,
    pc.count_start_date,
    pc.count_end_date,
    l.location_name,
    l.location_code,
    ac.category_name,
    pc.expected_asset_count,
    pc.scanned_asset_count,
    pc.missing_asset_count,
    pc.excess_asset_count,
    pc.wrong_location_count,
    pc.variance_pct,
        CASE
            WHEN (pc.expected_asset_count > 0) THEN round((((pc.scanned_asset_count)::numeric / (pc.expected_asset_count)::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS completion_pct,
    pc.approval_status,
    pc.sync_status_code
   FROM ((fa.fa_physical_counts pc
     LEFT JOIN fa.fa_locations l ON ((pc.location_id = l.location_id)))
     LEFT JOIN fa.fa_asset_categories ac ON ((pc.asset_category_id = ac.asset_category_id)));


--
-- Name: v_fa_physical_count_variances; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_physical_count_variances AS
 SELECT cv.variance_id,
    cv.count_id,
    pc.count_name,
    cv.asset_id,
    a.asset_number,
    a.asset_name,
    ac.category_name,
    l_expected.location_name AS expected_location,
    l_actual.location_name AS actual_location,
    cv.variance_type_code,
    cv.variance_severity_code,
    cv.variance_reason_code,
    cv.expected_value,
    cv.actual_value,
    cv.requires_adjustment,
    cv.adjustment_pending,
    cv.resolution_code,
    cv.approval_status,
    cs.sheet_number,
    cs.counter_name,
    ms.scan_timestamp,
    ms.gps_latitude,
    ms.gps_longitude
   FROM ((((((((fa.fa_count_variances cv
     JOIN fa.fa_physical_counts pc ON ((cv.count_id = pc.count_id)))
     JOIN fa.fa_assets a ON ((cv.asset_id = a.asset_id)))
     LEFT JOIN fa.fa_asset_categories ac ON ((a.asset_category_id = ac.asset_category_id)))
     LEFT JOIN fa.fa_locations l_expected ON ((a.location_id = l_expected.location_id)))
     LEFT JOIN fa.fa_count_lines cl ON ((cv.count_line_id = cl.count_line_id)))
     LEFT JOIN fa.fa_locations l_actual ON ((cl.actual_location_id = l_actual.location_id)))
     LEFT JOIN fa.fa_count_sheets cs ON ((cl.sheet_id = cs.sheet_id)))
     LEFT JOIN fa.fa_mobile_scans ms ON ((cl.scan_id = ms.scan_id)));


--
-- Name: v_fa_warranty_status; Type: VIEW; Schema: fa; Owner: -
--

CREATE VIEW fa.v_fa_warranty_status AS
 SELECT w.warranty_id,
    w.warranty_number,
    w.warranty_type_code,
    w.warranty_provider,
    w.coverage_type_code,
    w.start_date,
    w.end_date,
    w.warranty_status_code,
        CASE
            WHEN (w.end_date < CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (w.end_date < (CURRENT_DATE + '30 days'::interval)) THEN 'EXPIRING_SOON'::text
            WHEN (w.end_date < (CURRENT_DATE + '90 days'::interval)) THEN 'EXPIRING'::text
            ELSE 'ACTIVE'::text
        END AS warranty_status,
    (w.end_date - CURRENT_DATE) AS days_remaining,
    count(DISTINCT a.asset_id) AS covered_asset_count
   FROM (fa.fa_warranties w
     LEFT JOIN fa.fa_assets a ON ((a.warranty_id = w.warranty_id)))
  GROUP BY w.warranty_id, w.warranty_number, w.warranty_type_code, w.warranty_provider, w.coverage_type_code, w.start_date, w.end_date, w.warranty_status_code;


