--
-- Name: mv_account_balance_by_period; Type: MATERIALIZED VIEW; Schema: gl; Owner: -
--

CREATE MATERIALIZED VIEW gl.mv_account_balance_by_period AS
 SELECT a.account_id,
    a.account_code,
    a.account_type,
    EXTRACT(year FROM h.accounting_date) AS yr,
    EXTRACT(month FROM h.accounting_date) AS mon,
    sum(l.debit_amount) AS debit,
    sum(l.credit_amount) AS credit,
    sum((l.debit_amount - l.credit_amount)) AS balance
   FROM ((gl.chart_of_accounts a
     LEFT JOIN gl.journal_lines l ON ((l.account_id = a.account_id)))
     LEFT JOIN gl.journal_headers h ON ((h.journal_id = l.journal_id)))
  GROUP BY a.account_id, a.account_code, a.account_type, (EXTRACT(year FROM h.accounting_date)), (EXTRACT(month FROM h.accounting_date))
  WITH NO DATA;


--
-- Name: mv_trial_balance; Type: MATERIALIZED VIEW; Schema: gl; Owner: -
--

CREATE MATERIALIZED VIEW gl.mv_trial_balance AS
 SELECT a.account_id,
    a.account_code,
    a.account_name,
    a.account_type,
    sum(l.debit_amount) AS total_debit,
    sum(l.credit_amount) AS total_credit,
    sum((l.debit_amount - l.credit_amount)) AS balance
   FROM (gl.chart_of_accounts a
     LEFT JOIN gl.journal_lines l ON ((l.account_id = a.account_id)))
  GROUP BY a.account_id, a.account_code, a.account_name, a.account_type
  WITH NO DATA;


