CREATE TABLE gl.period_statuses (
    period_stat_id uuid DEFAULT uuidv7() NOT NULL,
    ledger_id uuid NOT NULL,
    period_id uuid NOT NULL,
    status character varying(30) DEFAULT 'FUTURE'::character varying,
    opened_at timestamp with time zone,
    closed_by uuid,
    closed_at timestamp with time zone,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    object_version_number integer DEFAULT 1
);


--
-- Name: v_journal_entry_view; Type: VIEW; Schema: gl; Owner: -
--

CREATE VIEW gl.v_journal_entry_view AS
 SELECT h.journal_id,
    h.accounting_date,
    h.doc_sequence,
    h.source_module,
    l.line_id,
    l.account_id,
    a.account_code,
    a.account_name,
    a.account_type,
    l.debit_amount,
    l.credit_amount
   FROM ((gl.journal_headers h
     JOIN gl.journal_lines l ON ((l.journal_id = h.journal_id)))
     LEFT JOIN gl.chart_of_accounts a ON ((a.account_id = l.account_id)));


