--
-- Name: v_aged_onhand; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_aged_onhand AS
 SELECT ob.onhand_id,
    ob.item_id,
    i.item_number,
    i.description,
    ob.warehouse_id,
    w.warehouse_code,
    ob.location_id,
    l.location_code,
    ob.lot_number,
    ob.qty_onhand,
    ob.qty_available,
    lm.expiration_date,
    lm.manufacturing_date,
        CASE
            WHEN (lm.expiration_date IS NULL) THEN 'NO_EXPIRY'::text
            WHEN (lm.expiration_date <= CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (lm.expiration_date <= (CURRENT_DATE + 30)) THEN 'EXPIRING_SOON'::text
            WHEN (lm.expiration_date <= (CURRENT_DATE + 90)) THEN 'EXPIRING'::text
            ELSE 'FRESH'::text
        END AS expiration_status,
        CASE
            WHEN (lm.expiration_date IS NOT NULL) THEN (lm.expiration_date - CURRENT_DATE)
            ELSE NULL::integer
        END AS days_until_expiry
   FROM ((((inv.inv_onhand_balances ob
     LEFT JOIN mdm.items i ON ((i.item_id = ob.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = ob.warehouse_id)))
     LEFT JOIN core.locations l ON ((l.location_id = ob.location_id)))
     LEFT JOIN inv.lot_master lm ON ((((lm.lot_number)::text = (ob.lot_number)::text) AND (lm.item_id = ob.item_id))))
  WHERE ((ob.is_active = true) AND (ob.qty_onhand > (0)::numeric))
  ORDER BY lm.expiration_date;


--
-- Name: v_cycle_count_dashboard; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_cycle_count_dashboard AS
 SELECT cs.schedule_id,
    cs.schedule_code,
    cs.schedule_name,
    cs.class_code,
    cs.frequency_days,
    cs.warehouse_id,
    w.warehouse_code,
    (count(cc.cycle_count_id))::integer AS total_counts,
    (count(
        CASE
            WHEN ((cc.status)::text = 'PENDING'::text) THEN 1
            ELSE NULL::integer
        END))::integer AS pending_counts,
    (count(
        CASE
            WHEN ((cc.status)::text = 'COMPLETED'::text) THEN 1
            ELSE NULL::integer
        END))::integer AS completed_counts
   FROM ((inv.cycle_count_schedules cs
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = cs.warehouse_id)))
     LEFT JOIN inv.inv_cycle_counts cc ON ((cc.item_id IN ( SELECT ia.item_id
           FROM inv.item_attributes ia
          WHERE ((ia.abc_class)::text = (cs.class_code)::text)))))
  GROUP BY cs.schedule_id, cs.schedule_code, cs.schedule_name, cs.class_code, cs.frequency_days, cs.warehouse_id, w.warehouse_code
  ORDER BY cs.schedule_code;


--
-- Name: v_inventory_valuation; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_inventory_valuation AS
 SELECT ob.item_id,
    i.item_number,
    i.description,
    ia.abc_class,
    (count(DISTINCT ob.warehouse_id))::integer AS warehouse_count,
    (COALESCE(sum(ob.qty_onhand), (0)::numeric))::numeric(19,4) AS total_qty,
    (COALESCE(avg(ob.unit_cost), (0)::numeric))::numeric(19,4) AS avg_unit_cost,
    (COALESCE(sum((ob.qty_onhand * ob.unit_cost)), (0)::numeric))::numeric(19,4) AS total_value,
    ic.unit_cost AS standard_cost,
    ((COALESCE(sum(ob.qty_onhand), (0)::numeric) * COALESCE(ic.unit_cost, (0)::numeric)))::numeric(19,4) AS standard_value
   FROM (((inv.inv_onhand_balances ob
     LEFT JOIN mdm.items i ON ((i.item_id = ob.item_id)))
     LEFT JOIN inv.item_attributes ia ON ((ia.item_id = ob.item_id)))
     LEFT JOIN inv.item_costs ic ON ((ic.item_id = ob.item_id)))
  WHERE ((ob.is_active = true) AND (ob.qty_onhand > (0)::numeric))
  GROUP BY ob.item_id, i.item_number, i.description, ia.abc_class, ic.unit_cost
  ORDER BY ((COALESCE(sum((ob.qty_onhand * ob.unit_cost)), (0)::numeric))::numeric(19,4)) DESC;


--
-- Name: v_lot_expiration_alerts; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_lot_expiration_alerts AS
 SELECT lm.lot_id,
    lm.lot_number,
    lm.item_id,
    i.item_number,
    i.description,
    lm.expiration_date,
    lm.lot_status,
    (lm.expiration_date - CURRENT_DATE) AS days_remaining,
    COALESCE(lo.qty_onhand, (0)::numeric) AS qty_onhand,
        CASE
            WHEN (lm.expiration_date <= CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (lm.expiration_date <= (CURRENT_DATE + 30)) THEN 'CRITICAL'::text
            WHEN (lm.expiration_date <= (CURRENT_DATE + 90)) THEN 'WARNING'::text
            ELSE 'OK'::text
        END AS alert_level
   FROM ((inv.lot_master lm
     LEFT JOIN mdm.items i ON ((i.item_id = lm.item_id)))
     LEFT JOIN inv.lot_onhand lo ON ((lo.lot_id = lm.lot_id)))
  WHERE ((lm.is_active = true) AND (lm.expiration_date IS NOT NULL))
  ORDER BY lm.expiration_date;


--
-- Name: v_onhand_summary; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_onhand_summary AS
 SELECT ob.item_id,
    i.item_number,
    i.description,
    ob.warehouse_id,
    w.warehouse_code,
    w.warehouse_name,
    ob.location_id,
    l.location_code,
    l.zone_name,
    ob.lot_number,
    ob.qty_onhand,
    ob.qty_reserved,
    ob.qty_available,
    ob.unit_cost,
    (ob.qty_onhand * ob.unit_cost) AS inventory_value
   FROM (((inv.inv_onhand_balances ob
     LEFT JOIN mdm.items i ON ((i.item_id = ob.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = ob.warehouse_id)))
     LEFT JOIN core.locations l ON ((l.location_id = ob.location_id)))
  WHERE (ob.is_active = true)
  ORDER BY i.item_number, w.warehouse_code;


--
-- Name: v_replenishment_candidates; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_replenishment_candidates AS
 SELECT r.rule_id,
    r.rule_code,
    r.rule_name,
    r.item_id,
    i.item_number,
    i.description,
    r.warehouse_id,
    w.warehouse_code,
    r.min_qty,
    r.max_qty,
    r.reorder_point,
    r.safety_stock,
    r.lead_time_days,
    COALESCE(ob.qty_onhand, (0)::numeric) AS current_stock,
    COALESCE(ob.qty_available, (0)::numeric) AS available_stock,
        CASE
            WHEN (COALESCE(ob.qty_onhand, (0)::numeric) <= r.reorder_point) THEN 'REORDER'::text
            WHEN (COALESCE(ob.qty_onhand, (0)::numeric) <= r.safety_stock) THEN 'CRITICAL'::text
            ELSE 'OK'::text
        END AS status,
    GREATEST((0)::numeric, (r.max_qty - COALESCE(ob.qty_onhand, (0)::numeric))) AS suggested_order_qty
   FROM (((inv.replenishment_rules r
     LEFT JOIN mdm.items i ON ((i.item_id = r.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = r.warehouse_id)))
     LEFT JOIN inv.inv_onhand_balances ob ON (((ob.item_id = r.item_id) AND (ob.warehouse_id = r.warehouse_id))))
  WHERE (r.is_active = true)
  ORDER BY
        CASE
            WHEN (COALESCE(ob.qty_onhand, (0)::numeric) <= r.reorder_point) THEN 'REORDER'::text
            WHEN (COALESCE(ob.qty_onhand, (0)::numeric) <= r.safety_stock) THEN 'CRITICAL'::text
            ELSE 'OK'::text
        END, r.rule_code;


--
-- Name: v_reservation_summary; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_reservation_summary AS
 SELECT r.reservation_id,
    r.item_id,
    i.item_number,
    i.description,
    r.warehouse_id,
    w.warehouse_code,
    r.lot_number,
    r.qty_reserved,
    r.demand_type,
    r.source_doc_id AS demand_id,
    r.status,
    r.created_at
   FROM ((inv.inv_reservations r
     LEFT JOIN mdm.items i ON ((i.item_id = r.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = r.warehouse_id)))
  WHERE ((r.is_active = true) AND ((r.status)::text = 'ACTIVE'::text))
  ORDER BY r.created_at DESC;


--
-- Name: v_stock_by_warehouse; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_stock_by_warehouse AS
 SELECT warehouse_id,
    item_id,
    sum(qty_onhand) AS qty_onhand,
    sum(qty_reserved) AS qty_reserved,
    sum(qty_available) AS qty_available
   FROM inv.inv_onhand_balances b
  GROUP BY warehouse_id, item_id;


--
-- Name: v_transaction_history; Type: VIEW; Schema: inv; Owner: -
--

CREATE VIEW inv.v_transaction_history AS
 SELECT mt.transaction_id,
    mt.transaction_type,
    mt.item_id,
    i.item_number,
    i.description,
    mt.warehouse_id,
    w.warehouse_code,
    mt.location_from_id,
    lf.location_code AS location_from,
    mt.location_to_id,
    lt.location_code AS location_to,
    mt.lot_number,
    mt.serial_number,
    mt.qty,
    mt.uom_code,
    mt.unit_cost,
    mt.total_cost,
    mt.source_doc_type,
    mt.source_doc_id,
    mt.reference_number,
    mt.transaction_date
   FROM ((((inv.material_transactions mt
     LEFT JOIN mdm.items i ON ((i.item_id = mt.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = mt.warehouse_id)))
     LEFT JOIN core.locations lf ON ((lf.location_id = mt.location_from_id)))
     LEFT JOIN core.locations lt ON ((lt.location_id = mt.location_to_id)))
  WHERE (mt.is_active = true)
  ORDER BY mt.transaction_date DESC;


