--
-- Name: mv_trip_optimization_status; Type: MATERIALIZED VIEW; Schema: log; Owner: -
--

CREATE MATERIALIZED VIEW log.mv_trip_optimization_status AS
 SELECT t.trips_id,
    t.trip_number,
    t.status,
    count(ts.trip_stops_id) AS total_stops,
    count(ts.trip_stops_id) FILTER (WHERE ((ts.status)::text = 'COMPLETED'::text)) AS completed_stops,
    count(ts.trip_stops_id) FILTER (WHERE ((ts.status)::text = ANY ((ARRAY['PENDING'::character varying, 'PLANNED'::character varying])::text[]))) AS pending_stops,
    count(ts.trip_stops_id) FILTER (WHERE ((ts.status)::text = 'FAILED'::text)) AS failed_stops
   FROM (log.trips t
     LEFT JOIN log.trip_stops ts ON ((ts.trip_id = t.trips_id)))
  GROUP BY t.trips_id, t.trip_number, t.status
  WITH NO DATA;


