    latitude numeric(10,7),
    longitude numeric(10,7),
    source character varying(50) DEFAULT 'SYSTEM'::character varying,
    source_detail character varying(255),
    is_customer_visible boolean DEFAULT true,
    notes text,
    tenant_id character varying(50),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    object_version_number integer DEFAULT 1
);


--
-- Name: v_ai_orchestration; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_ai_orchestration AS
 SELECT ai_workflow_state_id,
    workflow_name,
    entity_type,
    entity_id,
    state_type,
    status,
    confidence_score,
    state_data,
    context_data,
    created_at,
    updated_at,
    ( SELECT jsonb_agg(jsonb_build_object('agent', aal.agent_name, 'action', aal.log_level, 'status', aal.status, 'duration_ms', aal.execution_time_ms) ORDER BY aal.created_at DESC) AS jsonb_agg
           FROM log.ai_agent_logs aal
          WHERE (aal.workflow_state_id = aws.ai_workflow_state_id)) AS agent_logs
   FROM log.ai_workflow_state aws
  WHERE ((status)::text <> ALL ((ARRAY['COMPLETED'::character varying, 'FAILED'::character varying])::text[]))
  ORDER BY created_at DESC;


--
-- Name: v_carrier_scorecard; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_carrier_scorecard AS
 SELECT cp.carrier_performance_id,
    cp.carrier_id,
    c.carrier_name,
    cp.period_start,
    cp.period_end,
    cp.total_shipments,
    cp.on_time_delivery_pct,
    cp.tender_acceptance_pct,
    cp.score,
    cp.score_category,
    cp.notes
   FROM (log.carrier_performance cp
     LEFT JOIN log.carriers c ON ((c.carriers_id = cp.carrier_id)))
  WHERE (cp.period_start IS NOT NULL)
  ORDER BY cp.period_start DESC, cp.score DESC;


--
-- Name: v_cost_metrics; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_cost_metrics AS
 SELECT date_trunc('month'::text, (fc.cost_date)::timestamp with time zone) AS month,
    fc.shipment_id,
    s.carrier_id,
    c.carrier_name,
    count(DISTINCT fc.shipment_id) AS shipment_count,
    sum(fc.amount) AS total_freight_cost,
    avg(fc.amount) AS avg_cost_per_shipment,
    COALESCE(sum(l.total_miles), (0)::numeric) AS total_miles,
        CASE
            WHEN (COALESCE(sum(l.total_miles), (0)::numeric) > (0)::numeric) THEN (sum(fc.amount) / sum(l.total_miles))
            ELSE (0)::numeric
        END AS cost_per_mile
   FROM (((log.freight_costs fc
     LEFT JOIN log.shipments s ON ((s.shipments_id = fc.shipment_id)))
     LEFT JOIN log.carriers c ON ((c.carriers_id = s.carrier_id)))
     LEFT JOIN log.loads l ON ((l.loads_id = fc.load_id)))
  WHERE (fc.amount > (0)::numeric)
  GROUP BY (date_trunc('month'::text, (fc.cost_date)::timestamp with time zone)), fc.shipment_id, s.carrier_id, c.carrier_name;


--
-- Name: v_delivery_exceptions; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_delivery_exceptions AS
 SELECT d.deliveries_id,
    d.delivery_number,
    d.shipment_id,
    s.shipment_number,
    d.delivery_type,
    d.recipient_name,
    d.city AS delivery_city,
    d.state AS delivery_state,
    d.delivery_date AS scheduled_date,
    s.actual_delivery_date,
    d.status,
    d.created_at,
    pod.condition_notes AS delivery_notes,
        CASE
            WHEN ((d.status)::text = 'FAILED'::text) THEN 'Delivery failed'::text
            WHEN ((s.actual_delivery_date IS NOT NULL) AND (s.actual_delivery_date > (d.delivery_date + '1 day'::interval))) THEN 'Late delivery'::text
            WHEN (((d.status)::text = 'PENDING'::text) AND (d.delivery_date < now())) THEN 'Overdue'::text
            ELSE 'Normal'::text
        END AS exception_type
   FROM ((log.deliveries d
     LEFT JOIN log.shipments s ON ((s.shipments_id = d.shipment_id)))
     LEFT JOIN log.pod pod ON ((pod.delivery_id = d.deliveries_id)))
  WHERE ((d.status)::text = ANY ((ARRAY['FAILED'::character varying, 'PENDING'::character varying])::text[]));


--
-- Name: v_dock_schedule; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_dock_schedule AS
 SELECT da.dock_appointments_id,
    da.dock_door_id,
    dd.door_code,
    dd.door_name,
    da.load_id,
    l.load_number,
    da.appointment_type,
    da.scheduled_start,
    da.scheduled_end,
    da.actual_arrival,
    da.actual_departure,
    da.status,
    da.notes
   FROM ((log.dock_appointments da
     LEFT JOIN log.dock_doors dd ON ((dd.dock_doors_id = da.dock_door_id)))
     LEFT JOIN log.loads l ON ((l.loads_id = da.load_id)))
  WHERE (da.scheduled_start >= (now() - '7 days'::interval))
  ORDER BY da.scheduled_start;


--
-- Name: v_driver_hos_status; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_driver_hos_status AS
 SELECT d.drivers_id,
    d.driver_code,
    (((d.first_name)::text || ' '::text) || (d.last_name)::text) AS driver_name,
    dh.log_date,
    dh.driving_minutes,
    dh.on_duty_minutes,
    dh.off_duty_minutes,
    (dh.driving_minutes + dh.on_duty_minutes) AS total_on_duty_minutes,
    dh.duty_status,
    d.status AS driver_status,
        CASE
            WHEN (dh.is_violation = true) THEN 'CRITICAL'::text
            WHEN ((dh.driving_minutes + dh.on_duty_minutes) > 660) THEN 'WARNING'::text
            ELSE 'OK'::text
        END AS alert_level
   FROM (log.drivers d
     LEFT JOIN LATERAL ( SELECT dh2.log_date,
            dh2.driving_minutes,
            dh2.on_duty_minutes,
            dh2.off_duty_minutes,
            dh2.duty_status,
            dh2.is_violation
           FROM log.driver_hos dh2
          WHERE (dh2.driver_id = d.drivers_id)
          ORDER BY dh2.log_date DESC
         LIMIT 1) dh ON (true))
  WHERE (d.is_active = true)
  ORDER BY dh.is_violation DESC NULLS LAST, d.driver_code;


--
-- Name: vehicle_types; Type: TABLE; Schema: log; Owner: -
--

CREATE TABLE log.vehicle_types (
    vehicle_types_id uuid DEFAULT uuidv7() NOT NULL,
    vehicle_type_code character varying(50) NOT NULL,
    vehicle_type_name character varying(255) NOT NULL,
    description text,
    max_gvw numeric(19,4),
    max_payload numeric(19,4),
    fuel_type character varying(50),
    num_axles integer,
    is_active boolean DEFAULT true,
    tenant_id character varying(50),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    object_version_number integer DEFAULT 1,
    CONSTRAINT vehicle_types_max_gvw_check CHECK (((max_gvw IS NULL) OR (max_gvw >= (0)::numeric))),
    CONSTRAINT vehicle_types_max_payload_check CHECK (((max_payload IS NULL) OR (max_payload >= (0)::numeric))),
    CONSTRAINT vehicle_types_num_axles_check CHECK (((num_axles IS NULL) OR (num_axles > 0)))
);


--
-- Name: vehicles; Type: TABLE; Schema: log; Owner: -
--

CREATE TABLE log.vehicles (
    vehicles_id uuid DEFAULT uuidv7() NOT NULL,
    vehicle_type_id uuid NOT NULL,
    vehicle_number character varying(100) NOT NULL,
    vin character varying(50),
    license_plate character varying(50),
    license_state character varying(2),
    year integer,
    make character varying(100),
    model character varying(100),
    color character varying(50),
    owned_leased character varying(20) DEFAULT 'OWNED'::character varying,
    purchase_date date,
    lease_expiration date,
    status character varying(50) DEFAULT 'ACTIVE'::character varying,
    current_odometer integer,
    last_maintenance_date date,
    next_maintenance_due_date date,
    registration_expiration date,
    insurance_expiration date,
    is_active boolean DEFAULT true,
    tenant_id character varying(50),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    object_version_number integer DEFAULT 1,
    CONSTRAINT vehicles_current_odometer_check CHECK (((current_odometer IS NULL) OR (current_odometer >= 0))),
    CONSTRAINT vehicles_year_check CHECK (((year IS NULL) OR (year >= 1980)))
);


--
-- Name: v_fleet_utilization; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_fleet_utilization AS
 SELECT v.vehicles_id,
    v.vehicle_number,
    v.license_plate,
    v.vehicle_type_id,
    vt.vehicle_type_name,
    v.status,
    count(DISTINCT t.trips_id) FILTER (WHERE ((t.status)::text = 'COMPLETED'::text)) AS completed_trips,
    count(DISTINCT t.trips_id) FILTER (WHERE ((t.status)::text = 'IN_TRANSIT'::text)) AS active_trips,
    sum(t.total_miles) AS total_miles,
    avg(t.total_miles) AS avg_miles_per_trip,
    max(t.actual_arrival) AS last_used_date,
        CASE
            WHEN (((v.status)::text = 'ACTIVE'::text) AND (max(t.actual_arrival) < (now() - '7 days'::interval))) THEN true
            ELSE false
        END AS is_underutilized
   FROM ((log.vehicles v
     LEFT JOIN log.vehicle_types vt ON ((vt.vehicle_types_id = v.vehicle_type_id)))
     LEFT JOIN log.trips t ON ((t.vehicle_id = v.vehicles_id)))
  GROUP BY v.vehicles_id, v.vehicle_number, v.license_plate, v.vehicle_type_id, vt.vehicle_type_name, v.status;


--
-- Name: v_fuel_consumption; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_fuel_consumption AS
 SELECT fc.fuel_consumption_id,
    fc.vehicle_id,
    v.vehicle_number,
    v.license_plate,
    fc.trip_id,
    t.trip_number,
    fc.period_start,
    fc.period_end,
    fc.gallons_consumed,
    fc.miles_driven,
    fc.mpg,
    fc.idle_time_minutes,
    fc.cost_total,
    fc.cost_per_mile
   FROM ((log.fuel_consumption fc
     LEFT JOIN log.vehicles v ON ((v.vehicles_id = fc.vehicle_id)))
     LEFT JOIN log.trips t ON ((t.trips_id = fc.trip_id)))
  ORDER BY fc.period_start DESC;


--
-- Name: v_in_transit; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_in_transit AS
 SELECT s.shipments_id,
    s.shipment_number,
    st.shipment_type_code,
    s.origin_city,
    s.destination_city,
    s.scheduled_delivery_date,
    c.carrier_name,
    c.scac AS carrier_scac,
    te.event_type AS latest_event,
    te.event_timestamp AS latest_event_time,
    te.city AS latest_city,
    te.latitude,
    te.longitude,
    te.event_description AS latest_message,
    (EXTRACT(epoch FROM (now() - te.event_timestamp)) / (3600)::numeric) AS hours_since_last_event
   FROM (((log.shipments s
     LEFT JOIN log.shipment_types st ON ((st.shipment_types_id = s.shipment_type_id)))
     LEFT JOIN log.carriers c ON ((c.carriers_id = s.carrier_id)))
     LEFT JOIN LATERAL ( SELECT te2.event_type,
            te2.event_timestamp,
            te2.city,
            te2.latitude,
            te2.longitude,
            te2.event_description
           FROM log.tracking_events te2
          WHERE (te2.shipment_id = s.shipments_id)
          ORDER BY te2.event_timestamp DESC
         LIMIT 1) te ON (true))
  WHERE (EXISTS ( SELECT 1
           FROM log.shipment_statuses ss
          WHERE ((ss.shipment_statuses_id = s.status_id) AND ((ss.status_code)::text = 'IN_TRANSIT'::text))));


--
-- Name: v_load_profitability; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_load_profitability AS
 SELECT loads_id,
    load_number,
    status,
    actual_start,
    actual_end,
    total_miles,
    estimated_cost AS planned_cost,
    actual_cost,
    revenue,
        CASE
            WHEN ((actual_cost > (0)::numeric) AND (revenue > (0)::numeric)) THEN (((revenue - actual_cost) / actual_cost) * (100)::numeric)
            ELSE NULL::numeric
        END AS profit_margin_pct,
    COALESCE(total_miles, (0)::numeric) AS total_miles_calc,
        CASE
            WHEN (COALESCE(total_miles, (0)::numeric) > (0)::numeric) THEN ((revenue - actual_cost) / total_miles)
            ELSE (0)::numeric
        END AS profit_per_mile
   FROM log.loads l
  WHERE ((status)::text = ANY ((ARRAY['COMPLETED'::character varying, 'IN_TRANSIT'::character varying])::text[]))
  ORDER BY actual_end DESC NULLS LAST;


--
-- Name: v_on_time_delivery; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_on_time_delivery AS
 SELECT date_trunc('month'::text, s.actual_delivery_date) AS month,
    s.carrier_id,
    c.carrier_name,
    count(*) AS total_deliveries,
    count(*) FILTER (WHERE (s.actual_delivery_date <= s.scheduled_delivery_date)) AS on_time_count,
    round(((100.0 * (count(*) FILTER (WHERE (s.actual_delivery_date <= s.scheduled_delivery_date)))::numeric) / (NULLIF(count(*), 0))::numeric), 1) AS on_time_pct
   FROM (log.shipments s
     LEFT JOIN log.carriers c ON ((c.carriers_id = s.carrier_id)))
  WHERE (s.actual_delivery_date IS NOT NULL)
  GROUP BY (date_trunc('month'::text, s.actual_delivery_date)), s.carrier_id, c.carrier_name;


--
-- Name: v_open_claims; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_open_claims AS
 SELECT c.claims_id,
    c.claim_number,
    c.shipment_id,
    s.shipment_number,
    c.claim_type,
    c.description AS claim_reason,
    c.claim_date,
    c.amount_claimed,
    c.amount_settled,
    c.amount_paid,
    c.currency,
    c.status,
    c.carrier_id,
    cr.carrier_name,
    c.resolution_notes,
    c.created_at
   FROM ((log.claims c
     LEFT JOIN log.shipments s ON ((s.shipments_id = c.shipment_id)))
     LEFT JOIN log.carriers cr ON ((cr.carriers_id = c.carrier_id)))
  WHERE ((c.status)::text <> ALL ((ARRAY['CLOSED'::character varying, 'PAID'::character varying])::text[]));


--
-- Name: v_real_time_tracking; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_real_time_tracking AS
 SELECT s.shipments_id,
    s.shipment_number,
    st.shipment_type_code,
    s.origin_city,
    s.destination_city,
    c.carrier_name,
    c.scac AS carrier_scac,
    te.event_type,
    te.event_timestamp,
    te.latitude,
    te.longitude,
    te.city,
    te.event_description AS message,
    te.source AS event_source,
    ss.status_code AS shipment_status_code
   FROM ((((log.shipments s
     LEFT JOIN log.shipment_types st ON ((st.shipment_types_id = s.shipment_type_id)))
     LEFT JOIN log.carriers c ON ((c.carriers_id = s.carrier_id)))
     LEFT JOIN log.shipment_statuses ss ON ((ss.shipment_statuses_id = s.status_id)))
     LEFT JOIN LATERAL ( SELECT te2.event_type,
            te2.event_timestamp,
            te2.latitude,
            te2.longitude,
            te2.city,
            te2.event_description,
            te2.source
           FROM log.tracking_events te2
          WHERE (te2.shipment_id = s.shipments_id)
          ORDER BY te2.event_timestamp DESC
         LIMIT 1) te ON (true))
  WHERE ((s.actual_delivery_date IS NULL) AND ((ss.status_code)::text <> ALL ((ARRAY['COMPLETED'::character varying, 'CANCELLED'::character varying])::text[])))
  ORDER BY s.created_at DESC;


--
-- Name: v_shipment_dashboard; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_shipment_dashboard AS
 SELECT s.shipments_id,
    s.shipment_number,
    st.shipment_type_code,
    st.shipment_type_name,
    ss.status_code AS shipment_status_code,
    ss.status_name AS shipment_status_name,
    c.carrier_name,
    c.scac AS carrier_scac,
    s.origin_city,
    s.origin_state,
    s.origin_country,
    s.destination_city,
    s.destination_state,
    s.destination_country,
    s.requested_pickup_date,
    s.requested_delivery_date,
    s.scheduled_pickup_date,
    s.scheduled_delivery_date,
    s.actual_pickup_date,
    s.actual_delivery_date,
    s.total_weight,
    s.total_pieces,
    s.estimated_cost,
    s.actual_cost,
    s.is_hazmat,
    s.created_at,
    s.updated_at
   FROM (((log.shipments s
     LEFT JOIN log.shipment_types st ON ((st.shipment_types_id = s.shipment_type_id)))
     LEFT JOIN log.shipment_statuses ss ON ((ss.shipment_statuses_id = s.status_id)))
     LEFT JOIN log.carriers c ON ((c.carriers_id = s.carrier_id)));


--
-- Name: v_trip_manifest; Type: VIEW; Schema: log; Owner: -
--

CREATE VIEW log.v_trip_manifest AS
 SELECT t.trips_id,
    t.trip_number,
    t.status,
    t.scheduled_departure,
    t.scheduled_arrival,
    t.actual_departure,
    t.actual_arrival,
    v.vehicle_number,
    v.license_plate,
    v.vehicle_type_id,
    ts.trip_stops_id AS stop_id,
    ts.stop_sequence,
    ts.stop_type,
    ts.status AS stop_status,
    ts.actual_arrival AS stop_actual_arrival,
    ts.city
   FROM ((log.trips t
     LEFT JOIN log.vehicles v ON ((v.vehicles_id = t.vehicle_id)))
     LEFT JOIN log.trip_stops ts ON ((ts.trip_id = t.trips_id)))
  ORDER BY t.trips_id, ts.stop_sequence;


