--
-- Name: v_ai_orchestration_status; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_ai_orchestration_status AS
 SELECT aws.state_id,
    aws.workflow_type,
    aws.entity_type,
    aws.entity_id,
    aws.workflow_status,
    aws.started_date,
    aws.completed_date,
    aws.retry_count,
    aws.max_retries,
    aws.error_message,
    al.log_id,
    al.agent_name,
    al.agent_action,
    al.processing_time_ms,
    al.status_code AS agent_status,
    al.error_message AS agent_error
   FROM (mdm.ai_workflow_state aws
     LEFT JOIN mdm.ai_agent_logs al ON ((aws.state_id = al.state_id)));


--
-- Name: v_bom_explosion; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_bom_explosion AS
 WITH RECURSIVE bom_expl AS (
         SELECT bh.bom_id,
            bh.assembly_item_id,
            bh.bom_name,
            bh.bom_type_code,
            1 AS level,
            bc.component_id,
            bc.component_item_id,
            bc.quantity_per_assembly,
            bc.component_uom_code,
            bc.operation_sequence,
            ARRAY[bh.assembly_item_id] AS path,
            false AS is_circular
           FROM (mdm.bom_headers bh
             JOIN mdm.bom_components bc ON ((bh.bom_id = bc.bom_id)))
        UNION ALL
         SELECT bh.bom_id,
            bh.assembly_item_id,
            bh.bom_name,
            bh.bom_type_code,
            (bex.level + 1) AS level,
            bc.component_id,
            bc.component_item_id,
            bc.quantity_per_assembly,
            bc.component_uom_code,
            bc.operation_sequence,
            (bex.path || bh.assembly_item_id) AS path,
            (bh.assembly_item_id = ANY (bex.path)) AS is_circular
           FROM ((bom_expl bex
             JOIN mdm.bom_headers bh ON ((bex.component_item_id = bh.assembly_item_id)))
             JOIN mdm.bom_components bc ON ((bh.bom_id = bc.bom_id)))
          WHERE (NOT bex.is_circular)
        )
 SELECT bom_id,
    assembly_item_id,
    bom_name,
    bom_type_code,
    level,
    component_id,
    component_item_id,
    quantity_per_assembly,
    component_uom_code,
    operation_sequence,
    path,
    is_circular
   FROM bom_expl;


--
-- Name: v_bom_where_used; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_bom_where_used AS
 WITH RECURSIVE where_used AS (
         SELECT bc.component_item_id AS component_id,
            bh.assembly_item_id AS parent_assembly_id,
            bh.bom_id,
            bh.bom_name,
            bc.quantity_per_assembly,
            1 AS level,
            ARRAY[bc.component_item_id] AS path,
            false AS is_circular
           FROM (mdm.bom_components bc
             JOIN mdm.bom_headers bh ON ((bc.bom_id = bh.bom_id)))
        UNION ALL
         SELECT wu.component_id,
            bh.assembly_item_id,
            bh.bom_id,
            bh.bom_name,
            wu.quantity_per_assembly,
            (wu.level + 1) AS level,
            (wu.path || bh.assembly_item_id) AS path,
            (bh.assembly_item_id = ANY (wu.path)) AS is_circular
           FROM ((where_used wu
             JOIN mdm.bom_components bc ON ((wu.parent_assembly_id = bc.component_item_id)))
             JOIN mdm.bom_headers bh ON ((bc.bom_id = bh.bom_id)))
          WHERE (NOT wu.is_circular)
        )
 SELECT component_id,
    parent_assembly_id,
    bom_id,
    bom_name,
    quantity_per_assembly,
    level,
    path,
    is_circular
   FROM where_used;


--
-- Name: v_category_hierarchy; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_category_hierarchy AS
 SELECT c.category_id,
    c.category_code,
    c.category_name,
    cs.name AS category_set,
    c.parent_category_id,
    pc.category_code AS parent_category_code,
    pc.category_name AS parent_category_name,
    c.hierarchy_path,
    public.nlevel(c.hierarchy_path) AS hierarchy_level
   FROM ((mdm.categories c
     JOIN mdm.category_sets cs ON (((c.category_set_code)::text = (cs.category_set_code)::text)))
     LEFT JOIN mdm.categories pc ON ((c.parent_category_id = pc.category_id)));


--
-- Name: v_compliance_status; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_compliance_status AS
 SELECT i.item_number,
    i.item_name,
    i.rohs_compliant,
    i.reach_compliant,
    i.fda_approved,
    i.ce_marked,
    i.ul_listed,
    cc.certificate_number,
    cc.issuing_body,
    cc.issue_date,
    cc.expiration_date,
        CASE
            WHEN (cc.expiration_date IS NULL) THEN 'NO_EXPIRY'::text
            WHEN (cc.expiration_date < CURRENT_DATE) THEN 'EXPIRED'::text
            WHEN (cc.expiration_date < (CURRENT_DATE + '90 days'::interval)) THEN 'EXPIRING_SOON'::text
            ELSE 'VALID'::text
        END AS cert_status
   FROM (mdm.items i
     LEFT JOIN mdm.compliance_certificates cc ON ((i.item_id = cc.item_id)));


--
-- Name: v_eco_pending_approval; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_eco_pending_approval AS
 SELECT eco_number,
    eco_title,
    priority_code,
    status_code,
    target_completion,
    effective_from_date,
    effective_to_date,
    cost_impact,
    schedule_impact_days
   FROM mdm.eng_ecos e
  WHERE ((status_code)::text = ANY ((ARRAY['PENDING_APPROVAL'::character varying, 'SUBMITTED'::character varying, 'UNDER_REVIEW'::character varying])::text[]));


--
-- Name: v_ecr_open; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_ecr_open AS
 SELECT e.ecr_number,
    e.ecr_title,
    e.description,
    e.ecr_type_code,
    e.priority_code,
    e.justification_code,
    e.requestor_id,
    e.status_code,
    e.target_completion_date,
    e.completion_date,
    i.item_number,
    i.item_name
   FROM (mdm.eng_ecrs e
     LEFT JOIN mdm.items i ON ((e.item_id = i.item_id)))
  WHERE ((e.status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying, 'IMPLEMENTED'::character varying])::text[]));


--
-- Name: v_effectivity_report; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_effectivity_report AS
 SELECT rule_id,
    entity_type,
    entity_id,
    effectivity_type,
    effective_from_date,
    effective_to_date,
    from_unit,
    to_unit,
    from_serial,
    to_serial,
    lot_number_from,
    lot_number_to,
    priority,
        CASE
            WHEN (((effectivity_type)::text = 'DATE'::text) AND (effective_from_date IS NOT NULL) AND ((effective_to_date IS NULL) OR (effective_to_date >= CURRENT_DATE))) THEN 'EFFECTIVE'::text
            WHEN (((effectivity_type)::text = 'DATE'::text) AND (effective_to_date < CURRENT_DATE)) THEN 'EXPIRED'::text
            WHEN (((effectivity_type)::text = 'DATE'::text) AND (effective_from_date > CURRENT_DATE)) THEN 'FUTURE'::text
            ELSE 'UNKNOWN'::text
        END AS current_effectivity_status
   FROM mdm.effectivity_rules er;


--
-- Name: v_item_categories; Type: VIEW; Schema: mdm; Owner: -
