    c.category_name,
    cs.name AS category_set,
    ica.primary_flag
   FROM (((mdm.item_category_assignments ica
     JOIN mdm.items i ON ((ica.item_id = i.item_id)))
     JOIN mdm.categories c ON ((ica.category_id = c.category_id)))
     JOIN mdm.category_sets cs ON (((ica.category_set_code)::text = (cs.category_set_code)::text)));


--
-- Name: v_item_lifecycle_status; Type: VIEW; Schema: mdm; Owner: -
