    lch.to_phase_code,
    lch.transition_date,
    lch.reason
   FROM ((mdm.items i
     JOIN mdm.lifecycle_phases lp ON (((i.lifecycle_phase_code)::text = (lp.phase_code)::text)))
     LEFT JOIN mdm.item_lifecycle_history lch ON ((i.item_id = lch.item_id)));


