    i.primary_uom_code AS primary_uom,
    i.make_buy_code AS make_buy,
    lp.name AS lifecycle_phase,
    i.is_active
   FROM (((mdm.items i
     LEFT JOIN mdm.item_types it ON (((i.item_type_code)::text = (it.item_type_code)::text)))
     LEFT JOIN mdm.item_statuses ist ON (((i.item_status_code)::text = (ist.item_status_code)::text)))
     LEFT JOIN mdm.lifecycle_phases lp ON (((i.lifecycle_phase_code)::text = (lp.phase_code)::text)));


