--
-- Name: v_uom_conversion_summary; Type: VIEW; Schema: mdm; Owner: -
--

CREATE VIEW mdm.v_uom_conversion_summary AS
 SELECT uc.uom_conversion_id,
    ucl.name AS uom_class,
    u_from.uom_code AS from_uom_code,
    u_from.name AS from_uom_name,
    u_to.uom_code AS to_uom_code,
    u_to.name AS to_uom_name,
    uc.conversion_factor,
    uc.inverse_factor
   FROM (((mdm.uom_conversions uc
     JOIN mdm.uom_classes ucl ON (((uc.uom_class_code)::text = (ucl.uom_class_code)::text)))
     JOIN mdm.uoms u_from ON (((uc.from_uom_code)::text = (u_from.uom_code)::text)))
     JOIN mdm.uoms u_to ON (((uc.to_uom_code)::text = (u_to.uom_code)::text)));


