--
-- Name: mes_dashboard_oee_summary; Type: VIEW; Schema: mes; Owner: -
--

CREATE VIEW mes.mes_dashboard_oee_summary AS
 SELECT e.equipment_code,
    e.equipment_name,
    wc.center_code AS work_center,
    o.calculation_date,
    o.oee_pct,
    o.availability_pct,
    o.performance_pct,
    o.quality_pct,
    o.total_parts,
    o.good_parts,
    o.defect_parts,
    o.downtime_min,
    ot.oee_target,
    (o.oee_pct - ot.oee_target) AS gap
   FROM (((mes.mes_oee_calculations o
     JOIN mes.mes_equipment e ON ((e.equipment_id = o.equipment_id)))
     LEFT JOIN mes.mes_work_centers wc ON ((wc.work_center_id = o.work_center_id)))
     LEFT JOIN mes.mes_oee_targets ot ON (((ot.equipment_id = e.equipment_id) AND (ot.effective_from <= o.calculation_date) AND ((ot.effective_until IS NULL) OR (ot.effective_until >= o.calculation_date)))))
  ORDER BY o.calculation_date DESC, o.oee_pct;


