--
-- Name: mes_dashboard_quality_alerts; Type: VIEW; Schema: mes; Owner: -
--

CREATE VIEW mes.mes_dashboard_quality_alerts AS
 SELECT a.alert_id,
    a.alert_type,
    a.severity,
    a.title,
    a.message,
    a.status,
    a.alert_time,
    a.assigned_to,
    concat(op.first_name, ' ', op.last_name) AS assigned_name,
    a.escalation_level,
        CASE
            WHEN ((a.alert_time < (now() - '01:00:00'::interval)) AND ((a.status)::text = 'ACTIVE'::text)) THEN 'OVERDUE'::text
            WHEN ((a.alert_time < (now() - '00:30:00'::interval)) AND ((a.status)::text = 'ACTIVE'::text)) THEN 'PENDING'::text
            ELSE 'ON_TIME'::text
        END AS response_status
   FROM (mes.mes_alerts a
     LEFT JOIN mes.mes_operators op ON ((op.operator_id = a.assigned_to)))
  WHERE ((a.alert_type)::text = ANY ((ARRAY['QUALITY'::character varying, 'EQUIPMENT'::character varying, 'MATERIAL'::character varying])::text[]))
  ORDER BY a.severity DESC, a.alert_time DESC;


--
-- Name: mes_work_order_execution; Type: TABLE; Schema: mes; Owner: -
--

CREATE TABLE mes.mes_work_order_execution (
    execution_id uuid DEFAULT uuidv7() NOT NULL,
