    work_order_number character varying(50),
    status character varying(30) DEFAULT 'QUEUED'::character varying,
    priority character varying(20) DEFAULT 'MEDIUM'::character varying,
    product_id uuid,
    product_code character varying(50),
    product_name character varying(200),
    planned_qty numeric(14,4) NOT NULL,
    started_qty numeric(14,4) DEFAULT 0,
    completed_qty numeric(14,4) DEFAULT 0,
    scrapped_qty numeric(14,4) DEFAULT 0,
    rework_qty numeric(14,4) DEFAULT 0,
    bom_revision character varying(20),
    routing_revision character varying(20),
    scheduled_start timestamp with time zone,
    scheduled_end timestamp with time zone,
    actual_start timestamp with time zone,
    actual_end timestamp with time zone,
    due_date date,
    project_id uuid,
    project_code character varying(50),
    notes text,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    object_version_number integer DEFAULT 1,
    corporate_id uuid,
    company_id uuid,
    site_id uuid
);

ALTER TABLE ONLY mes.mes_work_order_execution FORCE ROW LEVEL SECURITY;


--
-- Name: mes_dashboard_work_order_progress; Type: VIEW; Schema: mes; Owner: -
--

CREATE VIEW mes.mes_dashboard_work_order_progress AS
 SELECT execution_id,
    work_order_number,
    product_code,
    product_name,
    status,
    priority,
    planned_qty,
    completed_qty,
    scrapped_qty,
    scheduled_start,
    scheduled_end,
    actual_start,
    actual_end,
    due_date,
        CASE
            WHEN ((status)::text = 'COMPLETED'::text) THEN 100.00
            WHEN (planned_qty > (0)::numeric) THEN (((completed_qty / planned_qty) * (100)::numeric))::numeric(5,2)
            ELSE (0)::numeric
        END AS completion_pct,
        CASE
            WHEN ((due_date < CURRENT_DATE) AND ((status)::text <> ALL ((ARRAY['COMPLETED'::character varying, 'CLOSED'::character varying])::text[]))) THEN 'OVERDUE'::text
            WHEN ((scheduled_end < now()) AND ((status)::text <> ALL ((ARRAY['COMPLETED'::character varying, 'CLOSED'::character varying])::text[]))) THEN 'BEHIND'::text
            WHEN ((status)::text = 'ON_HOLD'::text) THEN 'HELD'::text
            ELSE 'ON_TRACK'::text
        END AS schedule_status
   FROM mes.mes_work_order_execution wo
  WHERE (is_active = true)
  ORDER BY
        CASE status
            WHEN 'IN_PROGRESS'::text THEN 1
            WHEN 'QUEUED'::text THEN 2
            WHEN 'ON_HOLD'::text THEN 3
            ELSE 4
        END, due_date;


