CREATE MATERIALIZED VIEW mes.mv_machine_telemetry_latest AS
 SELECT DISTINCT ON (t.work_center_id) t.work_center_id,
    wc.center_code,
    t.telemetry_id,
    t.metric_name,
    t.metric_value,
    t.metric_text,
    t.recorded_at
   FROM (mes.machine_telemetry t
     JOIN mes.work_centers wc ON ((wc.work_center_id = t.work_center_id)))
  ORDER BY t.work_center_id, t.recorded_at DESC
  WITH NO DATA;


