   FROM (mes.work_centers wc
     LEFT JOIN mes.job_orders jo ON (((jo.work_center_id = wc.work_center_id) AND ((jo.job_status)::text <> ALL ((ARRAY['COMPLETED'::character varying, 'CANCELLED'::character varying])::text[])))));


