--
-- Name: v_ai_orchestration_status; Type: VIEW; Schema: om; Owner: -
--

CREATE VIEW om.v_ai_orchestration_status AS
 SELECT s.state_id,
    s.order_id,
    h.so_number,
    s.workflow_def_id,
    wd.workflow_name,
    s.thread_id,
    s.status AS workflow_status,
    s.checkpoint,
    s.state_data,
    s.created_at AS state_created_at,
    s.updated_at AS state_updated_at,
    count(l.log_id) AS agent_call_count,
    max(l.created_at) AS last_agent_activity
   FROM (((om.ai_workflow_state s
     JOIN om.om_headers h ON ((h.so_id = s.order_id)))
     LEFT JOIN om.workflow_definitions wd ON ((wd.workflow_def_id = s.workflow_def_id)))
     LEFT JOIN om.ai_agent_logs l ON ((l.state_id = s.state_id)))
  WHERE (s.is_active = true)
  GROUP BY s.state_id, s.order_id, h.so_number, s.workflow_def_id, wd.workflow_name, s.thread_id, s.status, s.checkpoint, s.state_data, s.created_at, s.updated_at
  ORDER BY s.created_at DESC;


--
-- Name: v_order_line_details; Type: VIEW; Schema: om; Owner: -
--

CREATE VIEW om.v_order_line_details AS
 SELECT l.so_line_id,
    l.so_id,
    h.so_number,
    l.line_num,
    l.item_id,
    i.item_number,
    i.description AS item_description,
    l.line_description,
    l.uom_code,
    l.qty_ordered,
    l.unit_price,
    (l.qty_ordered * l.unit_price) AS line_total,
    l.discount_pct,
    l.discount_amount,
    ((l.qty_ordered * l.unit_price) - COALESCE(l.discount_amount, (0)::numeric)) AS net_amount,
    l.need_by_date,
    l.promised_date,
    l.line_type_id,
    lt.line_type_name,
    l.taxable_flag
   FROM (((om.om_lines l
     JOIN om.om_headers h ON ((h.so_id = l.so_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = l.item_id)))
     LEFT JOIN om.line_types lt ON ((lt.line_type_id = l.line_type_id)));


--
-- Name: v_order_summary; Type: VIEW; Schema: om; Owner: -
--

CREATE VIEW om.v_order_summary AS
 SELECT h.so_id,
    h.so_number,
    h.order_date,
    h.status,
    h.currency_code,
    h.order_type_id,
    ot.order_type_name,
    h.customer_id,
    p.legal_name AS customer_name,
    h.salesperson_id,
    h.requested_ship_date,
    h.promised_delivery_date,
    h.description,
    sum(((l.qty_ordered * l.unit_price) - COALESCE(l.discount_amount, (0)::numeric))) AS total_amount,
    sum(COALESCE(l.discount_amount, (0)::numeric)) AS total_discount,
    count(l.so_line_id) AS line_count
   FROM (((om.om_headers h
     LEFT JOIN om.om_lines l ON ((l.so_id = h.so_id)))
     LEFT JOIN om.order_types ot ON ((ot.order_type_id = h.order_type_id)))
     LEFT JOIN core.partners p ON ((p.partner_id = h.customer_id)))
  GROUP BY h.so_id, h.so_number, h.order_date, h.status, h.currency_code, h.order_type_id, ot.order_type_name, h.customer_id, p.legal_name, h.salesperson_id, h.requested_ship_date, h.promised_delivery_date, h.description;


--
-- Name: v_so_summary; Type: VIEW; Schema: om; Owner: -
--

CREATE VIEW om.v_so_summary AS
 SELECT h.so_id,
    h.so_number,
    h.order_date,
    h.status,
    sum((l.qty_ordered * l.unit_price)) AS total_amount,
    count(l.so_line_id) AS line_count
   FROM (om.om_headers h
     LEFT JOIN om.om_lines l ON ((l.so_id = h.so_id)))
  GROUP BY h.so_id, h.so_number, h.order_date, h.status;


--
-- Name: wms_task_queue; Type: TABLE; Schema: om; Owner: -
--

CREATE TABLE om.wms_task_queue (
    queue_id uuid DEFAULT uuidv7() NOT NULL,
    order_line_id uuid NOT NULL,
    item_id uuid,
    qty_required numeric(14,4) NOT NULL,
    qty_picked numeric(14,4) DEFAULT 0,
    qty_shipped numeric(14,4) DEFAULT 0,
    source_warehouse_id uuid,
    dest_warehouse_id uuid,
    priority integer DEFAULT 5,
    status character varying(30) DEFAULT 'PENDING'::character varying,
    assigned_to character varying(100),
    notes text,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    object_version_number integer DEFAULT 1,
    corporate_id uuid,
    company_id uuid,
    site_id uuid,
    CONSTRAINT wms_task_queue_status_check CHECK (((status)::text = ANY ((ARRAY['PENDING'::character varying, 'IN_PROGRESS'::character varying, 'PICKED'::character varying, 'SHIPPED'::character varying, 'CANCELLED'::character varying])::text[])))
);

ALTER TABLE ONLY om.wms_task_queue FORCE ROW LEVEL SECURITY;


--
-- Name: v_wms_task_queue; Type: VIEW; Schema: om; Owner: -
--

CREATE VIEW om.v_wms_task_queue AS
 SELECT q.queue_id,
    q.order_line_id,
    l.so_id AS order_id,
    h.so_number,
    l.line_num,
    q.item_id,
    i.item_number,
    i.description AS item_description,
    q.qty_required,
    q.qty_picked,
    q.qty_shipped,
    (q.qty_required - q.qty_picked) AS qty_remaining,
    q.source_warehouse_id,
    w.warehouse_code AS source_warehouse_code,
    q.priority,
    q.status,
    q.assigned_to,
    q.notes,
    q.created_at,
    q.updated_at
   FROM ((((om.wms_task_queue q
     JOIN om.om_lines l ON ((l.so_line_id = q.order_line_id)))
     JOIN om.om_headers h ON ((h.so_id = l.so_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = q.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = q.source_warehouse_id)))
  WHERE (q.is_active = true)
  ORDER BY q.priority, q.created_at;


