--
-- Name: v_ai_orchestration_status; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_ai_orchestration_status AS
 SELECT s.state_id,
    s.doc_id,
    s.doc_type,
    s.workflow_def_id,
    s.thread_id,
    s.status AS workflow_status,
    s.checkpoint,
    s.state_data,
    s.created_at,
    s.updated_at,
    count(l.log_id) AS agent_call_count,
    max(l.created_at) AS last_agent_activity
   FROM (po.ai_workflow_state s
     LEFT JOIN po.ai_agent_logs l ON ((l.state_id = s.state_id)))
  WHERE (s.is_active = true)
  GROUP BY s.state_id, s.doc_id, s.doc_type, s.workflow_def_id, s.thread_id, s.status, s.checkpoint, s.state_data, s.created_at, s.updated_at
  ORDER BY s.created_at DESC;


--
-- Name: v_approval_pending; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_approval_pending AS
 SELECT ah.history_id,
    ah.source_doc_type,
    ah.source_doc_id,
    ah.approval_level,
    ah.approver_id,
    ah.status AS approval_status,
    ah.created_at AS requested_at,
        CASE ah.source_doc_type
            WHEN 'PR'::text THEN (pr.pr_number)::text
            WHEN 'PO'::text THEN (h.po_number)::text
            ELSE (ah.source_doc_id)::text
        END AS doc_number,
        CASE ah.source_doc_type
            WHEN 'PR'::text THEN pr.description
            WHEN 'PO'::text THEN h.description
            ELSE NULL::text
        END AS doc_description,
        CASE ah.source_doc_type
            WHEN 'PR'::text THEN pr.status
            WHEN 'PO'::text THEN h.status
            ELSE NULL::character varying
        END AS doc_status
   FROM ((po.approval_history ah
     LEFT JOIN po.pr_headers pr ON ((((ah.source_doc_type)::text = 'PR'::text) AND (pr.pr_id = ah.source_doc_id))))
     LEFT JOIN po.po_headers h ON ((((ah.source_doc_type)::text = 'PO'::text) AND (h.po_id = ah.source_doc_id))))
  WHERE (((ah.status)::text = 'PENDING'::text) AND (ah.is_active = true))
  ORDER BY ah.created_at;


--
-- Name: v_po_line_details; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_po_line_details AS
 SELECT l.po_line_id,
    l.po_id,
    h.po_number,
    l.line_num,
    l.item_id,
    i.item_number,
    i.description AS item_description,
    l.line_description,
    l.uom_code,
    l.qty_ordered,
    l.unit_price,
    (l.qty_ordered * l.unit_price) AS line_total,
    l.need_by_date,
    l.promised_date,
    l.line_type,
    l.line_status,
    l.taxable_flag
   FROM ((po.po_lines l
     JOIN po.po_headers h ON ((h.po_id = l.po_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = l.item_id)));


--
-- Name: v_po_shipment_details; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_po_shipment_details AS
 SELECT s.po_shipment_id,
    s.po_id,
    h.po_number,
    s.po_line_id,
    l.line_num,
    i.item_number,
    i.description AS item_description,
    s.shipment_num,
    s.ship_to_warehouse_id,
    w.warehouse_code,
    w.warehouse_name,
    s.qty_ordered,
    s.qty_received,
    s.qty_accepted,
    s.qty_rejected,
    s.qty_billed,
    COALESCE(s.unit_price, l.unit_price) AS effective_price,
    (s.qty_ordered * COALESCE(s.unit_price, l.unit_price)) AS shipment_total,
    s.need_by_date,
    s.promised_date,
    s.expected_receipt_date,
    s.actual_arrival_date,
    s.closed_code,
    s.status
   FROM ((((po.po_shipments s
     JOIN po.po_headers h ON ((h.po_id = s.po_id)))
     JOIN po.po_lines l ON ((l.po_line_id = s.po_line_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = l.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = s.ship_to_warehouse_id)));


--
-- Name: v_po_summary; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_po_summary AS
 SELECT h.po_id,
    h.po_number,
    h.po_type,
    h.description,
    h.order_date,
    h.status,
    h.currency_code,
    h.buyer_id,
    h.ship_to_warehouse_id,
    h.approved_by,
    h.approved_at,
    h.revision_num,
    p.legal_name AS supplier_name,
    p.partner_code AS supplier_code,
    sum((l.qty_ordered * l.unit_price)) AS total_amount,
    count(l.po_line_id) AS line_count
   FROM ((po.po_headers h
     LEFT JOIN po.po_lines l ON ((l.po_id = h.po_id)))
     LEFT JOIN core.partners p ON ((p.partner_id = h.supplier_id)))
  GROUP BY h.po_id, h.po_number, h.po_type, h.description, h.order_date, h.status, h.currency_code, h.buyer_id, h.ship_to_warehouse_id, h.approved_by, h.approved_at, h.revision_num, p.legal_name, p.partner_code;


--
-- Name: v_po_suppliers; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_po_suppliers AS
 SELECT a.partner_id,
    a.po_supplier_code AS supplier_code,
    a.supplier_type,
    a.supplier_status AS status,
    a.payment_term_days,
    a.payment_method,
    a.default_currency,
    a.min_order_amount,
    a.max_order_amount,
    a.tax_registration_number,
    a.ship_via,
    a.fob_point,
    a.quality_rating,
    a.on_time_delivery_rate,
    a.approval_status,
    a.approved_by,
    a.approved_at,
    a.notes,
    a.is_active,
    a.created_at,
    a.updated_at,
    a.update_by,
    p.partner_code,
    p.legal_name,
    p.trade_name
   FROM (ap.ap_suppliers a
     JOIN core.partners p ON ((p.partner_id = a.partner_id)));


--
-- Name: v_supplier_performance; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_supplier_performance AS
 SELECT sp.performance_id,
    sp.partner_id,
    p.legal_name AS supplier_name,
    p.partner_code,
    sp.period_name,
    sp.on_time_rate,
    sp.quality_rate,
    sp.defect_rate,
    sp.lead_time_days,
    sp.response_time_hours,
    sp.rating,
    sp.created_at
   FROM (po.supplier_performance sp
     JOIN core.partners p ON ((p.partner_id = sp.partner_id)))
  WHERE (sp.is_active = true)
  ORDER BY sp.period_name DESC, sp.rating;


--
-- Name: v_wms_receiving_queue; Type: VIEW; Schema: po; Owner: -
--

CREATE VIEW po.v_wms_receiving_queue AS
 SELECT rh.receipt_id,
    rh.receipt_number,
    rh.po_id,
    h.po_number,
    h.supplier_id,
    rl.receipt_line_id,
    rl.po_line_id,
    l.line_num,
    l.line_description,
    rl.item_id,
    i.item_number,
    i.description AS item_description,
    rl.qty_received AS qty_expected,
    rl.qty_accepted,
    rl.qty_rejected,
    ((rl.qty_received - rl.qty_accepted) - rl.qty_rejected) AS qty_pending_inspection,
    rl.lot_number,
    rl.serial_number,
    rh.warehouse_id,
    w.warehouse_code,
    rh.receipt_date,
    rh.status,
    rh.carrier_info,
    rh.created_at
   FROM (((((po.receiving_headers rh
     JOIN po.po_headers h ON ((h.po_id = rh.po_id)))
     JOIN po.receiving_lines rl ON ((rl.receipt_id = rh.receipt_id)))
     LEFT JOIN po.po_lines l ON ((l.po_line_id = rl.po_line_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = rl.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = rh.warehouse_id)))
  WHERE (rh.is_active = true)
  ORDER BY rh.created_at;


