--
-- Name: mv_production_progress; Type: MATERIALIZED VIEW; Schema: prod; Owner: -
--

CREATE MATERIALIZED VIEW prod.mv_production_progress AS
 SELECT wo.wo_id,
    wo.wo_number,
    wo.qty_target,
    wo.status,
    COALESCE(sum(jo.qty_produced), (0)::numeric) AS qty_produced,
    COALESCE(sum(jo.qty_scrap), (0)::numeric) AS qty_scrap,
        CASE
            WHEN (wo.qty_target > (0)::numeric) THEN round(((COALESCE(sum(jo.qty_produced), (0)::numeric) / wo.qty_target) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS completion_pct
   FROM (prod.prod_work_orders wo
     LEFT JOIN mes.job_orders jo ON ((jo.wo_id = wo.wo_id)))
  GROUP BY wo.wo_id, wo.wo_number, wo.qty_target, wo.status
  WITH NO DATA;


