--
-- Name: mv_inspection_pass_rate; Type: MATERIALIZED VIEW; Schema: qc; Owner: -
--

CREATE MATERIALIZED VIEW qc.mv_inspection_pass_rate AS
 SELECT ip.plan_name,
    io.disposition,
    count(*) AS total_inspections,
    count(*) FILTER (WHERE ((io.disposition)::text = 'PASS'::text)) AS passed,
    count(*) FILTER (WHERE ((io.disposition)::text = 'REJECT'::text)) AS rejected,
    count(*) FILTER (WHERE ((io.disposition)::text = 'REWORK'::text)) AS reworked,
    round((((count(*) FILTER (WHERE ((io.disposition)::text = 'PASS'::text)))::numeric * 100.0) / (NULLIF(count(*), 0))::numeric), 2) AS pass_rate_pct
   FROM (qc.inspection_orders io
     LEFT JOIN qc.inspection_plans ip ON ((ip.plan_id = io.plan_id)))
  WHERE ((io.status)::text = 'COMPLETED'::text)
  GROUP BY ip.plan_name, io.disposition
  WITH NO DATA;


