--
-- Name: v_inspection_status; Type: VIEW; Schema: qc; Owner: -
--

CREATE VIEW qc.v_inspection_status AS
 SELECT io.inspection_id,
    io.source_type,
    io.lot_number,
    io.total_qty,
    io.sample_qty,
    io.status,
    io.disposition,
    io.inspected_at,
    ip.plan_name,
    ip.version AS plan_version,
    i.item_number,
    i.description
   FROM ((qc.inspection_orders io
     LEFT JOIN qc.inspection_plans ip ON ((ip.plan_id = io.plan_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = io.item_id)));


--
-- Name: v_qc_audit_schedule; Type: VIEW; Schema: qc; Owner: -
--

CREATE VIEW qc.v_qc_audit_schedule AS
 SELECT audit_id,
    audit_number,
    audit_title,
    audit_type_code,
    audit_standard_code,
    audit_status_code,
    scope_description,
    lead_auditor_name,
    planned_start_date,
    planned_end_date,
    actual_start_date,
    actual_end_date,
    overall_score,
    finding_count_critical,
    finding_count_major,
    finding_count_minor,
    finding_count_observation,
    organization_id,
    creation_date,
    is_active,
    tenant_id,
        CASE
            WHEN (((audit_status_code)::text = 'PLANNED'::text) AND (planned_start_date <= (CURRENT_DATE + '30 days'::interval))) THEN 'UPCOMING'::character varying
            WHEN (((audit_status_code)::text = 'PLANNED'::text) AND (planned_start_date > (CURRENT_DATE + '30 days'::interval))) THEN 'FUTURE'::character varying
            WHEN ((audit_status_code)::text = 'IN_PROGRESS'::text) THEN 'IN_PROGRESS'::character varying
            WHEN ((audit_status_code)::text = 'COMPLETED'::text) THEN 'COMPLETED'::character varying
            ELSE audit_status_code
        END AS schedule_status
   FROM qc.qc_audits a
  WHERE ((is_active)::text = 'Y'::text)
  ORDER BY planned_start_date;


