--
-- Name: v_qc_cost_of_quality; Type: VIEW; Schema: qc; Owner: -
--

CREATE VIEW qc.v_qc_cost_of_quality AS
 SELECT coq_category_code,
    coq_item_code,
    sum(amount) AS total_amount,
    count(*) AS transaction_count,
    min(transaction_date) AS first_transaction_date,
    max(transaction_date) AS last_transaction_date,
    organization_id,
    department_code,
    product_line_code,
    currency_code
   FROM qc.qc_cost_of_quality
  WHERE ((is_active)::text = 'Y'::text)
  GROUP BY GROUPING SETS ((coq_category_code, coq_item_code, organization_id, department_code, product_line_code, currency_code), (coq_category_code, organization_id, currency_code), (organization_id, currency_code), ());


--
-- Name: v_qc_defect_pareto; Type: VIEW; Schema: qc; Owner: -
--

CREATE VIEW qc.v_qc_defect_pareto AS
 SELECT d_o.defect_id,
    d_m.defect_code,
    d_m.defect_name,
    d_m.defect_type_code,
    d_m.defect_severity_code,
    count(d_o.defect_occurrence_id) AS occurrence_count,
    sum(d_o.quantity) AS total_quantity,
    sum(d_o.defect_cost) AS total_cost,
    row_number() OVER (ORDER BY (count(d_o.defect_occurrence_id)) DESC) AS rank,
    round(((100.0 * (count(d_o.defect_occurrence_id))::numeric) / sum(count(d_o.defect_occurrence_id)) OVER ()), 2) AS pct_of_total,
    round(((100.0 * sum(count(d_o.defect_occurrence_id)) OVER (ORDER BY (count(d_o.defect_occurrence_id)) DESC)) / sum(count(d_o.defect_occurrence_id)) OVER ()), 2) AS cumulative_pct
   FROM (qc.qc_defect_occurrences d_o
     JOIN qc.qc_defect_master d_m ON (((d_m.defect_id = d_o.defect_id) AND ((d_m.is_active)::text = 'Y'::text))))
  WHERE ((d_o.is_active)::text = 'Y'::text)
  GROUP BY d_o.defect_id, d_m.defect_code, d_m.defect_name, d_m.defect_type_code, d_m.defect_severity_code
  ORDER BY (count(d_o.defect_occurrence_id)) DESC;


