--
-- Name: v_qc_kpi_dashboard; Type: VIEW; Schema: qc; Owner: -
--

CREATE VIEW qc.v_qc_kpi_dashboard AS
 SELECT kd.kpi_definition_id,
    kd.kpi_code,
    kd.kpi_name,
    kd.kpi_category_code,
    kd.kpi_subcategory_code,
    kd.description,
    kd.unit_of_measure,
    kd.direction_code,
    kd.target_value,
    kd.threshold_green_from,
    kd.threshold_green_to,
    kd.threshold_yellow_from,
    kd.threshold_yellow_to,
    kd.threshold_red_from,
    kd.threshold_red_to,
    ka.kpi_actual_id,
    ka.actual_value,
    ka.target_value AS actual_target,
    ka.variance,
    ka.variance_pct,
    ka.evaluation_date,
    ka.period_type_code,
    ka.period_start_date,
    ka.period_end_date,
    ka.entity_type_code,
    ka.entity_id,
        CASE
            WHEN ((ka.actual_value >= kd.threshold_green_from) AND ((kd.threshold_green_to IS NULL) OR (ka.actual_value <= kd.threshold_green_to))) THEN 'GREEN'::text
            WHEN ((ka.actual_value >= kd.threshold_yellow_from) AND ((kd.threshold_yellow_to IS NULL) OR (ka.actual_value <= kd.threshold_yellow_to))) THEN 'YELLOW'::text
            ELSE 'RED'::text
        END AS status_indicator
   FROM (qc.qc_kpi_definitions kd
     JOIN qc.qc_kpi_actuals ka ON (((ka.kpi_definition_id = kd.kpi_definition_id) AND ((ka.is_active)::text = 'Y'::text))))
  WHERE ((kd.is_active)::text = 'Y'::text);


