--
-- Name: mv_x_procure_to_pay; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_x_procure_to_pay AS
 SELECT p.po_id,
    p.po_number,
    p.order_date,
    p.status AS po_status,
    p.supplier_id,
    pt.partner_code,
    pt.legal_name AS supplier_name,
    sum((pl.qty_ordered * pl.unit_price)) AS po_total,
    ap.ap_invoice_id,
    ap.invoice_number,
    ap.amount_residual AS amount_due,
    ap.is_paid,
    mt.transaction_id AS receipt_txn_id,
    mt.qty AS receipt_qty,
    mt.transaction_date AS receipt_date
   FROM ((((po.po_headers p
     LEFT JOIN po.po_lines pl ON ((pl.po_id = p.po_id)))
     LEFT JOIN core.partners pt ON ((pt.partner_id = p.supplier_id)))
     LEFT JOIN ap.ap_invoices ap ON ((ap.po_id = p.po_id)))
     LEFT JOIN inv.material_transactions mt ON (((mt.source_doc_id = pl.po_line_id) AND ((mt.transaction_type)::text = 'PO_RECEIPT'::text))))
  GROUP BY p.po_id, p.po_number, p.order_date, p.status, p.supplier_id, pt.partner_code, pt.legal_name, ap.ap_invoice_id, ap.invoice_number, ap.amount_residual, ap.is_paid, mt.transaction_id, mt.qty, mt.transaction_date
  WITH NO DATA;


--
-- Name: v_x_customer_scorecard; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_x_customer_scorecard AS
 SELECT pt.partner_id,
    pt.partner_code,
    pt.legal_name,
    count(DISTINCT so.so_id) AS total_orders,
    COALESCE(sum((ol.qty_ordered * ol.unit_price)), (0)::numeric) AS total_order_value,
    count(DISTINCT ar.ar_invoice_id) AS total_invoices,
    COALESCE(sum(ar.amount_due), (0)::numeric) AS total_outstanding,
    count(DISTINCT ar.ar_invoice_id) FILTER (WHERE (ar.is_paid = false)) AS unpaid_invoices,
    ca.credit_limit
   FROM ((((core.partners pt
     LEFT JOIN om.om_headers so ON ((so.customer_id = pt.partner_id)))
     LEFT JOIN om.om_lines ol ON ((ol.so_id = so.so_id)))
     LEFT JOIN ar.ar_invoices ar ON ((ar.customer_id = pt.partner_id)))
     LEFT JOIN om.customer_attributes ca ON ((ca.partner_id = pt.partner_id)))
  GROUP BY pt.partner_id, pt.partner_code, pt.legal_name, ca.credit_limit;


--
-- Name: v_x_inventory_position; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_x_inventory_position AS
 SELECT b.item_id,
    i.item_number,
    i.description,
    b.warehouse_id,
    w.warehouse_code,
    w.warehouse_name,
    s.site_code,
    s.site_name,
    b.location_id,
    l.location_code,
    b.qty_onhand,
    attr.safety_stock,
    attr.reorder_point,
        CASE
            WHEN ((attr.reorder_point IS NOT NULL) AND (b.qty_onhand < attr.reorder_point)) THEN true
            ELSE false
        END AS is_low_stock
   FROM (((((inv.inv_onhand_balances b
     LEFT JOIN mdm.items i ON ((i.item_id = b.item_id)))
     LEFT JOIN core.warehouses w ON ((w.warehouse_id = b.warehouse_id)))
     LEFT JOIN core.sites s ON ((s.site_id = w.site_id)))
     LEFT JOIN core.locations l ON ((l.location_id = b.location_id)))
     LEFT JOIN inv.item_attributes attr ON ((attr.item_id = b.item_id)));


