--
-- Name: v_x_supplier_scorecard; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_x_supplier_scorecard AS
 SELECT pt.partner_id,
    pt.partner_code,
    pt.legal_name,
    count(DISTINCT p.po_id) AS total_pos,
    count(DISTINCT p.po_id) FILTER (WHERE ((p.status)::text = 'CLOSED'::text)) AS closed_pos,
    COALESCE(sum((pl.qty_ordered * pl.unit_price)), (0)::numeric) AS total_po_value,
    count(DISTINCT r.response_id) AS rfq_count,
    count(DISTINCT r.response_id) FILTER (WHERE ((r.status)::text = 'ACCEPTED'::text)) AS accepted_rfqs,
    count(DISTINCT a.asn_id) AS total_asns
   FROM ((((core.partners pt
     LEFT JOIN po.po_headers p ON ((p.supplier_id = pt.partner_id)))
     LEFT JOIN po.po_lines pl ON ((pl.po_id = p.po_id)))
     LEFT JOIN sup.rfq_responses r ON ((r.partner_id = pt.partner_id)))
     LEFT JOIN sup.shipment_advices a ON ((a.partner_id = pt.partner_id)))
  GROUP BY pt.partner_id, pt.partner_code, pt.legal_name;


