--
-- Name: mv_replenishment_recommendations; Type: MATERIALIZED VIEW; Schema: scm; Owner: -
--

CREATE MATERIALIZED VIEW scm.mv_replenishment_recommendations AS
 SELECT rp.plan_id,
    rp.item_id,
    i.item_number,
    i.description,
    rp.target_site_id,
    rp.recommended_qty,
    rp.source_type,
    rp.status,
    COALESCE(b.qty_onhand, (0)::numeric) AS current_onhand,
    COALESCE(attr.reorder_point, (0)::numeric) AS reorder_point,
        CASE
            WHEN (COALESCE(b.qty_onhand, (0)::numeric) < COALESCE(attr.reorder_point, (0)::numeric)) THEN true
            ELSE false
        END AS needs_replenish
   FROM (((scm.replenishment_plans rp
     LEFT JOIN mdm.items i ON ((i.item_id = rp.item_id)))
     LEFT JOIN LATERAL ( SELECT sum(inv_onhand_balances.qty_onhand) AS qty_onhand
           FROM inv.inv_onhand_balances
          WHERE (inv_onhand_balances.item_id = rp.item_id)) b ON (true))
     LEFT JOIN inv.item_attributes attr ON ((attr.item_id = rp.item_id)))
  WITH NO DATA;


