--
-- Name: v_ai_model_performance; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_ai_model_performance AS
 SELECT m.model_code,
    m.model_name,
    m.framework,
    m.version,
    m.deployment_status,
    mon.evaluation_date,
    mon.accuracy,
    mon."precision",
    mon.recall,
    mon.f1_score,
    mon.rmse,
    mon.drift_score
   FROM (scm.scm_ml_models m
     LEFT JOIN scm.scm_ml_monitoring mon ON ((mon.ml_model_id = m.ml_model_id)))
  WHERE m.is_active;


--
-- Name: v_alert_summary; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_alert_summary AS
 SELECT alert_id,
    severity,
    title,
    status,
    entity_type,
    entity_id,
    created_at,
    assigned_to,
    acknowledged_at,
    resolved_at
   FROM scm.scm_alerts a
  WHERE is_active
  ORDER BY created_at DESC;


--
-- Name: v_carbon_footprint_report; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_carbon_footprint_report AS
 SELECT ns.network_scenario_id,
    ns.scenario_name,
    ns.carbon_footprint AS total_carbon,
    count(nf.flow_id) AS flow_count,
    sum(nf.quantity) AS total_flow_qty
   FROM (scm.scm_network_scenarios ns
     LEFT JOIN scm.scm_network_flows nf ON (((nf.network_scenario_id = ns.network_scenario_id) AND nf.is_active)))
  WHERE ns.is_active
  GROUP BY ns.network_scenario_id, ns.scenario_name, ns.carbon_footprint;


--
-- Name: v_demand_forecast_summary; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_demand_forecast_summary AS
 SELECT fv.forecast_version_id,
    fver.version_label,
    fver.bucket_type,
    fv.item_id,
    fv.location_id,
    count(*) AS period_count,
    sum(fv.point_forecast) AS total_forecast,
    sum(fv.actual_quantity) AS total_actual,
    avg(fv.mape) AS avg_mape
   FROM (scm.scm_forecast_values fv
     JOIN scm.scm_forecast_versions fver ON ((fver.forecast_version_id = fv.forecast_version_id)))
  WHERE fv.is_active
  GROUP BY fv.forecast_version_id, fver.version_label, fver.bucket_type, fv.item_id, fv.location_id;


--
-- Name: v_inventory_optimization_summary; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_inventory_optimization_summary AS
 SELECT policy_code,
    policy_name,
    policy_type,
    item_id,
    location_id,
    min_quantity,
    max_quantity,
    reorder_point,
    safety_stock,
    target_service_level
   FROM scm.scm_inventory_policies ip
  WHERE is_active;


--
-- Name: v_kpi_dashboard; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_kpi_dashboard AS
 SELECT kd.kpi_code,
    kd.kpi_name,
    kd.kpi_category,
    kv.actual_value,
    kv.target_value,
    kv.variance,
    kv.variance_pct,
    kv.evaluation_date,
        CASE
            WHEN (kv.actual_value >= kd.threshold_green) THEN 'GREEN'::text
            WHEN (kv.actual_value >= kd.threshold_yellow) THEN 'YELLOW'::text
            ELSE 'RED'::text
        END AS status
   FROM (scm.scm_kpi_definitions kd
     JOIN scm.scm_kpi_values kv ON (((kv.kpi_definition_id = kd.kpi_definition_id) AND kv.is_active)))
  WHERE kd.is_active;


--
-- Name: v_optimization_execution_history; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_optimization_execution_history AS
 SELECT el.exec_log_id,
    p.problem_code,
    p.problem_name,
    el.solver_type,
    el.status,
    el.started_at,
    el.completed_at,
    el.solve_time_ms,
    el.objective_value,
    el.gap_pct,
    el.error_message
   FROM (scm.scm_optimization_execution_log el
     JOIN scm.scm_optimization_problems p ON ((p.problem_id = el.problem_id)))
  WHERE el.is_active
  ORDER BY el.started_at DESC;


--
-- Name: v_scenario_comparison; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_scenario_comparison AS
 SELECT sc.comparison_id,
    bs.scenario_name AS baseline_name,
    as2.scenario_name AS alternative_name,
    sc.summary,
    sc.recommended_scenario_id
   FROM ((scm.scm_scenario_comparisons sc
     JOIN scm.scm_scenarios bs ON ((bs.scenario_id = sc.baseline_scenario_id)))
     JOIN scm.scm_scenarios as2 ON ((as2.scenario_id = sc.alternative_scenario_id)));


--
-- Name: v_supplier_scorecard; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_supplier_scorecard AS
 SELECT partner_id,
    evaluation_date,
    quality_score,
    delivery_score,
    cost_score,
    innovation_score,
    sustainability_score,
    overall_score,
    rating
   FROM scm.scm_supplier_scorecards ss
  WHERE is_active
  ORDER BY evaluation_date DESC;


--
-- Name: v_supply_plan_summary; Type: VIEW; Schema: scm; Owner: -
--

CREATE VIEW scm.v_supply_plan_summary AS
 SELECT sp.supply_plan_id,
    sp.plan_name,
    sp.plan_type,
    sp.status,
    count(spl.supply_plan_line_id) AS line_count,
    sum(spl.quantity) AS total_quantity,
    sum(spl.total_cost) AS total_cost
   FROM (scm.scm_supply_plans sp
     LEFT JOIN scm.scm_supply_plan_lines spl ON (((spl.supply_plan_id = sp.supply_plan_id) AND spl.is_active)))
  WHERE sp.is_active
  GROUP BY sp.supply_plan_id, sp.plan_name, sp.plan_type, sp.status;


