--
-- Name: v_asn_status; Type: VIEW; Schema: sup; Owner: -
--

CREATE VIEW sup.v_asn_status AS
 SELECT a.asn_id,
    a.asn_number,
    a.ship_date,
    a.expected_arrival,
    a.status,
    a.partner_id,
    p.partner_code,
    p.legal_name,
    a.po_id
   FROM (sup.shipment_advices a
     LEFT JOIN core.partners p ON ((p.partner_id = a.partner_id)));


--
-- Name: v_rfq_summary; Type: VIEW; Schema: sup; Owner: -
--

CREATE VIEW sup.v_rfq_summary AS
 SELECT r.partner_id,
    p.partner_code,
    p.legal_name,
    r.item_id,
    i.item_number,
    r.quoted_price,
    r.lead_time_days,
    r.valid_until,
    r.status
   FROM ((sup.rfq_responses r
     LEFT JOIN core.partners p ON ((p.partner_id = r.partner_id)))
     LEFT JOIN mdm.items i ON ((i.item_id = r.item_id)));


