--
-- Name: mv_tax_summary_by_period; Type: MATERIALIZED VIEW; Schema: tax; Owner: -
--

CREATE MATERIALIZED VIEW tax.mv_tax_summary_by_period AS
 SELECT rg.tax_regime_code,
    tt.tax_type_code,
    tr.tax_code,
    tr.tax_rate_pct,
    tx.tax_period,
    count(*) AS transaction_count,
    sum(tx.base_amount) AS total_base,
    sum(tx.tax_amount) AS total_tax,
    sum(tx.recoverable_tax_amount) AS total_recoverable,
    sum(tx.non_recoverable_tax_amount) AS total_non_recoverable
   FROM (((tax.tax_transactions tx
     LEFT JOIN tax.tax_rates tr ON ((tr.tax_rate_id = tx.tax_rate_id)))
     LEFT JOIN tax.tax_types tt ON ((tt.tax_type_id = tr.tax_type_id)))
     LEFT JOIN tax.tax_regimes rg ON ((rg.tax_regime_id = COALESCE(tx.tax_regime_id, tr.tax_regime_id))))
  GROUP BY rg.tax_regime_code, tt.tax_type_code, tr.tax_code, tr.tax_rate_pct, tx.tax_period
  WITH NO DATA;


