--
-- Name: v_tax_compliance_calendar; Type: VIEW; Schema: tax; Owner: -
--

CREATE VIEW tax.v_tax_compliance_calendar AS
 SELECT tc.calendar_id,
    tc.due_date,
    tc.period_name,
    tc.status,
    o.obligation_code,
    o.obligation_name,
    o.frequency,
    rg.tax_regime_code,
    jd.jurisdiction_code
   FROM (((tax.tax_compliance_calendars tc
     JOIN tax.tax_compliance_obligations o ON ((o.obligation_id = tc.obligation_id)))
     LEFT JOIN tax.tax_regimes rg ON ((rg.tax_regime_id = o.tax_regime_id)))
     LEFT JOIN tax.tax_jurisdictions jd ON ((jd.tax_jurisdiction_id = o.tax_jurisdiction_id)));


--
-- Name: v_tax_prediction_dashboard; Type: VIEW; Schema: tax; Owner: -
--

CREATE VIEW tax.v_tax_prediction_dashboard AS
 SELECT p.prediction_id,
    p.prediction_type,
    p.prediction_date,
    p.prediction_value,
    p.confidence_level,
    m.model_name,
    a.actual_value,
    a.error_pct
   FROM ((tax.tax_predictions p
     LEFT JOIN tax.tax_ml_models m ON ((m.model_id = p.model_id)))
     LEFT JOIN tax.tax_prediction_actuals a ON ((a.prediction_id = p.prediction_id)));


--
-- Name: v_tax_regime_summary; Type: VIEW; Schema: tax; Owner: -
--

CREATE VIEW tax.v_tax_regime_summary AS
 SELECT rg.tax_regime_id,
    rg.tax_regime_name,
    count(DISTINCT r.tax_jurisdiction_id) AS jurisdiction_count,
    count(DISTINCT r.tax_rate_id) AS rate_count,
    count(DISTINCT t.tax_transaction_id) AS transaction_count
   FROM ((tax.tax_regimes rg
     LEFT JOIN tax.tax_rates r ON ((rg.tax_regime_id = r.tax_regime_id)))
     LEFT JOIN tax.tax_transactions t ON ((r.tax_rate_id = t.tax_rate_id)))
  GROUP BY rg.tax_regime_id, rg.tax_regime_name;


--
-- Name: v_tax_return_status; Type: VIEW; Schema: tax; Owner: -
--

CREATE VIEW tax.v_tax_return_status AS
 SELECT r.tax_return_id,
    r.tax_regime_id,
    r.tax_period_id,
    r.tax_jurisdiction_id,
    r.tax_authority_id,
    r.return_type,
    r.return_number,
    r.period_name,
    r.due_date,
    r.submitted_date,
    r.accepted_date,
    r.status,
    r.taxable_sales,
    r.taxable_purchases,
    r.output_tax,
    r.input_tax,
    r.net_tax_payable,
    r.net_tax_refundable,
    r.total_adjustments,
    r.currency_code,
    r.filing_confirmation,
    r.notes,
    r.is_active,
    r.created_at,
    r.updated_at,
    r.update_by,
    rg.tax_regime_code,
    rg.tax_regime_name,
    jd.jurisdiction_code,
    jd.jurisdiction_name
   FROM ((tax.tax_returns r
     LEFT JOIN tax.tax_regimes rg ON ((rg.tax_regime_id = r.tax_regime_id)))
     LEFT JOIN tax.tax_jurisdictions jd ON ((jd.tax_jurisdiction_id = r.tax_jurisdiction_id)));


--
-- Name: v_withholding_tax_summary; Type: VIEW; Schema: tax; Owner: -
--

CREATE VIEW tax.v_withholding_tax_summary AS
 SELECT wc.wht_code,
    wc.wht_name,
    wc.wht_rate_pct,
    count(DISTINCT wcert.wht_certificate_id) AS certificate_count,
    sum(wcert.gross_amount) AS total_gross,
    sum(wcert.wht_amount) AS total_wht
   FROM (tax.tax_withholding_configs wc
     LEFT JOIN tax.tax_withholding_certificates wcert ON ((wcert.wht_config_id = wc.wht_config_id)))
  WHERE (wc.is_active = true)
  GROUP BY wc.wht_code, wc.wht_name, wc.wht_rate_pct;


