ALTER TABLE ONLY wms.receiving_schedules FORCE ROW LEVEL SECURITY;


--
-- Name: shipment_headers; Type: TABLE; Schema: wms; Owner: -
--

CREATE TABLE wms.shipment_headers (
    shipment_id uuid DEFAULT uuidv7() NOT NULL,
    so_id uuid,
    packing_id uuid,
    trip_id uuid,
    shipment_code character varying(50) NOT NULL,
    status character varying(20) DEFAULT 'PENDING'::character varying,
    shipped_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid,
    corporate_id uuid,
    company_id uuid,
    site_id uuid
);

ALTER TABLE ONLY wms.shipment_headers FORCE ROW LEVEL SECURITY;


--
-- Name: v_cycle_count_variance; Type: VIEW; Schema: wms; Owner: -
--

CREATE VIEW wms.v_cycle_count_variance AS
 SELECT c.count_id,
    c.warehouse_id,
    c.location_id,
    c.item_id,
    i.item_number,
    c.expected_qty,
    c.actual_qty,
    c.variance_qty,
    c.status,
    c.counted_at
   FROM (wms.cycle_counts c
     LEFT JOIN mdm.items i ON ((i.item_id = c.item_id)));


--
-- Name: v_picking_status; Type: VIEW; Schema: wms; Owner: -
--

CREATE VIEW wms.v_picking_status AS
 SELECT p.picking_id,
    p.item_id,
    i.item_number,
    p.qty_required,
    p.qty_picked,
    p.status,
    p.assigned_to,
    p.completed_at
   FROM (wms.picking_tasks p
     LEFT JOIN mdm.items i ON ((i.item_id = p.item_id)));


--
-- Name: v_receiving_status; Type: VIEW; Schema: wms; Owner: -
--

CREATE VIEW wms.v_receiving_status AS
 SELECT r.receiving_id,
    r.scheduled_date,
    r.status,
    r.dock_door,
    r.warehouse_id,
    r.po_id,
    r.asn_id,
    count(pt.putaway_id) AS putaway_count,
    count(pt.putaway_id) FILTER (WHERE ((pt.status)::text = 'COMPLETED'::text)) AS putaway_done
   FROM (wms.receiving_schedules r
     LEFT JOIN wms.putaway_tasks pt ON ((pt.receiving_id = r.receiving_id)))
  GROUP BY r.receiving_id, r.scheduled_date, r.status, r.dock_door, r.warehouse_id, r.po_id, r.asn_id;


--
-- Name: v_shipment_status; Type: VIEW; Schema: wms; Owner: -
--

CREATE VIEW wms.v_shipment_status AS
 SELECT shipment_id,
    shipment_code,
    status,
    shipped_at,
    so_id,
    packing_id,
    trip_id
   FROM wms.shipment_headers s;


--
-- Name: warehouse_zones; Type: TABLE; Schema: wms; Owner: -
--

CREATE TABLE wms.warehouse_zones (
    zone_id uuid DEFAULT uuidv7() NOT NULL,
    warehouse_id uuid NOT NULL,
    zone_code character varying(50) NOT NULL,
    zone_name character varying(100) NOT NULL,
    zone_type character varying(30) NOT NULL,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone,
    update_by uuid
);


