--
-- Name: v_ap_invoice_with_lines _RETURN; Type: RULE; Schema: ap; Owner: -
--

CREATE OR REPLACE VIEW ap.v_ap_invoice_with_lines AS
 SELECT i.ap_invoice_id,
    i.invoice_number,
    i.supplier_id,
    i.supplier_site_id,
    i.company_id,
    i.currency_id,
    i.invoice_type,
    i.invoice_status,
    i.po_id,
    i.invoice_date,
    i.invoice_due_date,
    i.date_received,
    i.gl_date,
    i.payment_term_days,
    i.payment_method,
    i.description,
    i.amount_untaxed,
    i.amount_tax,
    i.amount_total,
    i.amount_paid,
    i.amount_residual,
    i.tax_id,
    i.account_payable_id,
    i.payment_reference,
    i.partner_ref,
    i.is_paid,
    i.notes,
    i.is_active,
    i.created_at,
    i.updated_at,
    i.update_by,
    (count(l.ap_invoice_line_id))::integer AS line_count,
    (COALESCE(sum((l.line_total)::numeric), (0)::numeric))::numeric(18,2) AS lines_total
   FROM (ap.ap_invoices i
     LEFT JOIN ap.ap_invoice_lines l ON ((l.ap_invoice_id = i.ap_invoice_id)))
  GROUP BY i.ap_invoice_id;


--
-- Name: v_qc_capa_summary _RETURN; Type: RULE; Schema: qc; Owner: -
--

CREATE OR REPLACE VIEW qc.v_qc_capa_summary AS
 SELECT c.capa_id,
    c.capa_number,
    c.capa_title,
    c.capa_type_code,
    c.capa_source_code,
    c.capa_priority_code,
    c.capa_status_code,
    c.source_ncr_id,
    c.source_audit_id,
    c.source_complaint_id,
    c.organization_id,
    c.problem_description,
    c.requested_by,
    c.requested_date,
    c.assigned_to,
    c.assigned_date,
    c.due_date,
    c.effectiveness_review_date,
    c.effectiveness_result,
    c.is_effective,
    c.closed_date,
    c.creation_date,
    c.is_active,
    c.tenant_id,
        CASE
            WHEN ((c.due_date IS NOT NULL) AND (c.due_date < CURRENT_DATE) AND ((c.capa_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[]))) THEN 'OVERDUE'::text
            WHEN ((c.due_date IS NOT NULL) AND (c.due_date <= (CURRENT_DATE + '7 days'::interval)) AND ((c.capa_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[]))) THEN 'DUE_SOON'::text
            ELSE 'OK'::text
        END AS due_status,
    count(a.capa_action_id) AS total_actions,
    count(a.capa_action_id) FILTER (WHERE ((a.action_status_code)::text = 'COMPLETED'::text)) AS completed_actions,
    count(a.capa_action_id) FILTER (WHERE ((a.action_status_code)::text = 'OPEN'::text)) AS open_actions
   FROM (qc.qc_capa_headers c
     LEFT JOIN qc.qc_capa_actions a ON (((a.capa_id = c.capa_id) AND ((a.is_active)::text = 'Y'::text))))
  WHERE ((c.is_active)::text = 'Y'::text)
  GROUP BY c.capa_id;


--
-- Name: v_qc_inspection_summary _RETURN; Type: RULE; Schema: qc; Owner: -
--

CREATE OR REPLACE VIEW qc.v_qc_inspection_summary AS
 SELECT i.inspection_id,
    i.inspection_number,
    i.inspection_type_code,
    i.inspection_status_code,
    i.overall_result_code,
    i.disposition_code,
    i.item_id,
    i.lot_number,
    i.inspector_name,
    i.quality_plan_id,
    i.sampling_plan_id,
    i.inspection_quantity,
    i.sample_quantity,
    i.accepted_quantity,
    i.rejected_quantity,
    i.rework_quantity,
    i.scrapped_quantity,
    i.planned_date,
    i.started_date,
    i.completed_date,
    i.source_type_code,
    i.source_document_id,
    i.ncr_id,
    i.hold_id,
    i.organization_id,
    i.creation_date,
    i.is_active,
    i.tenant_id,
    count(tr.test_result_id) AS total_tests,
    count(tr.test_result_id) FILTER (WHERE ((tr.overall_result_code)::text = 'PASS'::text)) AS passed_tests,
    count(tr.test_result_id) FILTER (WHERE ((tr.overall_result_code)::text = ANY ((ARRAY['FAIL'::character varying, 'OUT_OF_SPEC'::character varying])::text[]))) AS failed_tests
   FROM (qc.qc_inspections i
     LEFT JOIN qc.qc_test_results tr ON (((tr.inspection_id = i.inspection_id) AND ((tr.is_active)::text = 'Y'::text))))
  WHERE ((i.is_active)::text = 'Y'::text)
  GROUP BY i.inspection_id;


--
-- Name: v_qc_ncr_summary _RETURN; Type: RULE; Schema: qc; Owner: -
--

CREATE OR REPLACE VIEW qc.v_qc_ncr_summary AS
 SELECT n.ncr_id,
    n.ncr_number,
    n.ncr_title,
    n.ncr_type_code,
    n.ncr_severity_code,
    n.ncr_status_code,
    n.discovery_source_code,
    n.item_id,
    n.lot_number,
    n.quantity_affected,
    n.cost_affected,
    n.disposition_code,
    n.containment_required,
    n.reported_by,
    n.reported_date,
    n.assigned_to,
    n.due_date,
    n.closed_date,
    n.recurrence_count,
    n.organization_id,
    n.creation_date,
    n.is_active,
    n.tenant_id,
        CASE
            WHEN ((n.ncr_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[])) THEN EXTRACT(day FROM (CURRENT_TIMESTAMP - (n.reported_date)::timestamp with time zone))
            ELSE (0)::numeric
        END AS aging_days,
        CASE
            WHEN ((n.due_date IS NOT NULL) AND (n.due_date < CURRENT_DATE) AND ((n.ncr_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[]))) THEN 'OVERDUE'::text
            WHEN ((n.due_date IS NOT NULL) AND (n.due_date <= (CURRENT_DATE + '7 days'::interval)) AND ((n.ncr_status_code)::text <> ALL ((ARRAY['CLOSED'::character varying, 'CANCELLED'::character varying])::text[]))) THEN 'DUE_SOON'::text
            ELSE 'OK'::text
        END AS due_status,
    count(c.containment_id) AS containment_actions,
    count(c.containment_id) FILTER (WHERE ((c.containment_status_code)::text = 'COMPLETED'::text)) AS containment_completed
   FROM (qc.qc_ncr_headers n
     LEFT JOIN qc.qc_ncr_containment c ON (((c.ncr_id = n.ncr_id) AND ((c.is_active)::text = 'Y'::text))))
  WHERE ((n.is_active)::text = 'Y'::text)
  GROUP BY n.ncr_id;


--
-- Name: v_tax_audit_status _RETURN; Type: RULE; Schema: tax; Owner: -
--

CREATE OR REPLACE VIEW tax.v_tax_audit_status AS
 SELECT a.audit_id,
    a.audit_reference,
    a.audit_type,
    a.status,
    a.start_date,
    a.end_date,
    a.assessment_amount,
    a.penalty_amount,
    ath.authority_code,
    ath.authority_name,
    count(DISTINCT af.finding_id) AS finding_count,
    count(DISTINCT ar.response_id) AS response_count
   FROM (((tax.tax_audits a
     LEFT JOIN tax.tax_authorities ath ON ((ath.tax_authority_id = a.tax_authority_id)))
     LEFT JOIN tax.tax_audit_findings af ON ((af.audit_id = a.audit_id)))
     LEFT JOIN tax.tax_audit_responses ar ON ((ar.audit_id = a.audit_id)))
  GROUP BY a.audit_id, ath.authority_code, ath.authority_name;


--
-- Name: v_tax_certificate_status _RETURN; Type: RULE; Schema: tax; Owner: -
--

CREATE OR REPLACE VIEW tax.v_tax_certificate_status AS
 SELECT c.certificate_id,
    c.certificate_type,
    c.certificate_number,
    c.issuer_id,
    c.partner_id,
    c.certificate_name,
    c.effective_from,
    c.expiration_date,
    c.status,
    c.verification_status,
    c.document_url,
    c.notes,
    c.is_active,
    c.created_at,
    c.updated_at,
    c.update_by,
    count(DISTINCT cj.tax_jurisdiction_id) AS jurisdiction_count
   FROM (tax.tax_certificates c
     LEFT JOIN tax.tax_certificate_jurisdictions cj ON ((cj.certificate_id = c.certificate_id)))
  GROUP BY c.certificate_id;


