--
-- Name: accounting_entries accounting_entries_company_isolation; Type: POLICY; Schema: ap; Owner: -
--

CREATE POLICY accounting_entries_company_isolation ON ap.accounting_entries USING (((current_setting('app.access_level'::text, true) = 'COMPANY'::text) AND (company_id = app.current_company_id())));


--
